{
  "name": "LexiWeek - Weekly Vocabulary Builder",
  "description": "A focused English learning app where you input your weekly vocabulary list. The app uses AI to generate definitions and context, then quizzes you with audio feedback to ensure mastery."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useEffect } from 'react';
import { WordInput } from './components/WordInput';
import { QuizSession } from './components/QuizSession';
import { Dashboard } from './components/Dashboard';
import { WordData, AppState } from './types';
import { enrichVocabulary } from './services/geminiService';
import { Toaster, toast } from 'react-hot-toast';

const STORAGE_KEY = 'lexiweek_data_v1';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.DASHBOARD);
  const [words, setWords] = useState<WordData[]>([]);
  const [loading, setLoading] = useState(false);

  // Load from local storage on mount
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setWords(parsed);
        if (parsed.length === 0) {
          setAppState(AppState.INPUT);
        }
      } catch (e) {
        console.error("Failed to parse saved data", e);
        setAppState(AppState.INPUT);
      }
    } else {
      setAppState(AppState.INPUT);
    }
  }, []);

  // Save to local storage whenever words change
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(words));
  }, [words]);

  const handleWordsSubmit = async (rawWords: string[]) => {
    setLoading(true);
    try {
      const enrichedWords = await enrichVocabulary(rawWords);
      setWords(enrichedWords);
      setAppState(AppState.DASHBOARD);
      toast.success('Vocabulary list created!');
    } catch (error) {
      console.error(error);
      toast.error('Failed to process words. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const handleResetWeek = () => {
    if (window.confirm("Are you sure? This will delete current progress and start a new week.")) {
      setWords([]);
      setAppState(AppState.INPUT);
      localStorage.removeItem(STORAGE_KEY);
    }
  };

  const handleUpdateWordProgress = (wordId: string, correct: boolean) => {
    setWords(prev => prev.map(w => {
      if (w.id !== wordId) return w;
      return {
        ...w,
        correctCount: correct ? w.correctCount + 1 : w.correctCount,
        lastPracticed: new Date().toISOString()
      };
    }));
  };

  return (
    <div className="min-h-screen flex flex-col items-center justify-center p-4 sm:p-6 lg:p-8 relative overflow-hidden">
      <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-indigo-500 via-purple-500 to-pink-500 z-50"></div>

      <main className="w-full max-w-4xl z-10">
        {appState === AppState.INPUT && (
          <WordInput 
            onSubmit={handleWordsSubmit} 
            isLoading={loading} 
            hasExistingData={words.length > 0}
            onCancel={words.length > 0 ? () => setAppState(AppState.DASHBOARD) : undefined}
          />
        )}

        {appState === AppState.DASHBOARD && (
          <Dashboard 
            words={words} 
            onStartQuiz={() => setAppState(AppState.QUIZ)}
            onNewWeek={handleResetWeek}
          />
        )}

        {appState === AppState.QUIZ && (
          <QuizSession 
            words={words}
            onComplete={(results) => {
              // Batch update could happen here, but we update incrementally for now
              setAppState(AppState.DASHBOARD);
            }}
            onUpdateWord={handleUpdateWordProgress}
            onExit={() => setAppState(AppState.DASHBOARD)}
          />
        )}
      </main>

      <Toaster position="bottom-center" />

      {/* Background decoration */}
      <div className="fixed top-20 left-10 w-64 h-64 bg-indigo-200 rounded-full mix-blend-multiply filter blur-3xl opacity-30 animate-blob"></div>
      <div className="fixed top-20 right-10 w-64 h-64 bg-purple-200 rounded-full mix-blend-multiply filter blur-3xl opacity-30 animate-blob animation-delay-2000"></div>
      <div className="fixed -bottom-32 left-20 w-64 h-64 bg-pink-200 rounded-full mix-blend-multiply filter blur-3xl opacity-30 animate-blob animation-delay-4000"></div>
    </div>
  );
};

export default App;

export enum AppState {
  INPUT = 'INPUT',
  DASHBOARD = 'DASHBOARD',
  QUIZ = 'QUIZ'
}

export interface WordData {
  id: string;
  word: string;
  definition: string;
  exampleSentence: string; // The sentence with the word replaced by underscores
  partOfSpeech: string;
  correctCount: number;
  lastPracticed?: string;
}

export interface QuizResult {
  wordId: string;
  correct: boolean;
}

import { GoogleGenAI, Type } from "@google/genai";
import { WordData } from '../types';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const enrichVocabulary = async (words: string[]): Promise<WordData[]> => {
  if (words.length === 0) return [];

  const prompt = `
    I have a list of English vocabulary words for a student. 
    Please process these words and provide a definition, part of speech, and a "cloze" example sentence 
    (a sentence where the target word is replaced by '_______') for each one.

    The words are: ${words.join(', ')}.

    Return the data in a strict JSON structure.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              word: { type: Type.STRING, description: "The vocabulary word (lowercase)" },
              definition: { type: Type.STRING, description: "A concise definition" },
              partOfSpeech: { type: Type.STRING, description: "e.g., noun, verb, adjective" },
              exampleSentence: { type: Type.STRING, description: "A sentence using the word, but the word itself is replaced with _______" }
            },
            required: ["word", "definition", "partOfSpeech", "exampleSentence"]
          }
        }
      }
    });

    const rawData = JSON.parse(response.text || '[]');

    // Map to our internal structure with IDs
    return rawData.map((item: any) => ({
      id: crypto.randomUUID(),
      word: item.word.toLowerCase().trim(),
      definition: item.definition,
      exampleSentence: item.exampleSentence,
      partOfSpeech: item.partOfSpeech,
      correctCount: 0
    }));

  } catch (error) {
    console.error("Gemini API Error:", error);
    throw new Error("Failed to enrich vocabulary.");
  }
};

// Simple synth sounds to avoid external dependencies
export const playSuccessSound = () => {
  const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
  if (!AudioContext) return;

  const ctx = new AudioContext();
  const osc = ctx.createOscillator();
  const gain = ctx.createGain();

  osc.type = 'sine';
  osc.frequency.setValueAtTime(523.25, ctx.currentTime); // C5
  osc.frequency.exponentialRampToValueAtTime(1046.5, ctx.currentTime + 0.1); // C6

  gain.gain.setValueAtTime(0.1, ctx.currentTime);
  gain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 0.4);

  osc.connect(gain);
  gain.connect(ctx.destination);

  osc.start();
  osc.stop(ctx.currentTime + 0.4);
};

export const playErrorSound = () => {
  const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
  if (!AudioContext) return;

  const ctx = new AudioContext();
  const osc = ctx.createOscillator();
  const gain = ctx.createGain();

  osc.type = 'sawtooth';
  osc.frequency.setValueAtTime(200, ctx.currentTime);
  osc.frequency.linearRampToValueAtTime(100, ctx.currentTime + 0.2);

  gain.gain.setValueAtTime(0.1, ctx.currentTime);
  gain.gain.linearRampToValueAtTime(0.01, ctx.currentTime + 0.3);

  osc.connect(gain);
  gain.connect(ctx.destination);

  osc.start();
  osc.stop(ctx.currentTime + 0.3);
};

import React, { useState } from 'react';

interface WordInputProps {
  onSubmit: (words: string[]) => void;
  isLoading: boolean;
  hasExistingData: boolean;
  onCancel?: () => void;
}

export const WordInput: React.FC<WordInputProps> = ({ onSubmit, isLoading, hasExistingData, onCancel }) => {
  const [inputText, setInputText] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const words = inputText
      .split(/[\n,]+/) // Split by newline or comma
      .map(w => w.trim())
      .filter(w => w.length > 0);

    if (words.length > 0) {
      onSubmit(words);
    }
  };

  return (
    <div className="bg-white/80 backdrop-blur-md shadow-xl rounded-2xl p-8 border border-white/50 animate-fade-in-up">
      <div className="text-center mb-8">
        <h1 className="text-3xl font-bold text-slate-800 mb-2">New Week, New Words</h1>
        <p className="text-slate-500">
          Paste your vocabulary list below. We'll use AI to generate definitions and quiz questions for you.
        </p>
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">
        <div>
          <label htmlFor="words" className="block text-sm font-medium text-slate-700 mb-2">
            Vocabulary List (separated by commas or new lines)
          </label>
          <textarea
            id="words"
            rows={8}
            className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition-all text-slate-700 placeholder-slate-400 bg-white"
            placeholder="e.g. ephemeral, serendipity, resilient..."
            value={inputText}
            onChange={(e) => setInputText(e.target.value)}
            disabled={isLoading}
          />
        </div>

        <div className="flex gap-4">
          {hasExistingData && onCancel && (
            <button
              type="button"
              onClick={onCancel}
              className="flex-1 px-6 py-3 rounded-xl border border-slate-200 text-slate-600 font-semibold hover:bg-slate-50 transition-colors"
              disabled={isLoading}
            >
              Cancel
            </button>
          )}
          <button
            type="submit"
            disabled={isLoading || !inputText.trim()}
            className={`flex-1 px-6 py-3 rounded-xl text-white font-semibold shadow-lg shadow-indigo-500/30 transition-all transform active:scale-95
              ${isLoading || !inputText.trim() 
                ? 'bg-slate-400 cursor-not-allowed' 
                : 'bg-indigo-600 hover:bg-indigo-700 hover:-translate-y-0.5'}`}
          >
            {isLoading ? (
              <span className="flex items-center justify-center gap-2">
                <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                  <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                  <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                </svg>
                Processing with AI...
              </span>
            ) : 'Start Learning Week'}
          </button>
        </div>
      </form>
    </div>
  );
};

import React from 'react';
import { WordData } from '../types';

interface DashboardProps {
  words: WordData[];
  onStartQuiz: () => void;
  onNewWeek: () => void;
}

export const Dashboard: React.FC<DashboardProps> = ({ words, onStartQuiz, onNewWeek }) => {
  const totalCorrect = words.reduce((acc, curr) => acc + curr.correctCount, 0);

  return (
    <div className="space-y-6">
      <div className="bg-white/80 backdrop-blur-md shadow-xl rounded-2xl p-6 sm:p-8 border border-white/50">
        <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center mb-8 gap-4">
          <div>
            <h1 className="text-2xl sm:text-3xl font-bold text-slate-800">This Week's Set</h1>
            <p className="text-slate-500 mt-1">{words.length} words to master</p>
          </div>
          <div className="flex gap-3 w-full sm:w-auto">
            <button
              onClick={onNewWeek}
              className="px-4 py-2 rounded-lg text-sm font-medium text-slate-500 hover:bg-slate-100 hover:text-slate-700 transition-colors"
            >
              Reset Week
            </button>
            <button
              onClick={onStartQuiz}
              className="flex-1 sm:flex-none px-6 py-2.5 bg-indigo-600 text-white rounded-lg font-semibold shadow-lg shadow-indigo-500/30 hover:bg-indigo-700 hover:-translate-y-0.5 transition-all active:scale-95 flex items-center justify-center gap-2"
            >
              <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polygon points="5 3 19 12 5 21 5 3"></polygon></svg>
              Start Practice
            </button>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4 max-h-[60vh] overflow-y-auto pr-2 custom-scrollbar">
          {words.map((word) => (
            <div key={word.id} className="bg-slate-50 p-4 rounded-xl border border-slate-100 hover:border-indigo-100 transition-colors group">
              <div className="flex justify-between items-start mb-2">
                <h3 className="text-lg font-bold text-slate-800 capitalize group-hover:text-indigo-600 transition-colors">
                  {word.word}
                </h3>
                <span className="text-xs font-medium px-2 py-1 bg-slate-200 text-slate-600 rounded-full">
                  {word.partOfSpeech}
                </span>
              </div>
              <p className="text-sm text-slate-600 leading-relaxed mb-3">
                {word.definition}
              </p>
              <div className="flex items-center justify-between pt-3 border-t border-slate-200">
                <span className="text-xs text-slate-400">Mastery</span>
                <div className="flex items-center gap-1">
                  {[...Array(3)].map((_, i) => (
                    <div 
                      key={i} 
                      className={`w-2 h-2 rounded-full ${i < Math.min(word.correctCount, 3) ? 'bg-green-400' : 'bg-slate-200'}`} 
                    />
                  ))}
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>

      <div className="text-center">
        <p className="text-sm text-slate-500 font-medium bg-white/50 inline-block px-4 py-1 rounded-full backdrop-blur-sm">
          Total Correct Answers: {totalCorrect}
        </p>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { WordData, QuizResult } from '../types';
import { playSuccessSound, playErrorSound } from '../services/audioService';

interface QuizSessionProps {
  words: WordData[];
  onComplete: (results: QuizResult[]) => void;
  onUpdateWord: (id: string, correct: boolean) => void;
  onExit: () => void;
}

export const QuizSession: React.FC<QuizSessionProps> = ({ words, onComplete, onUpdateWord, onExit }) => {
  // Fisher-Yates shuffle to randomize queue
  const [queue, setQueue] = useState<WordData[]>([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [input, setInput] = useState('');
  const [status, setStatus] = useState<'idle' | 'correct' | 'incorrect'>('idle');
  const [showHint, setShowHint] = useState(false);

  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    // Shuffle words on mount
    const shuffled = [...words].sort(() => Math.random() - 0.5);
    setQueue(shuffled);
  }, [words]);

  useEffect(() => {
    if (status === 'idle') {
      inputRef.current?.focus();
    }
  }, [status, currentIndex]);

  const currentWord = queue[currentIndex];

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentWord || status !== 'idle') return;

    const cleanInput = input.trim().toLowerCase();
    const cleanTarget = currentWord.word.toLowerCase();

    if (cleanInput === cleanTarget) {
      handleCorrect();
    } else {
      handleIncorrect();
    }
  };

  const handleCorrect = () => {
    setStatus('correct');
    playSuccessSound();
    onUpdateWord(currentWord.id, true);

    setTimeout(() => {
      handleNext();
    }, 1500);
  };

  const handleIncorrect = () => {
    setStatus('incorrect');
    playErrorSound();

    // Shake animation reset via key or just rely on state change causing re-render if needed
    // But mainly we show the 'incorrect' UI state

    setTimeout(() => {
      setStatus('idle');
      setInput(''); // Clear input to try again? Or keep it? Let's clear it.
      setShowHint(true);
    }, 1000);
  };

  const handleNext = () => {
    if (currentIndex < queue.length - 1) {
      setCurrentIndex(prev => prev + 1);
      setStatus('idle');
      setInput('');
      setShowHint(false);
    } else {
      onComplete([]); // Just finishing for now
    }
  };

  if (!currentWord) return <div>Loading...</div>;

  const progress = ((currentIndex) / queue.length) * 100;

  return (
    <div className="w-full max-w-2xl mx-auto">
      {/* Progress Bar */}
      <div className="bg-white/30 backdrop-blur-sm h-2 rounded-full mb-8 overflow-hidden">
        <div 
          className="bg-indigo-500 h-full transition-all duration-500 ease-out"
          style={{ width: `${progress}%` }}
        ></div>
      </div>

      <div className="bg-white shadow-2xl rounded-3xl overflow-hidden relative">
        {/* Card Header */}
        <div className="bg-indigo-600 px-8 py-6 flex justify-between items-center text-white">
          <span className="font-semibold text-indigo-100 tracking-wider text-sm uppercase">Word {currentIndex + 1} of {queue.length}</span>
          <button onClick={onExit} className="text-indigo-200 hover:text-white transition-colors">
            <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>
          </button>
        </div>

        {/* Card Body */}
        <div className="p-8 sm:p-12 flex flex-col items-center text-center">

          <div className="mb-8 space-y-4">
            <div className="text-sm font-bold text-indigo-500 uppercase tracking-wide bg-indigo-50 inline-block px-3 py-1 rounded-full">
              {currentWord.partOfSpeech}
            </div>
            <p className="text-slate-600 text-lg sm:text-xl italic">
              "{currentWord.exampleSentence}"
            </p>
            <p className="text-slate-400 text-sm mt-2">
              Definition: {currentWord.definition}
            </p>
          </div>

          <form onSubmit={handleSubmit} className="w-full relative">
            <div className={`relative transition-transform duration-300 ${status === 'incorrect' ? 'animate-shake' : ''}`}>
              <input
                ref={inputRef}
                type="text"
                value={input}
                onChange={(e) => setInput(e.target.value)}
                disabled={status === 'correct'}
                placeholder="Type the word..."
                className={`w-full text-center text-3xl font-bold py-4 bg-transparent border-b-4 focus:outline-none transition-colors
                  ${status === 'correct' ? 'border-green-500 text-green-600' : 
                    status === 'incorrect' ? 'border-red-500 text-red-500' : 
                    'border-slate-200 focus:border-indigo-500 text-slate-800'}`}
                autoComplete="off"
                autoCorrect="off"
                autoCapitalize="off"
                spellCheck="false"
              />
              {status === 'correct' && (
                <div className="absolute right-0 top-1/2 -translate-y-1/2 translate-x-12 text-green-500">
                  <svg className="w-8 h-8 animate-bounce" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7"></path></svg>
                </div>
              )}
            </div>

            {showHint && status === 'idle' && (
              <div className="mt-4 text-sm text-slate-400 animate-fade-in">
                Hint: Starts with <span className="font-bold text-slate-600">{currentWord.word.substring(0, 1).toUpperCase()}</span>...
              </div>
            )}

            <button 
              type="submit" 
              className="sr-only" 
              disabled={status !== 'idle'}
            >
              Submit
            </button>
          </form>

          <div className="mt-12 text-sm text-slate-400">
            Press <span className="font-mono bg-slate-100 px-2 py-0.5 rounded border border-slate-200">Enter</span> to submit
          </div>
        </div>
      </div>
    </div>
  );
};

