import React, { useState, useEffect, useRef } from 'react';
import { WordData, QuizResult } from '../types';
import { playSuccessSound, playErrorSound } from '../services/audioService';
import { generateWordImage } from '../services/geminiService';

interface QuizSessionProps {
  words: WordData[];
  onComplete: (results: QuizResult[]) => void;
  onUpdateWord: (id: string, updates: Partial<WordData>) => void;
  onExit: () => void;
}

export const QuizSession: React.FC<QuizSessionProps> = ({ words, onComplete, onUpdateWord, onExit }) => {
  const [queue, setQueue] = useState<WordData[]>([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [input, setInput] = useState('');
  const [status, setStatus] = useState<'idle' | 'correct' | 'incorrect'>('idle');
  const [showHint, setShowHint] = useState(false);
  const [isImageLoading, setIsImageLoading] = useState(false);

  const inputRef = useRef<HTMLInputElement>(null);

  // Initialize Queue
  useEffect(() => {
    const shuffled = [...words].sort(() => Math.random() - 0.5);
    setQueue(shuffled);
  }, [words]);

  // Focus Input
  useEffect(() => {
    if (status === 'idle') {
      inputRef.current?.focus();
    }
  }, [status, currentIndex]);

  const currentWord = queue[currentIndex];

  // Background Image Generation
  useEffect(() => {
    const fetchImage = async () => {
      if (currentWord && !currentWord.imageUrl) {
        setIsImageLoading(true);
        // Only log, don't block
        try {
          const url = await generateWordImage(currentWord.word);
          if (url) {
            // Update parent state (which persists to storage)
            onUpdateWord(currentWord.id, { imageUrl: url });
            // Update local queue state so UI updates immediately
            setQueue(prev => prev.map(w => w.id === currentWord.id ? { ...w, imageUrl: url } : w));
          }
        } finally {
          setIsImageLoading(false);
        }
      }
    };

    if (currentWord) {
      fetchImage();
    }
  }, [currentWord]); // Intentionally omitting dependencies that handle updates to avoid loops, only trigger on currentWord change

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentWord || status !== 'idle') return;

    const cleanInput = input.trim().toLowerCase();
    const cleanTarget = currentWord.word.toLowerCase();

    if (cleanInput === cleanTarget) {
      handleCorrect();
    } else {
      handleIncorrect();
    }
  };

  const handleCorrect = () => {
    setStatus('correct');
    playSuccessSound();

    const newCount = currentWord.correctCount + 1;
    onUpdateWord(currentWord.id, { 
      correctCount: newCount, 
      lastPracticed: new Date().toISOString() 
    });

    // Longer timeout to allow viewing the image
    setTimeout(() => {
      handleNext();
    }, 4000);
  };

  const handleIncorrect = () => {
    setStatus('incorrect');
    playErrorSound();

    setTimeout(() => {
      setStatus('idle');
      setInput('');
      setShowHint(true);
    }, 1000);
  };

  const handleNext = () => {
    if (currentIndex < queue.length - 1) {
      setCurrentIndex(prev => prev + 1);
      setStatus('idle');
      setInput('');
      setShowHint(false);
    } else {
      onComplete([]); 
    }
  };

  if (!currentWord) return <div>加载中...</div>;

  const progress = ((currentIndex) / queue.length) * 100;

  return (
    <div className="w-full max-w-2xl mx-auto">
      {/* Progress Bar */}
      <div className="bg-white/30 backdrop-blur-sm h-2 rounded-full mb-8 overflow-hidden">
        <div 
          className="bg-indigo-500 h-full transition-all duration-500 ease-out"
          style={{ width: `${progress}%` }}
        ></div>
      </div>

      <div className="bg-white shadow-2xl rounded-3xl overflow-hidden relative">
        {/* Card Header */}
        <div className="bg-indigo-600 px-8 py-6 flex justify-between items-center text-white">
          <span className="font-semibold text-indigo-100 tracking-wider text-sm uppercase">单词 {currentIndex + 1} / {queue.length}</span>
          <button onClick={onExit} className="text-indigo-200 hover:text-white transition-colors">
            <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>
          </button>
        </div>

        {/* Card Body */}
        <div className="p-8 sm:p-12 flex flex-col items-center text-center relative min-h-[400px]">

          {/* Main Content or Image Reward */}
          {status === 'correct' ? (
            <div className="animate-fade-in flex flex-col items-center justify-center flex-1 w-full">
              <div className="text-3xl font-bold text-green-500 mb-6 flex items-center gap-2">
                <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7"></path></svg>
                回答正确!
              </div>
              <div className="text-xl text-slate-700 font-bold mb-6 capitalize">{currentWord.word}</div>

              <div className="w-48 h-48 sm:w-64 sm:h-64 rounded-xl overflow-hidden shadow-lg border border-slate-100 bg-slate-50 flex items-center justify-center relative">
                {currentWord.imageUrl ? (
                  <img src={currentWord.imageUrl} alt={currentWord.word} className="w-full h-full object-cover animate-fade-in" />
                ) : (
                  <div className="text-slate-400 flex flex-col items-center">
                    {isImageLoading ? (
                      <>
                        <svg className="animate-spin h-8 w-8 text-indigo-400 mb-2" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                          <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                          <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                        </svg>
                        <span className="text-xs">生成图片中...</span>
                      </>
                    ) : (
                      <span className="text-xs">暂无图片</span>
                    )}
                  </div>
                )}
              </div>
            </div>
          ) : (
            <>
              <div className="mb-8 space-y-4 w-full">
                <div className="text-sm font-bold text-indigo-500 uppercase tracking-wide bg-indigo-50 inline-block px-3 py-1 rounded-full">
                  {currentWord.partOfSpeech}
                </div>
                <p className="text-slate-600 text-lg sm:text-xl italic">
                  "{currentWord.exampleSentence}"
                </p>
                <p className="text-slate-400 text-sm mt-2">
                  释义: {currentWord.definition}
                </p>
              </div>

              <form onSubmit={handleSubmit} className="w-full relative mt-auto">
                <div className={`relative transition-transform duration-300 ${status === 'incorrect' ? 'animate-shake' : ''}`}>
                  <input
                    ref={inputRef}
                    type="text"
                    value={input}
                    onChange={(e) => setInput(e.target.value)}
                    placeholder="输入单词..."
                    className={`w-full text-center text-3xl font-bold py-4 bg-transparent border-b-4 focus:outline-none transition-colors
                      ${status === 'incorrect' ? 'border-red-500 text-red-500' : 
                      'border-slate-200 focus:border-indigo-500 text-slate-800'}`}
                    autoComplete="off"
                    autoCorrect="off"
                    autoCapitalize="off"
                    spellCheck="false"
                  />
                </div>

                {showHint && status === 'idle' && (
                  <div className="mt-4 text-sm text-slate-400 animate-fade-in">
                    提示: 首字母是 <span className="font-bold text-slate-600">{currentWord.word.substring(0, 1).toUpperCase()}</span>...
                  </div>
                )}
              </form>

              <div className="mt-12 text-sm text-slate-400">
                按 <span className="font-mono bg-slate-100 px-2 py-0.5 rounded border border-slate-200">Enter</span> 提交
              </div>
            </>
          )}
        </div>
      </div>
    </div>
  );
};

// Simple synth sounds to avoid external dependencies
export const playSuccessSound = () => {
  const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
  if (!AudioContext) return;

  const ctx = new AudioContext();
  const now = ctx.currentTime;

  // Helper to play a bell-like note
  const playNote = (freq: number, startTime: number, duration: number) => {
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();

    osc.type = 'sine'; // Sine wave for a pure bell tone
    osc.frequency.setValueAtTime(freq, startTime);

    // Envelope for bell sound: fast attack, exponential decay
    gain.gain.setValueAtTime(0, startTime);
    gain.gain.linearRampToValueAtTime(0.15, startTime + 0.02); // Quick attack
    gain.gain.exponentialRampToValueAtTime(0.001, startTime + duration); // Long decay

    osc.connect(gain);
    gain.connect(ctx.destination);

    osc.start(startTime);
    osc.stop(startTime + duration);
  };

  // Play "Ding" (High Note, e.g., E5)
  playNote(659.25, now, 0.8);

  // Play "Dong" (Lower Note, e.g., C5) slightly later
  playNote(523.25, now + 0.25, 1.2);
};

export const playErrorSound = () => {
  const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
  if (!AudioContext) return;

  const ctx = new AudioContext();
  const osc = ctx.createOscillator();
  const gain = ctx.createGain();

  osc.type = 'sawtooth';
  osc.frequency.setValueAtTime(200, ctx.currentTime);
  osc.frequency.linearRampToValueAtTime(100, ctx.currentTime + 0.2);

  gain.gain.setValueAtTime(0.1, ctx.currentTime);
  gain.gain.linearRampToValueAtTime(0.01, ctx.currentTime + 0.3);

  osc.connect(gain);
  gain.connect(ctx.destination);

  osc.start();
  osc.stop(ctx.currentTime + 0.3);
};

import { GoogleGenAI, Type } from "@google/genai";
import { WordData } from '../types';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const enrichVocabulary = async (words: string[]): Promise<WordData[]> => {
  if (words.length === 0) return [];

  const prompt = `
    I have a list of English vocabulary words for a student. 
    Please process these words and provide:
    1. A concise definition in Simplified Chinese (中文).
    2. Part of speech.
    3. A "cloze" example sentence in English (a sentence where the target word is replaced by '_______').

    The words are: ${words.join(', ')}.

    Return the data in a strict JSON structure.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              word: { type: Type.STRING, description: "The vocabulary word (lowercase)" },
              definition: { type: Type.STRING, description: "Definition in Simplified Chinese" },
              partOfSpeech: { type: Type.STRING, description: "e.g., noun, verb, adjective" },
              exampleSentence: { type: Type.STRING, description: "A sentence using the word, but the word itself is replaced with _______" }
            },
            required: ["word", "definition", "partOfSpeech", "exampleSentence"]
          }
        }
      }
    });

    const rawData = JSON.parse(response.text || '[]');

    // Map to our internal structure with IDs
    return rawData.map((item: any) => ({
      id: crypto.randomUUID(),
      word: item.word.toLowerCase().trim(),
      definition: item.definition,
      exampleSentence: item.exampleSentence,
      partOfSpeech: item.partOfSpeech,
      correctCount: 0
    }));

  } catch (error) {
    console.error("Gemini API Error:", error);
    throw new Error("Failed to enrich vocabulary.");
  }
};

export const generateWordImage = async (word: string): Promise<string | null> => {
  try {
    // Improved prompt for clarity and relevance
    const prompt = `Create a clear, literal, and educational illustration suitable for a vocabulary flashcard of the English word: "${word}". 
    The image should concretely depict the definition of the word. 
    Use a clean, semi-realistic or high-quality vector style. 
    The subject should be centered on a plain white background. 
    No text inside the image.`;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          { text: prompt },
        ],
      },
      config: {
        imageConfig: {
          aspectRatio: "1:1" // Square image
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (error) {
    console.error("Image Gen Error:", error);
    return null;
  }
};

