              ) : (
                <form onSubmit={handleSpellingSubmit} className="w-full relative shrink-0 mb-4">
                  <div className={`relative transition-transform duration-300 ${status === 'incorrect' ? 'animate-shake' : ''}`}>
                    <input
                      ref={inputRef}
                      type="text"
