export interface WordData {
  id: string;
  word: string;
  definition: string;
  exampleSentence: string; // The sentence with the word replaced by underscores
  partOfSpeech: string;
  correctCount: number;
  lastPracticed?: string;
  imageUrl?: string;
  // New fields for the song feature
