import { GoogleGenAI, Type } from "@google/genai";
import { WordData } from '../types';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateWordImage = async (word: string): Promise<string | null> => {
  try {
    // Improved prompt: simple, vector, white background
    const prompt = `A simple, bold, minimalist vector illustration of the English word "${word}". 
    The image should be a direct, literal representation suitable for a vocabulary flashcard.
    Single central subject on a pure white background. 
    Flat design, no text, no abstract concepts.`;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          { text: prompt },
        ],
      },
      config: {
        imageConfig: {
          aspectRatio: "1:1"
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (error) {
    console.error("Image Gen Error:", error);
    return null;
  }
};

export const enrichVocabulary = async (words: string[]): Promise<WordData[]> => {
  if (words.length === 0) return [];

  const prompt = `
    I have a list of English vocabulary words for a student. 
    Please process these words and provide:
    1. A concise definition in Simplified Chinese (中文).
    2. Part of speech.
    3. A "cloze" example sentence in English (word replaced by '_______').
    4. A famous, catchy song lyric that contains this word (in English). Ideally from pop culture (Taylor Swift, Beatles, Queen, Adele, etc.).
    5. The Artist and Song Name for that lyric.

    The words are: ${words.join(', ')}.

    Return the data in a strict JSON structure.
  `;

  try {
    // 1. Get Text Data
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              word: { type: Type.STRING, description: "The vocabulary word (lowercase)" },
              definition: { type: Type.STRING, description: "Definition in Simplified Chinese" },
              partOfSpeech: { type: Type.STRING, description: "e.g., noun, verb, adjective" },
              exampleSentence: { type: Type.STRING, description: "A sentence using the word, but the word itself is replaced with _______" },
              songLyric: { type: Type.STRING, description: "A line from a famous song containing the word" },
              songInfo: { type: Type.STRING, description: "Artist - Song Name" }
            },
            required: ["word", "definition", "partOfSpeech", "exampleSentence"]
          }
        }
      }
    });

    const rawData = JSON.parse(response.text || '[]');

    // 2. Map to internal structure
    const processedWords: WordData[] = rawData.map((item: any) => ({
      id: crypto.randomUUID(),
      word: item.word.toLowerCase().trim(),
      definition: item.definition,
      exampleSentence: item.exampleSentence,
      partOfSpeech: item.partOfSpeech,
      songLyric: item.songLyric,
      songInfo: item.songInfo,
      correctCount: 0,
      imageUrl: undefined // Will be filled below
    }));

    // 3. Pre-generate images for ALL words immediately
    await Promise.all(processedWords.map(async (word) => {
        try {
            const imageUrl = await generateWordImage(word.word);
            if (imageUrl) {
                word.imageUrl = imageUrl;
            }
        } catch (imgError) {
            console.warn(`Failed to generate image for ${word.word}`, imgError);
        }
    }));

    return processedWords;

  } catch (error) {
    console.error("Gemini API Error:", error);
    throw new Error("Failed to enrich vocabulary.");
  }
};

// Simple synth sounds to avoid external dependencies
export const playSuccessSound = () => {
  const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
  if (!AudioContext) return;

  const ctx = new AudioContext();
  const now = ctx.currentTime;

  // Helper to play a bell-like note
  const playNote = (freq: number, startTime: number, duration: number) => {
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();

    osc.type = 'sine'; // Sine wave for a pure bell tone
    osc.frequency.setValueAtTime(freq, startTime);

    // Envelope for bell sound: fast attack, exponential decay
    gain.gain.setValueAtTime(0, startTime);
    gain.gain.linearRampToValueAtTime(0.15, startTime + 0.02); // Quick attack
    gain.gain.exponentialRampToValueAtTime(0.001, startTime + duration); // Long decay

    osc.connect(gain);
    gain.connect(ctx.destination);

    osc.start(startTime);
    osc.stop(startTime + duration);
  };

  // Play "Ding" (High Note, e.g., E5)
  playNote(659.25, now, 0.8);

  // Play "Dong" (Lower Note, e.g., C5) slightly later
  playNote(523.25, now + 0.25, 1.2);
};

export const playErrorSound = () => {
  const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
  if (!AudioContext) return;

  const ctx = new AudioContext();
  const osc = ctx.createOscillator();
  const gain = ctx.createGain();

  osc.type = 'sawtooth';
  osc.frequency.setValueAtTime(200, ctx.currentTime);
  osc.frequency.linearRampToValueAtTime(100, ctx.currentTime + 0.2);

  gain.gain.setValueAtTime(0.1, ctx.currentTime);
  gain.gain.linearRampToValueAtTime(0.01, ctx.currentTime + 0.3);

  osc.connect(gain);
  gain.connect(ctx.destination);

  osc.start();
  osc.stop(ctx.currentTime + 0.3);
};

export const playVictorySound = () => {
  const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
  if (!AudioContext) return;

  const ctx = new AudioContext();
  const now = ctx.currentTime;

  const playNote = (freq: number, startTime: number, duration: number, type: OscillatorType = 'triangle') => {
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();

    osc.type = type;
    osc.frequency.setValueAtTime(freq, startTime);

    gain.gain.setValueAtTime(0, startTime);
    gain.gain.linearRampToValueAtTime(0.2, startTime + 0.05);
    gain.gain.linearRampToValueAtTime(0, startTime + duration);

    osc.connect(gain);
    gain.connect(ctx.destination);

    osc.start(startTime);
    osc.stop(startTime + duration);
  };

  // C Major Arpeggio fanfare
  playNote(523.25, now, 0.2);       // C5
  playNote(659.25, now + 0.15, 0.2); // E5
  playNote(783.99, now + 0.30, 0.2); // G5
  playNote(1046.50, now + 0.45, 0.8, 'sine'); // C6 (Long)

  // Confetti sound (noise burst)
  const bufferSize = ctx.sampleRate * 1; 
  const buffer = ctx.createBuffer(1, bufferSize, ctx.sampleRate);
  const data = buffer.getChannelData(0);
  for (let i = 0; i < bufferSize; i++) {
    data[i] = Math.random() * 2 - 1;
  }
  const noise = ctx.createBufferSource();
  noise.buffer = buffer;
  const noiseGain = ctx.createGain();
  noiseGain.gain.setValueAtTime(0.1, now + 0.45);
  noiseGain.gain.exponentialRampToValueAtTime(0.001, now + 1.0);
  noise.connect(noiseGain);
  noiseGain.connect(ctx.destination);
  noise.start(now + 0.45);
};

export const speakText = (text: string, rate: number = 0.9) => {
  if (!('speechSynthesis' in window)) return;

  // Cancel any ongoing speech
  window.speechSynthesis.cancel();

  const utterance = new SpeechSynthesisUtterance(text);
  utterance.lang = 'en-US';
  utterance.rate = rate; 

  // Try to find a good English voice
  const voices = window.speechSynthesis.getVoices();
  const preferredVoice = voices.find(v => v.lang.startsWith('en') && v.name.includes('Google')) || 
                         voices.find(v => v.lang.startsWith('en'));

  if (preferredVoice) {
    utterance.voice = preferredVoice;
  }

  window.speechSynthesis.speak(utterance);
};

import React, { useState, useEffect, useRef } from 'react';
import { WordData, QuizResult } from '../types';
import { playSuccessSound, playErrorSound, playVictorySound, speakText } from '../services/audioService';

interface QuizSessionProps {
  words: WordData[];
  onComplete: (results: QuizResult[]) => void;
  onUpdateWord: (id: string, updates: Partial<WordData>) => void;
  onExit: () => void;
}

type QuizMode = 'SPELL_FROM_DEF' | 'SPELL_FROM_AUDIO' | 'MEANING_FROM_WORD';

export const QuizSession: React.FC<QuizSessionProps> = ({ words, onComplete, onUpdateWord, onExit }) => {
  const [queue, setQueue] = useState<WordData[]>([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [input, setInput] = useState('');
  const [status, setStatus] = useState<'idle' | 'correct' | 'incorrect'>('idle');
  const [showHint, setShowHint] = useState(false);

  // New States for Mixed Mode
  const [quizMode, setQuizMode] = useState<QuizMode>('SPELL_FROM_DEF');
  const [choices, setChoices] = useState<WordData[]>([]);

  // New State for Completion Screen
  const [isFinished, setIsFinished] = useState(false);

  const inputRef = useRef<HTMLInputElement>(null);
  const nextButtonRef = useRef<HTMLButtonElement>(null);
  const hasInitialized = useRef(false);

  // Cleanup speech on unmount
  useEffect(() => {
    return () => {
      window.speechSynthesis?.cancel();
    };
  }, []);

  // Play Victory Sound when finished
  useEffect(() => {
    if (isFinished) {
      playVictorySound();
    }
  }, [isFinished]);

  // Initialize Queue
  useEffect(() => {
    if (!hasInitialized.current && words.length > 0) {
      const shuffled = [...words].sort(() => Math.random() - 0.5);
      setQueue(shuffled);
      hasInitialized.current = true;
      // Initialize first mode
      setupNewRound(shuffled[0], shuffled);
    }
  }, [words]);

  const currentWord = queue[currentIndex];

  // Logic to set up the mode and choices for a new word
  const setupNewRound = (word: WordData, allWords: WordData[]) => {
    const modes: QuizMode[] = ['SPELL_FROM_DEF', 'SPELL_FROM_AUDIO', 'MEANING_FROM_WORD'];
    const nextMode = modes[Math.floor(Math.random() * modes.length)];
    setQuizMode(nextMode);

    if (nextMode === 'MEANING_FROM_WORD') {
      // Generate distractors
      const distractors = allWords
        .filter(w => w.id !== word.id)
        .sort(() => 0.5 - Math.random())
        .slice(0, 3);
      const options = [word, ...distractors].sort(() => 0.5 - Math.random());
      setChoices(options);
    } else if (nextMode === 'SPELL_FROM_AUDIO') {
       // Auto play audio after a short delay
       setTimeout(() => speakText(word.word), 500);
    }
  };

  // Focus Logic
  useEffect(() => {
    const timer = setTimeout(() => {
      if (isFinished) return; // Don't focus if finished

      if (status === 'idle') {
        if (quizMode !== 'MEANING_FROM_WORD') {
          inputRef.current?.focus();
        }
      } else if (status === 'correct') {
        nextButtonRef.current?.focus();
      }
    }, 100);
    return () => clearTimeout(timer);
  }, [status, currentIndex, quizMode, isFinished]);

  const handleSpellingSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentWord || status !== 'idle') return;

    const cleanInput = input.trim().toLowerCase();
    const cleanTarget = currentWord.word.toLowerCase();

    if (cleanInput === cleanTarget) {
      handleCorrect();
    } else {
      handleIncorrect();
    }
  };

  const handleChoiceSelect = (selectedId: string) => {
    if (!currentWord || status !== 'idle') return;

    if (selectedId === currentWord.id) {
      handleCorrect();
    } else {
      handleIncorrect();
    }
  };

  const handleCorrect = () => {
    setStatus('correct');

    // Play the standard ping for immediate feedback
    playSuccessSound();

    // Speak logic: First the word, then the song if available
    let speechDelay = 100;

    if (currentWord.songLyric && currentWord.songInfo) {
      const speechText = `Correct! ${currentWord.word}. Like in the song ${currentWord.songInfo}: ${currentWord.songLyric}`;
      setTimeout(() => speakText(speechText, 0.95), speechDelay);
    } else {
      setTimeout(() => speakText(currentWord.word), speechDelay);
    }

    const newCount = currentWord.correctCount + 1;
    onUpdateWord(currentWord.id, { 
      correctCount: newCount, 
      lastPracticed: new Date().toISOString() 
    });
  };

  const handleIncorrect = () => {
    setStatus('incorrect');
    playErrorSound();

    setTimeout(() => {
      setStatus('idle');
      setInput('');
      setShowHint(true);
    }, 1000);
  };

  const handleNext = () => {
    if (currentIndex < queue.length - 1) {
      const nextIndex = currentIndex + 1;
      setCurrentIndex(nextIndex);
      setStatus('idle');
      setInput('');
      setShowHint(false);
      setupNewRound(queue[nextIndex], queue);
    } else {
      setIsFinished(true);
    }
  };

  if (isFinished) {
    return (
      <div className="w-full max-w-lg mx-auto flex flex-col h-full justify-center items-center p-4">
        <div className="bg-white shadow-xl rounded-2xl p-8 w-full text-center animate-fade-in-up flex flex-col items-center">
           <div className="w-24 h-24 bg-green-100 rounded-full flex items-center justify-center mb-6 text-green-500 shadow-sm animate-bounce">
             <svg xmlns="http://www.w3.org/2000/svg" width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M6 9H4.5a2.5 2.5 0 0 1 0-5H6"></path><path d="M18 9h1.5a2.5 2.5 0 0 0 0-5H18"></path><path d="M4 22h16"></path><path d="M10 14.66V17c0 .55-.47.98-.97 1.21C7.85 18.75 7 20.24 7 22"></path><path d="M14 14.66V17c0 .55.47.98.97 1.21C16.15 18.75 17 20.24 17 22"></path><path d="M18 2H6v7a6 6 0 0 0 12 0V2Z"></path></svg>
           </div>
           <h2 className="text-3xl font-bold text-slate-800 mb-2">周任务完成！</h2>
           <p className="text-slate-500 mb-8 text-lg">你已经成功掌握了所有的单词。</p>

           <button
             onClick={() => onComplete([])}
             className="w-full bg-indigo-600 text-white font-bold py-4 px-6 rounded-xl shadow-lg shadow-indigo-500/30 hover:bg-indigo-700 transition-all active:scale-95 flex items-center justify-center gap-2"
           >
             <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M3 9l9-7 9 7v11a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2z"></path><polyline points="9 22 9 12 15 12 15 22"></polyline></svg>
             回到主页
           </button>
        </div>
      </div>
    );
  }

  if (!currentWord) return <div className="p-8 text-center text-slate-500">准备中...</div>;

  const progress = ((currentIndex) / queue.length) * 100;

  // Helper to render the question part based on mode
  const renderQuestion = () => {
    switch (quizMode) {
      case 'SPELL_FROM_DEF':
        return (
          <div className="flex flex-col items-center animate-fade-in">
             <div className="text-xs font-bold text-indigo-500 uppercase tracking-wide bg-indigo-50 inline-block px-3 py-1 rounded-full mb-4">
               根据中文拼写
            </div>
            <p className="text-slate-700 text-xl sm:text-2xl font-medium leading-relaxed px-2 mb-2">
              {currentWord.definition}
            </p>
            <p className="text-slate-400 text-sm mb-6">{currentWord.partOfSpeech}</p>
          </div>
        );
      case 'SPELL_FROM_AUDIO':
        return (
          <div className="flex flex-col items-center animate-fade-in">
            <div className="text-xs font-bold text-pink-500 uppercase tracking-wide bg-pink-50 inline-block px-3 py-1 rounded-full mb-6">
               听音拼写
            </div>
            <button 
              type="button"
              onClick={() => speakText(currentWord.word)}
              className="w-24 h-24 rounded-full bg-indigo-100 text-indigo-600 flex items-center justify-center hover:bg-indigo-200 transition-all active:scale-95 mb-6"
            >
              <svg xmlns="http://www.w3.org/2000/svg" width="40" height="40" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polygon points="11 5 6 9 2 9 2 15 6 15 11 19 11 5"></polygon><path d="M19.07 4.93a10 10 0 0 1 0 14.14M15.54 8.46a5 5 0 0 1 0 7.07"></path></svg>
            </button>
            <p className="text-slate-400 text-sm mb-2">点击图标重播读音</p>
          </div>
        );
      case 'MEANING_FROM_WORD':
        return (
          <div className="flex flex-col items-center animate-fade-in mb-4">
             <div className="text-xs font-bold text-teal-500 uppercase tracking-wide bg-teal-50 inline-block px-3 py-1 rounded-full mb-4">
               英译中
            </div>
            <h2 className="text-3xl sm:text-4xl font-bold text-slate-800 mb-2">{currentWord.word}</h2>
            <p className="text-slate-400 text-sm">{currentWord.partOfSpeech}</p>
          </div>
        );
    }
  };

  return (
    <div className="w-full max-w-lg mx-auto flex flex-col gap-4">
      {/* Progress Bar */}
      <div className="bg-white/30 backdrop-blur-sm h-1.5 rounded-full overflow-hidden shrink-0 mx-1">
        <div 
          className="bg-indigo-500 h-full transition-all duration-500 ease-out"
          style={{ width: `${progress}%` }}
        ></div>
      </div>

      <div className="bg-white shadow-xl rounded-2xl overflow-hidden relative flex flex-col min-h-[400px]">
        {/* Card Header */}
        <div className="bg-indigo-600 px-6 py-4 flex justify-between items-center text-white shrink-0">
          <span className="font-semibold text-indigo-100 tracking-wider text-xs uppercase">单词 {currentIndex + 1} / {queue.length}</span>
          <button onClick={onExit} className="text-indigo-200 hover:text-white transition-colors p-1">
            <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>
          </button>
        </div>

        {/* Card Body */}
        <div className="p-6 sm:p-10 flex flex-col items-center text-center flex-1">

          {status === 'correct' ? (
            <div className="animate-fade-in flex flex-col items-center w-full gap-6">
              <div className="flex flex-col items-center gap-1 sm:gap-2">
                <div className="text-xl sm:text-2xl font-bold text-green-500 flex items-center gap-2">
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7"></path></svg>
                  回答正确!
                </div>
                <div className="text-3xl sm:text-4xl text-slate-800 font-bold capitalize">{currentWord.word}</div>
                <div className="text-slate-500 text-sm mb-2">{currentWord.definition}</div>

                {currentWord.songInfo && currentWord.songLyric && (
                  <div className="bg-amber-50 border border-amber-200 rounded-lg p-3 w-full max-w-sm">
                    <div className="flex items-center gap-2 text-amber-600 text-xs font-bold uppercase mb-1">
                      <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M9 18V5l12-2v13"></path><circle cx="6" cy="18" r="3"></circle><circle cx="18" cy="16" r="3"></circle></svg>
                      {currentWord.songInfo}
                    </div>
                    <p className="text-slate-700 italic font-medium">"{currentWord.songLyric}"</p>
                  </div>
                )}
              </div>

              <div className="w-full flex items-center justify-center">
                <div className="w-full max-w-[280px] aspect-square rounded-xl overflow-hidden shadow-md border border-slate-100 bg-slate-50 flex items-center justify-center relative">
                  {currentWord.imageUrl ? (
                    <img 
                      src={currentWord.imageUrl} 
                      alt={currentWord.word} 
                      className="w-full h-full object-contain animate-fade-in bg-white" 
                    />
                  ) : (
                    <div className="text-slate-400 flex flex-col items-center p-4">
                        <span className="text-xs">暂无图片</span>
                    </div>
                  )}
                </div>
              </div>

              <button
                ref={nextButtonRef}
                onClick={handleNext}
                className="w-full bg-indigo-600 text-white font-bold py-3.5 px-6 rounded-xl shadow-lg shadow-indigo-500/30 active:scale-95 transition-all hover:bg-indigo-700 flex items-center justify-center gap-2 mb-2"
              >
                {currentIndex < queue.length - 1 ? (
                  <>
                    下一个单词
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 7l5 5m0 0l-5 5m5-5H6"></path></svg>
                  </>
                ) : (
                  <>
                    完成练习
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7"></path></svg>
                  </>
                )}
              </button>
            </div>
          ) : (
            <div className="flex flex-col w-full flex-1">
              <div className="flex-1 flex flex-col justify-center items-center mb-6 space-y-4 min-h-[120px]">
                {renderQuestion()}
              </div>

              {quizMode === 'MEANING_FROM_WORD' ? (
                <div className="w-full flex flex-col gap-3">
                  {choices.map((choice) => (
                    <button
                      key={choice.id}
                      onClick={() => handleChoiceSelect(choice.id)}
                      className={`w-full p-4 rounded-xl border-2 text-left transition-all active:scale-[0.98]
                        ${status === 'incorrect' 
                          ? 'border-slate-100 bg-slate-50 text-slate-400' 
                          : 'border-slate-200 bg-white hover:border-indigo-300 hover:bg-indigo-50 text-slate-700'
                        }`}
                    >
                       {choice.definition}
                    </button>
                  ))}
                  {status === 'incorrect' && (
                     <div className="text-center text-red-500 mt-2 font-medium animate-shake">
                       选择错误，请重试
                     </div>
                  )}
                </div>
              ) : (
                <form onSubmit={handleSpellingSubmit} className="w-full relative shrink-0 mb-4">
                  <div className={`relative transition-transform duration-300 ${status === 'incorrect' ? 'animate-shake' : ''}`}>
                    <input
                      ref={inputRef}
                      type="text"
                      value={input}
                      onChange={(e) => setInput(e.target.value)}
                      placeholder="输入单词..."
                      className={`w-full text-center text-2xl sm:text-3xl font-bold py-3 sm:py-4 bg-transparent border-b-2 sm:border-b-4 focus:outline-none transition-colors rounded-none
                        ${status === 'incorrect' ? 'border-red-500 text-red-500' : 
                        'border-slate-200 focus:border-indigo-500 text-slate-800'}`}
                      autoComplete="off"
                      autoCorrect="off"
                      autoCapitalize="off"
                      spellCheck="false"
                    />
                  </div>

                  {showHint && status === 'idle' && (
                    <div className="mt-3 text-sm text-slate-400 animate-fade-in">
                      提示: 首字母是 <span className="font-bold text-slate-600">{currentWord.word.substring(0, 1).toUpperCase()}</span>
                    </div>
                  )}
                </form>
              )}
            </div>
          )}
        </div>
      </div>
      <div className="h-4 sm:h-0"></div>
    </div>
  );
};

// Using a common public Vercel deployment of the Netease API.
// In a production environment, you should deploy your own instance of https://github.com/Binaryify/NeteaseCloudMusicApi
const API_BASE_URL = 'https://netease-cloud-music-api-brilliance.vercel.app';

interface SongSearchResult {
  result?: {
    songs?: {
      id: number;
      name: string;
      ar: { name: string }[];
    }[];
  };
}

interface SongUrlResult {
  data: {
    id: number;
    url: string;
    freeTrialInfo?: {
      start: number;
      end: number;
    }
  }[];
}

interface LyricResult {
  lrc?: {
    lyric: string;
  };
}

export interface SongPlayData {
  url: string;
  startTime: number;
  duration: number;
}

// Helper to normalize text for fuzzy matching (remove punctuation, lowercase)
const normalize = (text: string) => {
  return text.toLowerCase().replace(/[.,/#!$%^&*;:{}=\-_`~()]/g, "").replace(/\s{2,}/g, " ").trim();
};

const parseLrc = (lrc: string): { time: number; text: string }[] => {
  const lines = lrc.split('\n');
  const result: { time: number; text: string }[] = [];
  const timeRegex = /\[(\d{2}):(\d{2})\.(\d{2,3})\]/;

  for (const line of lines) {
    const match = timeRegex.exec(line);
    if (match) {
      const minutes = parseInt(match[1], 10);
      const seconds = parseInt(match[2], 10);
      const milliseconds = parseInt(match[3], 10);
      // Convert to seconds
      const time = minutes * 60 + seconds + milliseconds / 1000;
      const text = line.replace(timeRegex, '').trim();
      if (text) {
        result.push({ time, text });
      }
    }
  }
  return result;
};

export const getSongSegment = async (searchQuery: string, targetLyric: string): Promise<SongPlayData | null> => {
  try {
    // 1. Search for the song
    // Using fetch directly. Note: This relies on the API supporting CORS or being proxied.
    const searchRes = await fetch(`${API_BASE_URL}/cloudsearch?keywords=${encodeURIComponent(searchQuery)}&limit=1`);
    if (!searchRes.ok) throw new Error('Search failed');
    const searchData: SongSearchResult = await searchRes.json();

    const song = searchData.result?.songs?.[0];
    if (!song) return null;

    // 2. Get Song URL and Lyrics in parallel
    const [urlRes, lyricRes] = await Promise.all([
      fetch(`${API_BASE_URL}/song/url/v1?id=${song.id}&level=standard`),
      fetch(`${API_BASE_URL}/lyric?id=${song.id}`)
    ]);

    if (!urlRes.ok || !lyricRes.ok) throw new Error('Details fetch failed');

    const urlData: SongUrlResult = await urlRes.json();
    const lyricData: LyricResult = await lyricRes.json();

    const audioUrl = urlData.data?.[0]?.url;
    if (!audioUrl) return null;

    // 3. Find the timestamp
    let startTime = 0;
    // Default duration to play if we find the line
    const PLAY_DURATION = 8; 

    if (lyricData.lrc?.lyric) {
      const parsedLyrics = parseLrc(lyricData.lrc.lyric);
      const normalizedTarget = normalize(targetLyric);

      // Find the best matching line
      const matchIndex = parsedLyrics.findIndex(line => normalize(line.text).includes(normalizedTarget));

      if (matchIndex !== -1) {
        startTime = parsedLyrics[matchIndex].time;
        // Try to adjust start time slightly earlier to catch the breath before the line
        startTime = Math.max(0, startTime - 0.5);
      } else {
        // Fallback: simple text search without time parsing if parser fails, 
        // but since we need time, if we can't match, we might just start from beginning or return null?
        // Let's start from 0 if not found, or maybe middle? 
        // Actually, if we can't find the lyric, playing the intro is better than nothing.
        console.warn('Lyric line not found in LRC, playing from start');
      }
    }

    return {
      url: audioUrl,
      startTime: startTime,
      duration: PLAY_DURATION
    };

  } catch (error) {
    console.error("Music Service Error:", error);
    return null;
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { WordData, QuizResult } from '../types';
import { playSuccessSound, playErrorSound, playVictorySound, speakText } from '../services/audioService';
import { getSongSegment, SongPlayData } from '../services/musicService';
import toast from 'react-hot-toast';

interface QuizSessionProps {
  words: WordData[];
  onComplete: (results: QuizResult[]) => void;
  onUpdateWord: (id: string, updates: Partial<WordData>) => void;
  onExit: () => void;
}

type QuizMode = 'SPELL_FROM_DEF' | 'SPELL_FROM_AUDIO' | 'MEANING_FROM_WORD';

export const QuizSession: React.FC<QuizSessionProps> = ({ words, onComplete, onUpdateWord, onExit }) => {
  const [queue, setQueue] = useState<WordData[]>([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [input, setInput] = useState('');
  const [status, setStatus] = useState<'idle' | 'correct' | 'incorrect'>('idle');
  const [showHint, setShowHint] = useState(false);

  // New States for Mixed Mode
  const [quizMode, setQuizMode] = useState<QuizMode>('SPELL_FROM_DEF');
  const [choices, setChoices] = useState<WordData[]>([]);

  // Music State
  const [isPlayingMusic, setIsPlayingMusic] = useState(false);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  // New State for Completion Screen
  const [isFinished, setIsFinished] = useState(false);

  const inputRef = useRef<HTMLInputElement>(null);
  const nextButtonRef = useRef<HTMLButtonElement>(null);
  const hasInitialized = useRef(false);

  // Cleanup speech and audio on unmount
  useEffect(() => {
    return () => {
      window.speechSynthesis?.cancel();
      if (audioRef.current) {
        audioRef.current.pause();
        audioRef.current = null;
      }
    };
  }, []);

  // Play Victory Sound when finished
  useEffect(() => {
    if (isFinished) {
      playVictorySound();
    }
  }, [isFinished]);

  // Initialize Queue
  useEffect(() => {
    if (!hasInitialized.current && words.length > 0) {
      const shuffled = [...words].sort(() => Math.random() - 0.5);
      setQueue(shuffled);
      hasInitialized.current = true;
      // Initialize first mode
      setupNewRound(shuffled[0], shuffled);
    }
  }, [words]);

  const currentWord = queue[currentIndex];

  // Logic to set up the mode and choices for a new word
  const setupNewRound = (word: WordData, allWords: WordData[]) => {
    const modes: QuizMode[] = ['SPELL_FROM_DEF', 'SPELL_FROM_AUDIO', 'MEANING_FROM_WORD'];
    const nextMode = modes[Math.floor(Math.random() * modes.length)];
    setQuizMode(nextMode);

    if (nextMode === 'MEANING_FROM_WORD') {
      // Generate distractors
      const distractors = allWords
        .filter(w => w.id !== word.id)
        .sort(() => 0.5 - Math.random())
        .slice(0, 3);
      const options = [word, ...distractors].sort(() => 0.5 - Math.random());
      setChoices(options);
    } else if (nextMode === 'SPELL_FROM_AUDIO') {
       // Auto play audio after a short delay
       setTimeout(() => speakText(word.word), 500);
    }
  };

  // Focus Logic
  useEffect(() => {
    const timer = setTimeout(() => {
      if (isFinished) return; // Don't focus if finished

      if (status === 'idle') {
        if (quizMode !== 'MEANING_FROM_WORD') {
          inputRef.current?.focus();
        }
      } else if (status === 'correct') {
        nextButtonRef.current?.focus();
      }
    }, 100);
    return () => clearTimeout(timer);
  }, [status, currentIndex, quizMode, isFinished]);

  const handleSpellingSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentWord || status !== 'idle') return;

    const cleanInput = input.trim().toLowerCase();
    const cleanTarget = currentWord.word.toLowerCase();

    if (cleanInput === cleanTarget) {
      handleCorrect();
    } else {
      handleIncorrect();
    }
  };

  const handleChoiceSelect = (selectedId: string) => {
    if (!currentWord || status !== 'idle') return;

    if (selectedId === currentWord.id) {
      handleCorrect();
    } else {
      handleIncorrect();
    }
  };

  const handleCorrect = async () => {
    setStatus('correct');
    playSuccessSound(); // Immediate feedback 'ding'

    // Speak the word immediately
    speakText(currentWord.word);

    // Try to play the song
    if (currentWord.songInfo && currentWord.songLyric) {
      setIsPlayingMusic(true);
      try {
        const songData = await getSongSegment(currentWord.songInfo, currentWord.songLyric);

        if (songData) {
          // Stop any previous audio
          if (audioRef.current) {
            audioRef.current.pause();
          }

          const audio = new Audio(songData.url);
          audioRef.current = audio;
          audio.currentTime = songData.startTime;

          // Fade in/out logic could be added here, but simple play is safer for mobile
          await audio.play();

          // Stop after duration
          setTimeout(() => {
            if (audioRef.current === audio) {
              const fadeOut = setInterval(() => {
                 if (audio.volume > 0.1) {
                     audio.volume -= 0.1;
                 } else {
                     clearInterval(fadeOut);
                     audio.pause();
                     setIsPlayingMusic(false);
                 }
              }, 100);
            }
          }, songData.duration * 1000);

        } else {
          // Fallback if song not found
          console.log("Song not found, using TTS fallback");
          const speechText = `Like in the song ${currentWord.songInfo}: ${currentWord.songLyric}`;
          setTimeout(() => speakText(speechText, 0.95), 800);
          setIsPlayingMusic(false);
        }
      } catch (e) {
        console.error("Playback failed", e);
        setIsPlayingMusic(false);
        // Fallback TTS
        const speechText = `Like in the song ${currentWord.songInfo}: ${currentWord.songLyric}`;
        setTimeout(() => speakText(speechText, 0.95), 800);
      }
    } else {
        // No song info, just normal behavior
    }

    const newCount = currentWord.correctCount + 1;
    onUpdateWord(currentWord.id, { 
      correctCount: newCount, 
      lastPracticed: new Date().toISOString() 
    });
  };

  const handleIncorrect = () => {
    setStatus('incorrect');
    playErrorSound();

    setTimeout(() => {
      setStatus('idle');
      setInput('');
      setShowHint(true);
    }, 1000);
  };

  const handleNext = () => {
    // Stop music when moving to next
    if (audioRef.current) {
        audioRef.current.pause();
        audioRef.current = null;
        setIsPlayingMusic(false);
    }

    if (currentIndex < queue.length - 1) {
      const nextIndex = currentIndex + 1;
      setCurrentIndex(nextIndex);
      setStatus('idle');
      setInput('');
      setShowHint(false);
      setupNewRound(queue[nextIndex], queue);
    } else {
      setIsFinished(true);
    }
  };

  if (isFinished) {
    return (
      <div className="w-full max-w-lg mx-auto flex flex-col h-full justify-center items-center p-4">
        <div className="bg-white shadow-xl rounded-2xl p-8 w-full text-center animate-fade-in-up flex flex-col items-center">
           <div className="w-24 h-24 bg-green-100 rounded-full flex items-center justify-center mb-6 text-green-500 shadow-sm animate-bounce">
             <svg xmlns="http://www.w3.org/2000/svg" width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M6 9H4.5a2.5 2.5 0 0 1 0-5H6"></path><path d="M18 9h1.5a2.5 2.5 0 0 0 0-5H18"></path><path d="M4 22h16"></path><path d="M10 14.66V17c0 .55-.47.98-.97 1.21C7.85 18.75 7 20.24 7 22"></path><path d="M14 14.66V17c0 .55.47.98.97 1.21C16.15 18.75 17 20.24 17 22"></path><path d="M18 2H6v7a6 6 0 0 0 12 0V2Z"></path></svg>
           </div>
           <h2 className="text-3xl font-bold text-slate-800 mb-2">周任务完成！</h2>
           <p className="text-slate-500 mb-8 text-lg">你已经成功掌握了所有的单词。</p>

           <button
             onClick={() => onComplete([])}
             className="w-full bg-indigo-600 text-white font-bold py-4 px-6 rounded-xl shadow-lg shadow-indigo-500/30 hover:bg-indigo-700 transition-all active:scale-95 flex items-center justify-center gap-2"
           >
             <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M3 9l9-7 9 7v11a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2z"></path><polyline points="9 22 9 12 15 12 15 22"></polyline></svg>
             回到主页
           </button>
        </div>
      </div>
    );
  }

  if (!currentWord) return <div className="p-8 text-center text-slate-500">准备中...</div>;

  const progress = ((currentIndex) / queue.length) * 100;

  // Helper to render the question part based on mode
  const renderQuestion = () => {
    switch (quizMode) {
      case 'SPELL_FROM_DEF':
        return (
          <div className="flex flex-col items-center animate-fade-in">
             <div className="text-xs font-bold text-indigo-500 uppercase tracking-wide bg-indigo-50 inline-block px-3 py-1 rounded-full mb-4">
               根据中文拼写
            </div>
            <p className="text-slate-700 text-xl sm:text-2xl font-medium leading-relaxed px-2 mb-2">
              {currentWord.definition}
            </p>
            <p className="text-slate-400 text-sm mb-6">{currentWord.partOfSpeech}</p>
          </div>
        );
      case 'SPELL_FROM_AUDIO':
        return (
          <div className="flex flex-col items-center animate-fade-in">
            <div className="text-xs font-bold text-pink-500 uppercase tracking-wide bg-pink-50 inline-block px-3 py-1 rounded-full mb-6">
               听音拼写
            </div>
            <button 
              type="button"
              onClick={() => speakText(currentWord.word)}
              className="w-24 h-24 rounded-full bg-indigo-100 text-indigo-600 flex items-center justify-center hover:bg-indigo-200 transition-all active:scale-95 mb-6"
            >
              <svg xmlns="http://www.w3.org/2000/svg" width="40" height="40" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polygon points="11 5 6 9 2 9 2 15 6 15 11 19 11 5"></polygon><path d="M19.07 4.93a10 10 0 0 1 0 14.14M15.54 8.46a5 5 0 0 1 0 7.07"></path></svg>
            </button>
            <p className="text-slate-400 text-sm mb-2">点击图标重播读音</p>
          </div>
        );
      case 'MEANING_FROM_WORD':
        return (
          <div className="flex flex-col items-center animate-fade-in mb-4">
             <div className="text-xs font-bold text-teal-500 uppercase tracking-wide bg-teal-50 inline-block px-3 py-1 rounded-full mb-4">
               英译中
            </div>
            <h2 className="text-3xl sm:text-4xl font-bold text-slate-800 mb-2">{currentWord.word}</h2>
            <p className="text-slate-400 text-sm">{currentWord.partOfSpeech}</p>
          </div>
        );
    }
