// Using a common public Vercel deployment of the Netease API.
const API_BASE_URL = 'https://netease-cloud-music-api-brilliance.vercel.app';

interface SongSearchResult {
  result?: {
    songs?: {
      id: number;
      name: string;
      ar: { name: string }[];
      pop: number; // Popularity score
    }[];
  };
}

interface LyricResult {
  lrc?: {
    lyric: string;
  };
}

export interface SongPlayData {
  url: string;
  startTime: number;
  duration: number;
}

// Helper to normalize text for fuzzy matching (remove punctuation, lowercase, extra spaces)
const normalize = (text: string) => {
  return text.toLowerCase()
    .replace(/['".,/#!$%^&*;:{}=\-_`~()]/g, "") // Remove punctuation
    .replace(/\s+/g, " ") // Collapse spaces
    .trim();
};

const parseLrc = (lrc: string): { time: number; text: string }[] => {
  const lines = lrc.split('\n');
  const result: { time: number; text: string }[] = [];
  // Regex to match [mm:ss.xx] or [mm:ss.xxx]
  const timeRegex = /\[(\d{2}):(\d{2})\.(\d{2,3})\]/;

  for (const line of lines) {
    const match = timeRegex.exec(line);
    if (match) {
      const minutes = parseInt(match[1], 10);
      const seconds = parseInt(match[2], 10);
      const milliseconds = parseInt(match[3], 10);
      // Convert to seconds
      const time = minutes * 60 + seconds + milliseconds / 1000;
      const text = line.replace(/\[.*?\]/g, '').trim(); // Remove all timestamps from line
      if (text) {
        result.push({ time, text });
      }
    }
  }
  return result;
};

export const getSongSegment = async (searchQuery: string, targetLyric: string): Promise<SongPlayData | null> => {
  try {
    // 1. Search for the song
    // We search using the info provided by Gemini (Artist + Song Name)
    // Netease search (type=1) returns results sorted by popularity by default.
    const searchRes = await fetch(`${API_BASE_URL}/cloudsearch?keywords=${encodeURIComponent(searchQuery)}&limit=1`);
    if (!searchRes.ok) throw new Error('Search failed');
    const searchData: SongSearchResult = await searchRes.json();

    // Get the top result (most popular)
    const song = searchData.result?.songs?.[0];
    if (!song) return null;

    // 2. Get Lyrics
    // We do NOT fetch the song URL via API anymore because it often returns 403 or empty for free users.
    // Instead we use the "outer" link hack below.
    const lyricRes = await fetch(`${API_BASE_URL}/lyric?id=${song.id}`);
    if (!lyricRes.ok) throw new Error('Lyric fetch failed');
    const lyricData: LyricResult = await lyricRes.json();

    // 3. Construct Direct Audio URL (The "Outer" Link)
    // This is the key fix for "song not playing". 
    // This URL redirects to the actual mp3 and usually bypasses strict referrer checks.
    const audioUrl = `https://music.163.com/song/media/outer/url?id=${song.id}.mp3`;

    // 4. Find the timestamp
    let startTime = 0;
    const PLAY_DURATION = 10; // Play for 10 seconds

    if (lyricData.lrc?.lyric) {
      const parsedLyrics = parseLrc(lyricData.lrc.lyric);
      const normalizedTarget = normalize(targetLyric);

      // Fuzzy match: Find the line that contains the most significant part of our target lyric
      // We look for a substring match of the normalized texts
      const matchIndex = parsedLyrics.findIndex(line => {
        const normLine = normalize(line.text);
        return normLine.includes(normalizedTarget) || normalizedTarget.includes(normLine);
      });

      if (matchIndex !== -1) {
        startTime = parsedLyrics[matchIndex].time;
        // Start 1.5s before the line to catch the breath/intro of the phrase
        startTime = Math.max(0, startTime - 1.5);
      } else {
        console.warn('Lyric line not found in LRC, defaulting to 20% into the song');
        // If we can't find the exact line, start a bit into the song (e.g. 30s) hoping for chorus, 
        // or just start at 0. Let's try 0 to be safe, or maybe the chorus usually hits later.
        startTime = 0; 
      }
    }

    return {
      url: audioUrl,
      startTime: startTime,
      duration: PLAY_DURATION
    };

  } catch (error) {
    console.error("Music Service Error:", error);
    return null;
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { WordData, QuizResult } from '../types';
import { playSuccessSound, playErrorSound, playVictorySound, speakText } from '../services/audioService';
import { getSongSegment, SongPlayData } from '../services/musicService';
import toast from 'react-hot-toast';

interface QuizSessionProps {
  words: WordData[];
  onComplete: (results: QuizResult[]) => void;
  onUpdateWord: (id: string, updates: Partial<WordData>) => void;
  onExit: () => void;
}

type QuizMode = 'SPELL_FROM_DEF' | 'SPELL_FROM_AUDIO' | 'MEANING_FROM_WORD';

export const QuizSession: React.FC<QuizSessionProps> = ({ words, onComplete, onUpdateWord, onExit }) => {
  const [queue, setQueue] = useState<WordData[]>([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [input, setInput] = useState('');
  const [status, setStatus] = useState<'idle' | 'correct' | 'incorrect'>('idle');
  const [showHint, setShowHint] = useState(false);

  // New States for Mixed Mode
  const [quizMode, setQuizMode] = useState<QuizMode>('SPELL_FROM_DEF');
  const [choices, setChoices] = useState<WordData[]>([]);

  // Music State
  const [musicState, setMusicState] = useState<'idle' | 'loading' | 'playing' | 'error'>('idle');
  const audioRef = useRef<HTMLAudioElement | null>(null);

  // New State for Completion Screen
  const [isFinished, setIsFinished] = useState(false);

  const inputRef = useRef<HTMLInputElement>(null);
  const nextButtonRef = useRef<HTMLButtonElement>(null);
  const hasInitialized = useRef(false);

  // Cleanup speech and audio on unmount
  useEffect(() => {
    return () => {
      window.speechSynthesis?.cancel();
      stopMusic();
    };
  }, []);

  // Play Victory Sound when finished
  useEffect(() => {
    if (isFinished) {
      playVictorySound();
    }
  }, [isFinished]);

  // Initialize Queue
  useEffect(() => {
    if (!hasInitialized.current && words.length > 0) {
      const shuffled = [...words].sort(() => Math.random() - 0.5);
      setQueue(shuffled);
      hasInitialized.current = true;
      // Initialize first mode
      setupNewRound(shuffled[0], shuffled);
    }
  }, [words]);

  const currentWord = queue[currentIndex];

  const stopMusic = () => {
    if (audioRef.current) {
      audioRef.current.pause();
      audioRef.current = null;
    }
    setMusicState('idle');
  };

  // Logic to set up the mode and choices for a new word
  const setupNewRound = (word: WordData, allWords: WordData[]) => {
    const modes: QuizMode[] = ['SPELL_FROM_DEF', 'SPELL_FROM_AUDIO', 'MEANING_FROM_WORD'];
    const nextMode = modes[Math.floor(Math.random() * modes.length)];
    setQuizMode(nextMode);

    if (nextMode === 'MEANING_FROM_WORD') {
      // Generate distractors
      const distractors = allWords
        .filter(w => w.id !== word.id)
        .sort(() => 0.5 - Math.random())
        .slice(0, 3);
      const options = [word, ...distractors].sort(() => 0.5 - Math.random());
      setChoices(options);
    } else if (nextMode === 'SPELL_FROM_AUDIO') {
       // Auto play audio after a short delay
       setTimeout(() => speakText(word.word), 500);
    }
  };

  // Focus Logic
  useEffect(() => {
    const timer = setTimeout(() => {
      if (isFinished) return; // Don't focus if finished

      if (status === 'idle') {
        if (quizMode !== 'MEANING_FROM_WORD') {
          inputRef.current?.focus();
        }
      } else if (status === 'correct') {
        nextButtonRef.current?.focus();
      }
    }, 100);
    return () => clearTimeout(timer);
  }, [status, currentIndex, quizMode, isFinished]);

  const handleSpellingSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentWord || status !== 'idle') return;

    const cleanInput = input.trim().toLowerCase();
    const cleanTarget = currentWord.word.toLowerCase();

    if (cleanInput === cleanTarget) {
      handleCorrect();
    } else {
      handleIncorrect();
    }
  };

  const handleChoiceSelect = (selectedId: string) => {
    if (!currentWord || status !== 'idle') return;

    if (selectedId === currentWord.id) {
      handleCorrect();
    } else {
      handleIncorrect();
    }
  };

  const handleCorrect = async () => {
    setStatus('correct');
    playSuccessSound(); // Immediate feedback 'ding'

    // Speak the word immediately so user hears pronunciation
    speakText(currentWord.word);

    // Try to play the song
    if (currentWord.songInfo && currentWord.songLyric) {
      setMusicState('loading');
      try {
        const songData = await getSongSegment(currentWord.songInfo, currentWord.songLyric);

        if (songData) {
          stopMusic(); // Ensure previous is stopped

          const audio = new Audio(songData.url);
          audioRef.current = audio;
          audio.currentTime = songData.startTime;

          // Handle Loading Errors (e.g., 404, 403 on the mp3)
          audio.onerror = () => {
            console.warn("Audio playback error, falling back to TTS");
            setMusicState('error');
            fallbackTTS(currentWord);
          };

          // Play only when enough data
          audio.oncanplay = async () => {
            try {
              await audio.play();
              setMusicState('playing');

              // Stop after duration
              setTimeout(() => {
                if (audioRef.current === audio) {
                  // Simple fade out simulation
                  const fadeOut = setInterval(() => {
                     if (audio.volume > 0.1) {
                         audio.volume -= 0.1;
                     } else {
                         clearInterval(fadeOut);
                         audio.pause();
                         setMusicState('idle');
                     }
                  }, 200);
                }
              }, songData.duration * 1000);
            } catch (playError) {
              console.error("Play interrupted", playError);
              setMusicState('error');
              fallbackTTS(currentWord);
            }
          };

        } else {
          // Fallback if song not found
          console.log("Song not found, using TTS fallback");
          setMusicState('idle');
          fallbackTTS(currentWord);
        }
      } catch (e) {
        console.error("Playback failed logic", e);
        setMusicState('error');
        fallbackTTS(currentWord);
      }
    } else {
        // No song info, just normal behavior
    }

    const newCount = currentWord.correctCount + 1;
    onUpdateWord(currentWord.id, { 
      correctCount: newCount, 
      lastPracticed: new Date().toISOString() 
    });
  };

  const fallbackTTS = (word: WordData) => {
    // Wait a bit for the main word pronunciation to finish
    const speechText = `Like in the song ${word.songInfo}: ${word.songLyric}`;
    setTimeout(() => speakText(speechText, 0.95), 1000);
  };

  const handleIncorrect = () => {
    setStatus('incorrect');
    playErrorSound();

    setTimeout(() => {
      setStatus('idle');
      setInput('');
      setShowHint(true);
    }, 1000);
  };

  const handleNext = () => {
    stopMusic();

    if (currentIndex < queue.length - 1) {
      const nextIndex = currentIndex + 1;
      setCurrentIndex(nextIndex);
      setStatus('idle');
      setInput('');
      setShowHint(false);
      setupNewRound(queue[nextIndex], queue);
    } else {
      setIsFinished(true);
    }
  };

  if (isFinished) {
    return (
      <div className="w-full max-w-lg mx-auto flex flex-col h-full justify-center items-center p-4">
        <div className="bg-white shadow-xl rounded-2xl p-8 w-full text-center animate-fade-in-up flex flex-col items-center">
           <div className="w-24 h-24 bg-green-100 rounded-full flex items-center justify-center mb-6 text-green-500 shadow-sm animate-bounce">
             <svg xmlns="http://www.w3.org/2000/svg" width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M6 9H4.5a2.5 2.5 0 0 1 0-5H6"></path><path d="M18 9h1.5a2.5 2.5 0 0 0 0-5H18"></path><path d="M4 22h16"></path><path d="M10 14.66V17c0 .55-.47.98-.97 1.21C7.85 18.75 7 20.24 7 22"></path><path d="M14 14.66V17c0 .55.47.98.97 1.21C16.15 18.75 17 20.24 17 22"></path><path d="M18 2H6v7a6 6 0 0 0 12 0V2Z"></path></svg>
           </div>
           <h2 className="text-3xl font-bold text-slate-800 mb-2">周任务完成！</h2>
           <p className="text-slate-500 mb-8 text-lg">你已经成功掌握了所有的单词。</p>

           <button
             onClick={() => onComplete([])}
             className="w-full bg-indigo-600 text-white font-bold py-4 px-6 rounded-xl shadow-lg shadow-indigo-500/30 hover:bg-indigo-700 transition-all active:scale-95 flex items-center justify-center gap-2"
           >
             <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M3 9l9-7 9 7v11a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2z"></path><polyline points="9 22 9 12 15 12 15 22"></polyline></svg>
             回到主页
           </button>
        </div>
      </div>
    );
  }

  if (!currentWord) return <div className="p-8 text-center text-slate-500">准备中...</div>;

  const progress = ((currentIndex) / queue.length) * 100;

  // Helper to render the question part based on mode
  const renderQuestion = () => {
    switch (quizMode) {
      case 'SPELL_FROM_DEF':
        return (
          <div className="flex flex-col items-center animate-fade-in">
             <div className="text-xs font-bold text-indigo-500 uppercase tracking-wide bg-indigo-50 inline-block px-3 py-1 rounded-full mb-4">
               根据中文拼写
            </div>
            <p className="text-slate-700 text-xl sm:text-2xl font-medium leading-relaxed px-2 mb-2">
              {currentWord.definition}
            </p>
            <p className="text-slate-400 text-sm mb-6">{currentWord.partOfSpeech}</p>
          </div>
        );
      case 'SPELL_FROM_AUDIO':
        return (
          <div className="flex flex-col items-center animate-fade-in">
            <div className="text-xs font-bold text-pink-500 uppercase tracking-wide bg-pink-50 inline-block px-3 py-1 rounded-full mb-6">
               听音拼写
            </div>
            <button 
              type="button"
              onClick={() => speakText(currentWord.word)}
              className="w-24 h-24 rounded-full bg-indigo-100 text-indigo-600 flex items-center justify-center hover:bg-indigo-200 transition-all active:scale-95 mb-6"
            >
              <svg xmlns="http://www.w3.org/2000/svg" width="40" height="40" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polygon points="11 5 6 9 2 9 2 15 6 15 11 19 11 5"></polygon><path d="M19.07 4.93a10 10 0 0 1 0 14.14M15.54 8.46a5 5 0 0 1 0 7.07"></path></svg>
            </button>
            <p className="text-slate-400 text-sm mb-2">点击图标重播读音</p>
          </div>
        );
      case 'MEANING_FROM_WORD':
        return (
          <div className="flex flex-col items-center animate-fade-in mb-4">
             <div className="text-xs font-bold text-teal-500 uppercase tracking-wide bg-teal-50 inline-block px-3 py-1 rounded-full mb-4">
               英译中
            </div>
            <h2 className="text-3xl sm:text-4xl font-bold text-slate-800 mb-2">{currentWord.word}</h2>
            <p className="text-slate-400 text-sm">{currentWord.partOfSpeech}</p>
          </div>
        );
    }
  };

  return (
    <div className="w-full max-w-lg mx-auto flex flex-col gap-4">
      {/* Progress Bar */}
      <div className="bg-white/30 backdrop-blur-sm h-1.5 rounded-full overflow-hidden shrink-0 mx-1">
        <div 
          className="bg-indigo-500 h-full transition-all duration-500 ease-out"
          style={{ width: `${progress}%` }}
        ></div>
      </div>

      <div className="bg-white shadow-xl rounded-2xl overflow-hidden relative flex flex-col min-h-[400px]">
        {/* Card Header */}
        <div className="bg-indigo-600 px-6 py-4 flex justify-between items-center text-white shrink-0">
          <span className="font-semibold text-indigo-100 tracking-wider text-xs uppercase">单词 {currentIndex + 1} / {queue.length}</span>
          <button onClick={onExit} className="text-indigo-200 hover:text-white transition-colors p-1">
            <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>
          </button>
        </div>

        {/* Card Body */}
        <div className="p-6 sm:p-10 flex flex-col items-center text-center flex-1">

          {status === 'correct' ? (
            <div className="animate-fade-in flex flex-col items-center w-full gap-6">
              <div className="flex flex-col items-center gap-1 sm:gap-2">
                <div className="text-xl sm:text-2xl font-bold text-green-500 flex items-center gap-2">
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7"></path></svg>
                  回答正确!
                </div>
                <div className="text-3xl sm:text-4xl text-slate-800 font-bold capitalize">{currentWord.word}</div>
                <div className="text-slate-500 text-sm mb-2">{currentWord.definition}</div>

                {currentWord.songInfo && currentWord.songLyric && (
                  <div className={`bg-amber-50 border border-amber-200 rounded-lg p-3 w-full max-w-sm transition-all duration-500 relative overflow-hidden ${musicState === 'playing' ? 'shadow-lg shadow-amber-100 scale-105 ring-2 ring-amber-300' : ''}`}>
                    <div className="flex items-center gap-2 text-amber-600 text-xs font-bold uppercase mb-1 relative z-10">
                      {musicState === 'loading' ? (
                         <span className="flex gap-1 items-center animate-pulse">
                           <svg className="animate-spin h-3 w-3 text-amber-600" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                              <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                              <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                            </svg>
                           Loading Song...
                         </span>
                      ) : musicState === 'playing' ? (
                        <span className="flex gap-1 items-center">
                          <span className="flex h-3 w-3 relative">
                            <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-amber-400 opacity-75"></span>
                            <span className="relative inline-flex rounded-full h-3 w-3 bg-amber-500"></span>
                          </span>
                          Playing
                        </span>
                      ) : (
                        <span className="flex gap-1 items-center">
                           <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M9 18V5l12-2v13"></path><circle cx="6" cy="18" r="3"></circle><circle cx="18" cy="16" r="3"></circle></svg>
                           {currentWord.songInfo}
                        </span>
                      )}
                    </div>
                    <p className="text-slate-700 italic font-medium transition-colors duration-300 relative z-10">
                      "{currentWord.songLyric}"
                    </p>

                    {/* Background Progress Bar for Music */}
                    {musicState === 'playing' && (
                       <div className="absolute bottom-0 left-0 h-1 bg-amber-200/50 w-full animate-progress origin-left"></div>
                    )}
                  </div>
                )}
              </div>

              <div className="w-full flex items-center justify-center">
                <div className="w-full max-w-[280px] aspect-square rounded-xl overflow-hidden shadow-md border border-slate-100 bg-slate-50 flex items-center justify-center relative">
                  {currentWord.imageUrl ? (
                    <img 
                      src={currentWord.imageUrl} 
                      alt={currentWord.word} 
                      className="w-full h-full object-contain animate-fade-in bg-white" 
                    />
                  ) : (
                    <div className="text-slate-400 flex flex-col items-center p-4">
                        <span className="text-xs">暂无图片</span>
                    </div>
                  )}
                </div>
              </div>

              <button
                ref={nextButtonRef}
                onClick={handleNext}
                className="w-full bg-indigo-600 text-white font-bold py-3.5 px-6 rounded-xl shadow-lg shadow-indigo-500/30 active:scale-95 transition-all hover:bg-indigo-700 flex items-center justify-center gap-2 mb-2"
              >
                {currentIndex < queue.length - 1 ? (
                  <>
                    下一个单词
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 7l5 5m0 0l-5 5m5-5H6"></path></svg>
                  </>
                ) : (
                  <>
                    完成练习
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7"></path></svg>
                  </>
                )}
              </button>
            </div>
          ) : (
            <div className="flex flex-col w-full flex-1">
              <div className="flex-1 flex flex-col justify-center items-center mb-6 space-y-4 min-h-[120px]">
                {renderQuestion()}
              </div>

              {quizMode === 'MEANING_FROM_WORD' ? (
                <div className="w-full flex flex-col gap-3">
                  {choices.map((choice) => (
                    <button
                      key={choice.id}
                      onClick={() => handleChoiceSelect(choice.id)}
                      className={`w-full p-4 rounded-xl border-2 text-left transition-all active:scale-[0.98]
                        ${status === 'incorrect' 
                          ? 'border-slate-100 bg-slate-50 text-slate-400' 
                          : 'border-slate-200 bg-white hover:border-indigo-300 hover:bg-indigo-50 text-slate-700'
                        }`}
                    >
                       {choice.definition}
                    </button>
                  ))}
                  {status === 'incorrect' && (
                     <div className="text-center text-red-500 mt-2 font-medium animate-shake">
                       选择错误，请重试
                     </div>
                  )}
                </div>
              ) : (
                <form onSubmit={handleSpellingSubmit} className="w-full relative shrink-0 mb-4">
                  <div className={`relative transition-transform duration-300 ${status === 'incorrect' ? 'animate-shake' : ''}`}>
                    <input
                      ref={inputRef}
                      type="text"
                      value={input}
                      onChange={(e) => setInput(e.target.value)}
                      placeholder="输入单词..."
                      className={`w-full text-center text-2xl sm:text-3xl font-bold py-3 sm:py-4 bg-transparent border-b-2 sm:border-b-4 focus:outline-none transition-colors rounded-none
                        ${status === 'incorrect' ? 'border-red-500 text-red-500' : 
                        'border-slate-200 focus:border-indigo-500 text-slate-800'}`}
                      autoComplete="off"
                      autoCorrect="off"
                      autoCapitalize="off"
                      spellCheck="false"
                    />
                  </div>

                  {showHint && status === 'idle' && (
                    <div className="mt-3 text-sm text-slate-400 animate-fade-in">
                      提示: 首字母是 <span className="font-bold text-slate-600">{currentWord.word.substring(0, 1).toUpperCase()}</span>
                    </div>
                  )}
                </form>
              )}
            </div>
          )}
        </div>
      </div>
      <div className="h-4 sm:h-0"></div>
    </div>
  );
};

import { GoogleGenAI, Type } from "@google/genai";
import { WordData } from '../types';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateWordImage = async (word: string): Promise<string | null> => {
  try {
    // Improved prompt: simple, vector, white background
    const prompt = `A simple, bold, minimalist vector illustration of the English word "${word}". 
    The image should be a direct, literal representation suitable for a vocabulary flashcard.
    Single central subject on a pure white background. 
    Flat design, no text, no abstract concepts.`;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          { text: prompt },
        ],
      },
      config: {
        imageConfig: {
          aspectRatio: "1:1"
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (error) {
    console.error("Image Gen Error:", error);
    return null;
  }
};

export const enrichVocabulary = async (words: string[]): Promise<WordData[]> => {
  if (words.length === 0) return [];

  const prompt = `
    I have a list of English vocabulary words for a student. 
    Please process these words and provide:
    1. A concise definition in Simplified Chinese (中文).
    2. Part of speech.
    3. A "cloze" example sentence in English (word replaced by '_______').
    4. A VERY POPULAR song lyric that contains this word (in English). 
       - It MUST be from a very famous song (Taylor Swift, Adele, Beatles, Queen, Disney, Top 40 hits) so it is easy to find in a music database.
       - Do not pick obscure songs.
    5. The Artist and Song Name for that lyric.

    The words are: ${words.join(', ')}.

    Return the data in a strict JSON structure.
  `;

  try {
    // 1. Get Text Data
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              word: { type: Type.STRING, description: "The vocabulary word (lowercase)" },
              definition: { type: Type.STRING, description: "Definition in Simplified Chinese" },
              partOfSpeech: { type: Type.STRING, description: "e.g., noun, verb, adjective" },
              exampleSentence: { type: Type.STRING, description: "A sentence using the word, but the word itself is replaced with _______" },
              songLyric: { type: Type.STRING, description: "A line from a famous song containing the word" },
              songInfo: { type: Type.STRING, description: "Artist - Song Name" }
            },
            required: ["word", "definition", "partOfSpeech", "exampleSentence"]
          }
        }
      }
    });

    const rawData = JSON.parse(response.text || '[]');

    // 2. Map to internal structure
    const processedWords: WordData[] = rawData.map((item: any) => ({
      id: crypto.randomUUID(),
      word: item.word.toLowerCase().trim(),
      definition: item.definition,
      exampleSentence: item.exampleSentence,
      partOfSpeech: item.partOfSpeech,
      songLyric: item.songLyric,
      songInfo: item.songInfo,
      correctCount: 0,
      imageUrl: undefined // Will be filled below
    }));

    // 3. Pre-generate images for ALL words immediately
    await Promise.all(processedWords.map(async (word) => {
        try {
            const imageUrl = await generateWordImage(word.word);
            if (imageUrl) {
                word.imageUrl = imageUrl;
            }
        } catch (imgError) {
            console.warn(`Failed to generate image for ${word.word}`, imgError);
        }
    }));

    return processedWords;

  } catch (error) {
    console.error("Gemini API Error:", error);
    throw new Error("Failed to enrich vocabulary.");
  }
};

// Using a common public Vercel deployment of the Netease API.
const API_BASE_URL = 'https://netease-cloud-music-api-brilliance.vercel.app';

interface SongSearchResult {
  result?: {
    songs?: {
      id: number;
      name: string;
      ar: { name: string }[];
      pop: number; // Popularity score
      fee: number; // 0: free, 1: VIP, 8: SQ
    }[];
  };
}

interface LyricResult {
  lrc?: {
    lyric: string;
  };
}

interface CheckMusicResult {
  success: boolean;
  message: string;
}

export interface SongPlayData {
  url: string;
  startTime: number;
  duration: number;
}

// Helper to normalize text for fuzzy matching (remove punctuation, lowercase, extra spaces)
const normalize = (text: string) => {
  return text.toLowerCase()
    .replace(/['".,/#!$%^&*;:{}=\-_`~()]/g, "") // Remove punctuation
    .replace(/\s+/g, " ") // Collapse spaces
    .trim();
};

const parseLrc = (lrc: string): { time: number; text: string }[] => {
  const lines = lrc.split('\n');
  const result: { time: number; text: string }[] = [];
  // Regex to match [mm:ss.xx] or [mm:ss.xxx]
  const timeRegex = /\[(\d{2}):(\d{2})\.(\d{2,3})\]/;

  for (const line of lines) {
    const match = timeRegex.exec(line);
    if (match) {
      const minutes = parseInt(match[1], 10);
      const seconds = parseInt(match[2], 10);
      const milliseconds = parseInt(match[3], 10);
      // Convert to seconds
      const time = minutes * 60 + seconds + milliseconds / 1000;
      const text = line.replace(/\[.*?\]/g, '').trim(); // Remove all timestamps from line
      if (text) {
        result.push({ time, text });
      }
    }
  }
  return result;
};

export const getSongSegment = async (searchQuery: string, targetLyric: string): Promise<SongPlayData | null> => {
  try {
    // 1. Search for the song
    // We search using the info provided by Gemini (Artist + Song Name)
    const searchRes = await fetch(`${API_BASE_URL}/cloudsearch?keywords=${encodeURIComponent(searchQuery)}&limit=6`);
    if (!searchRes.ok) throw new Error('Search failed');
    const searchData: SongSearchResult = await searchRes.json();

    const songs = searchData.result?.songs || [];
    if (songs.length === 0) return null;

    // 2. Iterate through songs to find a playable one
    // Strategy: Try the top results. If the first one (usually original) is blocked/VIP, try the next (covers/remixes).
    for (const song of songs) {
      try {
        // A. Check Availability
        // This endpoint checks if the song is playable (copyright, VIP restrictions)
        const checkRes = await fetch(`${API_BASE_URL}/check/music?id=${song.id}`);
        const checkData: CheckMusicResult = await checkRes.json();

        if (!checkData.success) {
          console.log(`Song ${song.name} (ID: ${song.id}) is not available/VIP, skipping...`);
          continue; // Skip to next song
        }

        // B. Get Lyrics for THIS specific song version
        // IMPORTANT: Different versions (covers) have different timings, so we must fetch lyrics for the specific ID.
        const lyricRes = await fetch(`${API_BASE_URL}/lyric?id=${song.id}`);
        if (!lyricRes.ok) continue;
        const lyricData: LyricResult = await lyricRes.json();

        if (!lyricData.lrc?.lyric) {
           console.log(`Song ${song.name} (ID: ${song.id}) has no lyrics, skipping...`);
           continue;
        }

        // C. Match Timestamp
        const parsedLyrics = parseLrc(lyricData.lrc.lyric);
        const normalizedTarget = normalize(targetLyric);

        // Fuzzy match logic
        const matchIndex = parsedLyrics.findIndex(line => {
          const normLine = normalize(line.text);
          // Check inclusion both ways to handle slight variations or partial lines
          return normLine.length > 5 && (normLine.includes(normalizedTarget) || normalizedTarget.includes(normLine));
        });

        let startTime = 0;
        const PLAY_DURATION = 10;

        if (matchIndex !== -1) {
          startTime = parsedLyrics[matchIndex].time;
          // Start 1.5s before the line
          startTime = Math.max(0, startTime - 1.5);

          // SUCCESS: We found a playable song AND matched the lyrics
          const audioUrl = `https://music.163.com/song/media/outer/url?id=${song.id}.mp3`;

          console.log(`Found playable match: ${song.name} by ${song.ar[0].name}`);

          return {
            url: audioUrl,
            startTime: startTime,
            duration: PLAY_DURATION
          };
        } else {
           console.log(`Song ${song.name} (ID: ${song.id}) lyrics did not match target line, skipping...`);
        }
      } catch (innerError) {
        console.warn(`Error checking song ${song.id}`, innerError);
        continue;
      }
    }

    // If loop finishes and no match found
    console.warn("No playable song found with matching lyrics in top results.");
    return null;

  } catch (error) {
    console.error("Music Service Error:", error);
    return null;
  }
};

import React, { useState, useEffect } from 'react';
import { WordInput } from './components/WordInput';
import { QuizSession } from './components/QuizSession';
import { Dashboard } from './components/Dashboard';
import { WordData, AppState } from './types';
import { enrichVocabulary } from './services/geminiService';
import { Toaster, toast } from 'react-hot-toast';

const STORAGE_KEY = 'lexiweek_data_v1';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.DASHBOARD);
  const [words, setWords] = useState<WordData[]>([]);
  const [loading, setLoading] = useState(false);

  // Load from local storage on mount
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setWords(parsed);
        if (parsed.length === 0) {
          setAppState(AppState.INPUT);
        }
      } catch (e) {
        console.error("Failed to parse saved data", e);
        setAppState(AppState.INPUT);
      }
    } else {
      setAppState(AppState.INPUT);
    }
  }, []);

  // Save to local storage whenever words change
  useEffect(() => {
    try {
      // CRITICAL FIX: Do not save 'imageUrl' to local storage. 
      // Base64 images are too large and cause QuotaExceededError.
      // We only save the text data. Images will be lost on refresh, which is an acceptable trade-off for stability.
      const dataToSave = words.map(w => {
        // eslint-disable-next-line @typescript-eslint/no-unused-vars
        const { imageUrl, ...rest } = w;
        return rest;
      });
      localStorage.setItem(STORAGE_KEY, JSON.stringify(dataToSave));
    } catch (e) {
      console.error("Storage error:", e);
      if (e instanceof DOMException && (e.name === 'QuotaExceededError' || e.name === 'NS_ERROR_DOM_QUOTA_REACHED')) {
         toast.error("存储空间不足，部分数据可能无法保存", { id: 'quota-error' });
      }
    }
  }, [words]);

  const handleWordsSubmit = async (rawWords: string[]) => {
    setLoading(true);
    try {
      const enrichedWords = await enrichVocabulary(rawWords);
      setWords(enrichedWords);
      setAppState(AppState.DASHBOARD);
      toast.success('词库已创建！');
    } catch (error) {
      console.error(error);
      toast.error('处理单词失败，请重试。');
    } finally {
      setLoading(false);
    }
  };

  const handleResetWeek = () => {
    if (window.confirm("确定要重置吗？这将删除当前的进度并开始新的一周。")) {
      setWords([]);
      setAppState(AppState.INPUT);
      localStorage.removeItem(STORAGE_KEY);
    }
  };

  const handleUpdateWord = (wordId: string, updates: Partial<WordData>) => {
    setWords(prev => prev.map(w => {
      if (w.id !== wordId) return w;
      return { ...w, ...updates };
    }));
  };

  return (
    // Changed min-h-screen to ensure scrolling works when content overflows (like when keyboard is open)
    <div className="min-h-screen w-full bg-slate-50 relative">
      {/* 
        PERFORMANCE FIX: 
        Replaced heavy animated blobs (filter blur + animation loop) with a static CSS gradient mesh.
        This prevents crashes on mobile devices when the keyboard opens/closes (which triggers repaints).
      */}
      <div className="fixed inset-0 z-0 bg-gradient-to-br from-indigo-50 via-purple-50 to-pink-50 opacity-80 pointer-events-none"></div>
      <div className="fixed top-0 left-0 w-full h-1 bg-gradient-to-r from-indigo-500 via-purple-500 to-pink-500 z-50"></div>

      {/* Content Container - Allows scrolling */}
      <main className="relative z-10 w-full max-w-4xl mx-auto p-4 sm:p-6 lg:p-8 flex flex-col min-h-screen justify-center">
        {appState === AppState.INPUT && (
          <WordInput 
            onSubmit={handleWordsSubmit} 
            isLoading={loading} 
            hasExistingData={words.length > 0}
            onCancel={words.length > 0 ? () => setAppState(AppState.DASHBOARD) : undefined}
          />
        )}

        {appState === AppState.DASHBOARD && (
          <Dashboard 
            words={words} 
            onStartQuiz={() => setAppState(AppState.QUIZ)}
            onNewWeek={handleResetWeek}
          />
        )}

        {appState === AppState.QUIZ && (
          <QuizSession 
            words={words}
            onComplete={(results) => {
              setAppState(AppState.DASHBOARD);
            }}
            onUpdateWord={handleUpdateWord}
            onExit={() => setAppState(AppState.DASHBOARD)}
          />
        )}
      </main>

      <Toaster position="bottom-center" />
    </div>
  );
};

export default App;

// Providers
const QQ_API_BASE = 'https://api.qq.jsososo.com';
const NETEASE_API_BASE = 'https://netease-cloud-music-api-brilliance.vercel.app';

export interface SongPlayData {
  url: string;
  startTime: number;
  duration: number;
  provider: 'qq' | 'netease';
}

// Helper: Normalize text
const normalize = (text: string) => {
  return text.toLowerCase()
    .replace(/['".,/#!$%^&*;:{}=\-_`~()]/g, "")
    .replace(/\s+/g, " ")
    .trim();
};

// Helper: Parse Lyrics
const parseLrc = (lrc: string): { time: number; text: string }[] => {
  if (!lrc) return [];
  const lines = lrc.split('\n');
  const result: { time: number; text: string }[] = [];
  const timeRegex = /\[(\d{2}):(\d{2})\.(\d{2,3})\]/;

  for (const line of lines) {
    const match = timeRegex.exec(line);
    if (match) {
      const minutes = parseInt(match[1], 10);
      const seconds = parseInt(match[2], 10);
      const milliseconds = parseInt(match[3], 10);
      const time = minutes * 60 + seconds + milliseconds / 1000;
      const text = line.replace(/\[.*?\]/g, '').trim();
      if (text) {
        result.push({ time, text });
      }
    }
  }
  return result;
};

// Helper: Check lyric match
const findLyricMatch = (lrcContent: string, targetLyric: string) => {
  const parsedLyrics = parseLrc(lrcContent);
  const normalizedTarget = normalize(targetLyric);

  const matchIndex = parsedLyrics.findIndex(line => {
    const normLine = normalize(line.text);
    // Increased strictness: Line must be reasonably long or exact match to avoid false positives on short words
    if (normLine.length < 3) return false;
    return normLine.includes(normalizedTarget) || (normalizedTarget.length > 5 && normalizedTarget.includes(normLine));
  });

  if (matchIndex !== -1) {
    let startTime = parsedLyrics[matchIndex].time;
    startTime = Math.max(0, startTime - 1.5); // Start slightly before
    return startTime;
  }
  return null;
};

// --- QQ MUSIC IMPLEMENTATION ---
const searchQQ = async (query: string, targetLyric: string): Promise<SongPlayData | null> => {
  try {
    // 1. Search
    const searchRes = await fetch(`${QQ_API_BASE}/search?key=${encodeURIComponent(query)}&pageSize=5`);
    const searchData = await searchRes.json();
    const songs = searchData?.data?.list || [];

    for (const song of songs) {
      try {
        const songmid = song.songmid;

        // 2. Get Lyrics
        const lyricRes = await fetch(`${QQ_API_BASE}/lyric?songmid=${songmid}`);
        const lyricData = await lyricRes.json();
        const lrc = lyricData?.data?.lyric;

        if (!lrc) continue;

        const startTime = findLyricMatch(lrc, targetLyric);
        if (startTime === null) continue;

        // 3. Get Playable URL
        const urlRes = await fetch(`${QQ_API_BASE}/song/urls?id=${songmid}`);
        const urlData = await urlRes.json();
        const audioUrl = urlData?.data?.[songmid];

        if (audioUrl) {
           console.log(`[QQ] Found match: ${song.songname}`);
           return {
             url: audioUrl,
             startTime,
             duration: 10,
             provider: 'qq'
           };
        }
      } catch (e) {
        console.warn("[QQ] Error processing song", e);
      }
    }
  } catch (e) {
    console.warn("[QQ] Search failed", e);
  }
  return null;
};

// --- NETEASE IMPLEMENTATION ---
const searchNetease = async (query: string, targetLyric: string): Promise<SongPlayData | null> => {
  try {
    // 1. Search
    const searchRes = await fetch(`${NETEASE_API_BASE}/cloudsearch?keywords=${encodeURIComponent(query)}&limit=5`);
    const searchData = await searchRes.json();
    const songs = searchData.result?.songs || [];

    for (const song of songs) {
      try {
        // 2. Get Lyrics
        const lyricRes = await fetch(`${NETEASE_API_BASE}/lyric?id=${song.id}`);
        const lyricData = await lyricRes.json();
        const lrc = lyricData?.lrc?.lyric;

        if (!lrc) continue;

        const startTime = findLyricMatch(lrc, targetLyric);
        if (startTime === null) continue;

        // 3. Construct URL (Using Outer Link Hack as fallback, but checking availability slightly via try/catch in playback)
        // We skip the explicit check/music call to be faster and more aggressive, relying on the 'outer' link.
        const audioUrl = `https://music.163.com/song/media/outer/url?id=${song.id}.mp3`;

        console.log(`[Netease] Found match: ${song.name}`);
        return {
          url: audioUrl,
          startTime,
          duration: 10,
          provider: 'netease'
        };
      } catch (e) {
        console.warn("[Netease] Error processing song", e);
      }
    }
  } catch (e) {
    console.warn("[Netease] Search failed", e);
  }
  return null;
};

// --- MAIN EXPORT ---
export const getSongSegment = async (searchQuery: string, targetLyric: string): Promise<SongPlayData | null> => {
  // Strategy: Try QQ Music first (as requested), then fall back to Netease.

  console.log(`Searching for: ${searchQuery} ...`);

  // 1. Try QQ Music
  const qqResult = await searchQQ(searchQuery, targetLyric);
  if (qqResult) return qqResult;

  // 2. Try Netease
  console.log("QQ failed, trying Netease...");
  const neteaseResult = await searchNetease(searchQuery, targetLyric);
  if (neteaseResult) return neteaseResult;

  return null;
};

import React, { useState, useEffect, useRef } from 'react';
import { WordData, QuizResult } from '../types';
import { playSuccessSound, playErrorSound, playVictorySound, speakText } from '../services/audioService';
import { getSongSegment, SongPlayData } from '../services/musicService';
import toast from 'react-hot-toast';

interface QuizSessionProps {
  words: WordData[];
  onComplete: (results: QuizResult[]) => void;
  onUpdateWord: (id: string, updates: Partial<WordData>) => void;
  onExit: () => void;
}

type QuizMode = 'SPELL_FROM_DEF' | 'SPELL_FROM_AUDIO' | 'MEANING_FROM_WORD';

export const QuizSession: React.FC<QuizSessionProps> = ({ words, onComplete, onUpdateWord, onExit }) => {
  const [queue, setQueue] = useState<WordData[]>([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [input, setInput] = useState('');
  const [status, setStatus] = useState<'idle' | 'correct' | 'incorrect'>('idle');
  const [showHint, setShowHint] = useState(false);

  // New States for Mixed Mode
  const [quizMode, setQuizMode] = useState<QuizMode>('SPELL_FROM_DEF');
  const [choices, setChoices] = useState<WordData[]>([]);

  // Music State
  const [musicState, setMusicState] = useState<'idle' | 'loading' | 'playing' | 'error'>('idle');
  const audioRef = useRef<HTMLAudioElement | null>(null);

  const [isFinished, setIsFinished] = useState(false);

  const inputRef = useRef<HTMLInputElement>(null);
  const nextButtonRef = useRef<HTMLButtonElement>(null);
  const hasInitialized = useRef(false);

  // Cleanup
  useEffect(() => {
    return () => {
      window.speechSynthesis?.cancel();
      stopMusic();
    };
  }, []);

  useEffect(() => {
    if (isFinished) {
      playVictorySound();
    }
  }, [isFinished]);

  useEffect(() => {
    if (!hasInitialized.current && words.length > 0) {
      const shuffled = [...words].sort(() => Math.random() - 0.5);
      setQueue(shuffled);
      hasInitialized.current = true;
      setupNewRound(shuffled[0], shuffled);
    }
  }, [words]);

  const currentWord = queue[currentIndex];

  const stopMusic = () => {
    if (audioRef.current) {
      audioRef.current.pause();
      audioRef.current.removeAttribute('src'); // Fully detach
      audioRef.current.load();
      audioRef.current = null;
    }
    setMusicState('idle');
  };

  const setupNewRound = (word: WordData, allWords: WordData[]) => {
    const modes: QuizMode[] = ['SPELL_FROM_DEF', 'SPELL_FROM_AUDIO', 'MEANING_FROM_WORD'];
    const nextMode = modes[Math.floor(Math.random() * modes.length)];
    setQuizMode(nextMode);

    if (nextMode === 'MEANING_FROM_WORD') {
      const distractors = allWords
        .filter(w => w.id !== word.id)
        .sort(() => 0.5 - Math.random())
        .slice(0, 3);
      const options = [word, ...distractors].sort(() => 0.5 - Math.random());
      setChoices(options);
    } else if (nextMode === 'SPELL_FROM_AUDIO') {
       setTimeout(() => speakText(word.word), 500);
    }
  };

  // Focus Logic
  useEffect(() => {
    const timer = setTimeout(() => {
      if (isFinished) return;
      if (status === 'idle') {
        if (quizMode !== 'MEANING_FROM_WORD') {
          inputRef.current?.focus();
        }
      } else if (status === 'correct') {
        nextButtonRef.current?.focus();
      }
    }, 100);
    return () => clearTimeout(timer);
  }, [status, currentIndex, quizMode, isFinished]);

  const handleSpellingSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentWord || status !== 'idle') return;
    const cleanInput = input.trim().toLowerCase();
    const cleanTarget = currentWord.word.toLowerCase();
    if (cleanInput === cleanTarget) {
      handleCorrect();
    } else {
      handleIncorrect();
    }
  };

  const handleChoiceSelect = (selectedId: string) => {
    if (!currentWord || status !== 'idle') return;
    if (selectedId === currentWord.id) {
      handleCorrect();
    } else {
      handleIncorrect();
    }
  };

  const handleCorrect = async () => {
    setStatus('correct');
    playSuccessSound();
    speakText(currentWord.word);

    // Song Playback Logic
    if (currentWord.songInfo && currentWord.songLyric) {
      setMusicState('loading');
      try {
        const songData = await getSongSegment(currentWord.songInfo, currentWord.songLyric);

        if (songData) {
          stopMusic();

          const audio = new Audio();
          // Important: Set CORS to allow playback from other domains
          audio.crossOrigin = "anonymous"; 
          audio.src = songData.url;
          audioRef.current = audio;

          // Event: Metadata Loaded (Duration available) - Set Start Time Here
          audio.onloadedmetadata = () => {
             audio.currentTime = songData.startTime;
          };

          // Event: Ready to play
          audio.oncanplay = async () => {
            // Check if we are still on the same word and state
            if (audioRef.current !== audio) return;

            try {
              await audio.play();
              setMusicState('playing');

              // Stop after duration
              setTimeout(() => {
                if (audioRef.current === audio) {
                  // Fade out
                  const fadeOut = setInterval(() => {
                     if (audio.volume > 0.1) {
                         audio.volume -= 0.1;
                     } else {
                         clearInterval(fadeOut);
                         audio.pause();
                         setMusicState('idle');
                     }
                  }, 200);
                }
              }, songData.duration * 1000);
            } catch (playError) {
              console.warn("Autoplay blocked or failed", playError);
              setMusicState('error');
              fallbackTTS(currentWord);
            }
          };

          audio.onerror = (e) => {
            console.error("Audio Load Error", e);
            setMusicState('error');
            fallbackTTS(currentWord);
          };

        } else {
          console.log("No song found");
          setMusicState('idle');
          fallbackTTS(currentWord);
        }
      } catch (e) {
        console.error("Music fetch error", e);
        setMusicState('error');
        fallbackTTS(currentWord);
      }
    }

    const newCount = currentWord.correctCount + 1;
    onUpdateWord(currentWord.id, { 
      correctCount: newCount, 
      lastPracticed: new Date().toISOString() 
    });
  };

  const fallbackTTS = (word: WordData) => {
    const speechText = `Like in the song ${word.songInfo}: ${word.songLyric}`;
    setTimeout(() => speakText(speechText, 0.95), 1000);
  };

  const handleIncorrect = () => {
    setStatus('incorrect');
    playErrorSound();
    setTimeout(() => {
      setStatus('idle');
      setInput('');
      setShowHint(true);
    }, 1000);
  };

  const handleNext = () => {
    stopMusic();
    if (currentIndex < queue.length - 1) {
      const nextIndex = currentIndex + 1;
      setCurrentIndex(nextIndex);
      setStatus('idle');
      setInput('');
      setShowHint(false);
      setupNewRound(queue[nextIndex], queue);
    } else {
      setIsFinished(true);
    }
  };

  if (isFinished) {
    return (
      <div className="w-full max-w-lg mx-auto flex flex-col h-full justify-center items-center p-4">
