// API Base
// Using a stable Vercel deployment of the Netease API
const API_BASE_URL = 'https://netease-cloud-music-api-brilliance.vercel.app';

export interface SongPlayData {
  url: string;
  startTime: number;
  duration: number;
  name: string;
  artist: string;
}

// Helper: Normalize text
const normalize = (text: string) => {
  return text.toLowerCase()
    .replace(/['".,/#!$%^&*;:{}=\-_`~()]/g, "")
    .replace(/\s+/g, " ")
    .trim();
};

// Helper: Parse Lyrics
const parseLrc = (lrc: string): { time: number; text: string }[] => {
  if (!lrc) return [];
  const lines = lrc.split('\n');
  const result: { time: number; text: string }[] = [];
  const timeRegex = /\[(\d{2}):(\d{2})\.(\d{2,3})\]/;

  for (const line of lines) {
    const match = timeRegex.exec(line);
    if (match) {
      const minutes = parseInt(match[1], 10);
      const seconds = parseInt(match[2], 10);
      const milliseconds = parseInt(match[3], 10);
      const time = minutes * 60 + seconds + milliseconds / 1000;
      const text = line.replace(/\[.*?\]/g, '').trim();
      if (text) {
        result.push({ time, text });
      }
    }
  }
  return result;
};

// Helper: Check lyric match
const findLyricMatch = (lrcContent: string, targetLyric: string) => {
  const parsedLyrics = parseLrc(lrcContent);
  const normalizedTarget = normalize(targetLyric);

  const matchIndex = parsedLyrics.findIndex(line => {
    const normLine = normalize(line.text);
    // Strictness check: length > 4 to avoid matching "Yeah", "Oh"
    if (normLine.length < 4) return false;
    return normLine.includes(normalizedTarget) || (normalizedTarget.length > 5 && normalizedTarget.includes(normLine));
  });

  if (matchIndex !== -1) {
    let startTime = parsedLyrics[matchIndex].time;
    startTime = Math.max(0, startTime - 2.0); // Start 2 seconds before
    return startTime;
  }
  return null;
};

export const getSongSegment = async (searchQuery: string, targetLyric: string): Promise<SongPlayData | null> => {
  console.log(`Searching Netease for: ${searchQuery}`);

  try {
    // 1. Search
    // Type 1 = Single Song
    const searchRes = await fetch(`${API_BASE_URL}/cloudsearch?keywords=${encodeURIComponent(searchQuery)}&limit=15&type=1`);
    if (!searchRes.ok) throw new Error("Network response was not ok");

    const searchData = await searchRes.json();
    const songs = searchData.result?.songs || [];

    if (songs.length === 0) return null;

    // 2. Iterate and Filter
    // We prioritize songs that are likely free.
    // Netease 'fee' field: 0 = Free, 8 = Free (sometimes low quality), 1 = VIP, 4 = Paid Album
    // We will iterate through ALL songs. If we find a match in a 'fee:0' song, we take it immediately.
    // If we only find matches in fee:1, we keep looking, but maybe store it as a fallback?
    // Actually, for this app, we ONLY want playable songs. So we skip VIP if possible.

    // Sort songs: Free (0) > LowQ Free (8) > VIP (1)
    const sortedSongs = songs.sort((a: any, b: any) => {
      const getScore = (fee: number) => {
        if (fee === 0) return 0;
        if (fee === 8) return 1;
        return 2; // VIP or other
      };
      return getScore(a.fee) - getScore(b.fee);
    });

    for (const song of sortedSongs) {
      try {
        // Skip strictly paid songs if possible, but sometimes fee=1 works for previews? 
        // We will trust the 'check/music' or just try the outer link. 
        // The outer link usually fails for VIP.
        // Let's rely on the lyric match first.

        // Fetch Lyric
        const lyricRes = await fetch(`${API_BASE_URL}/lyric?id=${song.id}`);
        const lyricData = await lyricRes.json();
        const lrc = lyricData?.lrc?.lyric;

        if (!lrc) continue;

        const startTime = findLyricMatch(lrc, targetLyric);
        if (startTime === null) continue;

        // If we have a match, let's verify availability if it's marked as VIP
        let isPlayable = true;
        if (song.fee === 1 || song.fee === 4) {
           const checkRes = await fetch(`${API_BASE_URL}/check/music?id=${song.id}`);
           const checkData = await checkRes.json();
           if (!checkData.success) {
             isPlayable = false;
           }
        }

        if (isPlayable) {
          console.log(`Match found: ${song.name} (Fee: ${song.fee})`);
          // Use the standard outer link. 
          // Note: This relies on the <meta name="referrer" content="no-referrer" /> in index.html
          const audioUrl = `https://music.163.com/song/media/outer/url?id=${song.id}.mp3`;

          return {
            url: audioUrl,
            startTime,
            duration: 12, // Play a bit longer to be safe
            name: song.name,
            artist: song.ar?.[0]?.name || 'Unknown'
          };
        }
      } catch (innerE) {
        console.warn(`Error checking song ${song.id}`, innerE);
      }
    }

  } catch (e) {
    console.error("Netease search error", e);
  }

  return null;
};

import React, { useState, useEffect, useRef } from 'react';
import { WordData, QuizResult } from '../types';
import { playSuccessSound, playErrorSound, playVictorySound, speakText } from '../services/audioService';
import { getSongSegment, SongPlayData } from '../services/musicService';
import toast from 'react-hot-toast';

interface QuizSessionProps {
  words: WordData[];
  onComplete: (results: QuizResult[]) => void;
  onUpdateWord: (id: string, updates: Partial<WordData>) => void;
  onExit: () => void;
}

type QuizMode = 'SPELL_FROM_DEF' | 'SPELL_FROM_AUDIO' | 'MEANING_FROM_WORD';

export const QuizSession: React.FC<QuizSessionProps> = ({ words, onComplete, onUpdateWord, onExit }) => {
  const [queue, setQueue] = useState<WordData[]>([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [input, setInput] = useState('');
  const [status, setStatus] = useState<'idle' | 'correct' | 'incorrect'>('idle');
  const [showHint, setShowHint] = useState(false);

  // New States for Mixed Mode
  const [quizMode, setQuizMode] = useState<QuizMode>('SPELL_FROM_DEF');
  const [choices, setChoices] = useState<WordData[]>([]);

  // Music State
  const [musicState, setMusicState] = useState<'idle' | 'loading' | 'playing' | 'error'>('idle');
  const [currentSong, setCurrentSong] = useState<SongPlayData | null>(null);

  const audioRef = useRef<HTMLAudioElement | null>(null);

  const [isFinished, setIsFinished] = useState(false);

  const inputRef = useRef<HTMLInputElement>(null);
  const nextButtonRef = useRef<HTMLButtonElement>(null);
  const hasInitialized = useRef(false);

  // Cleanup
  useEffect(() => {
    return () => {
      window.speechSynthesis?.cancel();
      stopMusic();
    };
  }, []);

  useEffect(() => {
    if (isFinished) {
      playVictorySound();
    }
  }, [isFinished]);

  useEffect(() => {
    if (!hasInitialized.current && words.length > 0) {
      const shuffled = [...words].sort(() => Math.random() - 0.5);
      setQueue(shuffled);
      hasInitialized.current = true;
      setupNewRound(shuffled[0], shuffled);
    }
  }, [words]);

  const currentWord = queue[currentIndex];

  const stopMusic = () => {
    if (audioRef.current) {
      audioRef.current.pause();
      audioRef.current.removeAttribute('src'); // Fully detach
      audioRef.current.load();
      audioRef.current = null;
    }
    setMusicState('idle');
    setCurrentSong(null);
  };

  const setupNewRound = (word: WordData, allWords: WordData[]) => {
    const modes: QuizMode[] = ['SPELL_FROM_DEF', 'SPELL_FROM_AUDIO', 'MEANING_FROM_WORD'];
    const nextMode = modes[Math.floor(Math.random() * modes.length)];
    setQuizMode(nextMode);

    if (nextMode === 'MEANING_FROM_WORD') {
      const distractors = allWords
        .filter(w => w.id !== word.id)
        .sort(() => 0.5 - Math.random())
        .slice(0, 3);
      const options = [word, ...distractors].sort(() => 0.5 - Math.random());
      setChoices(options);
    } else if (nextMode === 'SPELL_FROM_AUDIO') {
       setTimeout(() => speakText(word.word), 500);
    }
  };

  // Focus Logic
  useEffect(() => {
    const timer = setTimeout(() => {
      if (isFinished) return;
      if (status === 'idle') {
        if (quizMode !== 'MEANING_FROM_WORD') {
          inputRef.current?.focus();
        }
      } else if (status === 'correct') {
        nextButtonRef.current?.focus();
      }
    }, 100);
    return () => clearTimeout(timer);
  }, [status, currentIndex, quizMode, isFinished]);

  const handleSpellingSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentWord || status !== 'idle') return;
    const cleanInput = input.trim().toLowerCase();
    const cleanTarget = currentWord.word.toLowerCase();
    if (cleanInput === cleanTarget) {
      handleCorrect();
    } else {
      handleIncorrect();
    }
  };

  const handleChoiceSelect = (selectedId: string) => {
    if (!currentWord || status !== 'idle') return;
    if (selectedId === currentWord.id) {
      handleCorrect();
    } else {
      handleIncorrect();
    }
  };

  const handleCorrect = async () => {
    setStatus('correct');
    playSuccessSound();
    speakText(currentWord.word);

    // Song Playback Logic
    if (currentWord.songInfo && currentWord.songLyric) {
      setMusicState('loading');
      try {
        const songData = await getSongSegment(currentWord.songInfo, currentWord.songLyric);

        if (songData) {
          setCurrentSong(songData);
          stopMusic();

          const audio = new Audio();

          // CRITICAL FIX: Removed 'crossOrigin = "anonymous"'
          // Netease "outer" links redirect to CDNs that often DO NOT send CORS headers.
          // By removing this, we accept an "opaque" response. We can play it, but we can't analyze the bytes.
          // This is fine for just playback and fixes the 403/Error issues.
          // audio.crossOrigin = "anonymous"; 

          audio.src = songData.url;
          audioRef.current = audio;

          // Event: Metadata Loaded (Duration available) - Set Start Time Here
          audio.onloadedmetadata = () => {
             // Ensure the start time is valid
             if (songData.startTime < audio.duration) {
                audio.currentTime = songData.startTime;
             }
          };

          // Event: Ready to play
          audio.oncanplay = async () => {
            // Check if we are still on the same word and state
            if (audioRef.current !== audio) return;

            try {
              await audio.play();
              setMusicState('playing');

              // Stop after duration
              setTimeout(() => {
                if (audioRef.current === audio) {
                  // Fade out logic
                  const fadeOut = setInterval(() => {
                     if (audio.volume > 0.1) {
                         audio.volume -= 0.1;
                     } else {
                         clearInterval(fadeOut);
                         try { audio.pause(); } catch(e) { /* ignore */ }
                         setMusicState('idle');
                     }
                  }, 200);
                }
              }, songData.duration * 1000);
            } catch (playError) {
              console.warn("Autoplay blocked or failed", playError);
              setMusicState('error');
              fallbackTTS(currentWord);
            }
          };

          audio.onerror = (e) => {
            console.error("Audio Load Error", e);
            setMusicState('error');
            fallbackTTS(currentWord);
          };

        } else {
          console.log("No song found");
          setMusicState('idle');
          fallbackTTS(currentWord);
        }
      } catch (e) {
        console.error("Music fetch error", e);
        setMusicState('error');
        fallbackTTS(currentWord);
      }
    }

    const newCount = currentWord.correctCount + 1;
    onUpdateWord(currentWord.id, { 
      correctCount: newCount, 
      lastPracticed: new Date().toISOString() 
    });
  };

  const fallbackTTS = (word: WordData) => {
    const speechText = `Like in the song ${word.songInfo}: ${word.songLyric}`;
    setTimeout(() => speakText(speechText, 0.95), 1000);
  };

  const handleIncorrect = () => {
    setStatus('incorrect');
    playErrorSound();
    setTimeout(() => {
      setStatus('idle');
      setInput('');
      setShowHint(true);
    }, 1000);
  };

  const handleNext = () => {
    stopMusic();
    if (currentIndex < queue.length - 1) {
      const nextIndex = currentIndex + 1;
      setCurrentIndex(nextIndex);
      setStatus('idle');
      setInput('');
      setShowHint(false);
      setupNewRound(queue[nextIndex], queue);
    } else {
      setIsFinished(true);
    }
