export const enrichVocabulary = async (words: string[]): Promise<WordData[]> => {
  if (words.length === 0) return [];

  const prompt = `
    I have a list of English vocabulary words for a student. 
    Please process these words and provide:
    1. A concise definition in Simplified Chinese (中文).
    2. Part of speech.
    3. A "cloze" example sentence in English (word replaced by '_______').
    4. A VERY POPULAR song lyric that contains this word (in English). 
       - It MUST be from a very famous song (Taylor Swift, Adele, Beatles, Queen, Disney, Top 40 hits) so it is easy to find in a music database.
       - Do not pick obscure songs.
    5. The Artist and Song Name for that lyric.

    The words are: ${words.join(', ')}.

    Return the data in a strict JSON structure.
  `;

  try {
    // 1. Get Text Data
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              word: { type: Type.STRING, description: "The vocabulary word (lowercase)" },
              definition: { type: Type.STRING, description: "Definition in Simplified Chinese" },
              partOfSpeech: { type: Type.STRING, description: "e.g., noun, verb, adjective" },
              exampleSentence: { type: Type.STRING, description: "A sentence using the word, but the word itself is replaced with _______" },
              songLyric: { type: Type.STRING, description: "A line from a famous song containing the word" },
              songInfo: { type: Type.STRING, description: "Artist - Song Name" }
            },
            required: ["word", "definition", "partOfSpeech", "exampleSentence"]
          }
        }
      }
    });

    const rawData = JSON.parse(response.text || '[]');

    // 2. Map to internal structure
    const processedWords: WordData[] = rawData.map((item: any) => ({
      id: crypto.randomUUID(),
      word: item.word.toLowerCase().trim(),
      definition: item.definition,
      exampleSentence: item.exampleSentence,
      partOfSpeech: item.partOfSpeech,
      songLyric: item.songLyric,
      songInfo: item.songInfo,
      correctCount: 0,
      imageUrl: undefined,
      songData: null
    }));

    // 3. Batch Processing to prevent Rate Limits
    // Processing all items at once (Promise.all) causes rate limiting (429) for images and network issues for music.
    // We process in small chunks (batches).
    const BATCH_SIZE = 3; 

    for (let i = 0; i < processedWords.length; i += BATCH_SIZE) {
      const batch = processedWords.slice(i, i + BATCH_SIZE);

      await Promise.all(batch.map(async (word) => {
          // A. Image Generation
          try {
              const imageUrl = await generateWordImage(word.word);
              if (imageUrl) {
                  word.imageUrl = imageUrl;
              }
          } catch (imgError) {
              console.warn(`Failed to generate image for ${word.word}`, imgError);
          }

          // B. Music Matching
          if (word.songInfo && word.songLyric) {
            try {
              const songData = await getSongSegment(word.songInfo, word.songLyric);
              if (songData) {
                word.songData = songData;
              }
            } catch (musicError) {
               console.warn(`Failed to find music for ${word.word}`, musicError);
            }
          }
      }));
    }

    return processedWords;

  } catch (error) {
    console.error("Gemini API Error:", error);
    throw new Error("Failed to enrich vocabulary.");
  }
};

import React, { useState, useEffect } from 'react';
import { WordInput } from './components/WordInput';
import { QuizSession } from './components/QuizSession';
import { Dashboard } from './components/Dashboard';
import { WordData, AppState } from './types';
import { enrichVocabulary } from './services/geminiService';
import { Toaster, toast } from 'react-hot-toast';

const STORAGE_KEY = 'lexiweek_data_v1';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.DASHBOARD);
  const [words, setWords] = useState<WordData[]>([]);
  const [loading, setLoading] = useState(false);

  // Load from local storage on mount
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setWords(parsed);
        if (parsed.length === 0) {
          setAppState(AppState.INPUT);
        }
      } catch (e) {
        console.error("Failed to parse saved data", e);
        setAppState(AppState.INPUT);
      }
    } else {
      setAppState(AppState.INPUT);
    }
  }, []);

  // Save to local storage whenever words change
  useEffect(() => {
    if (words.length === 0) {
       // Allow clearing storage if empty
       if (appState === AppState.INPUT) { // Only if we explicitly reset
          localStorage.removeItem(STORAGE_KEY);
       }
       return;
    }

    try {
      // 1. Try to save EVERYTHING including images
      localStorage.setItem(STORAGE_KEY, JSON.stringify(words));
    } catch (e) {
      // 2. If Quota Exceeded, fallback to saving ONLY text data
      if (e instanceof DOMException && (e.name === 'QuotaExceededError' || e.name === 'NS_ERROR_DOM_QUOTA_REACHED')) {
         console.warn("Storage quota exceeded. Saving without images.");
         try {
            const dataToSave = words.map(w => {
              // eslint-disable-next-line @typescript-eslint/no-unused-vars
              const { imageUrl, ...rest } = w;
              return rest;
            });
            localStorage.setItem(STORAGE_KEY, JSON.stringify(dataToSave));
            // Notify user only once per session ideally, but for now just log or simple toast if needed
            // toast.error("存储空间不足，图片无法保存 (刷新后将丢失)", { id: 'storage-warn' });
         } catch (retryError) {
            console.error("Critical: Failed to save data even without images", retryError);
         }
      } else {
        console.error("Storage error:", e);
      }
    }
  }, [words, appState]);

  const handleWordsSubmit = async (rawWords: string[]) => {
    setLoading(true);
    try {
      const enrichedWords = await enrichVocabulary(rawWords);
      setWords(enrichedWords);
      setAppState(AppState.DASHBOARD);
      toast.success('词库已创建！');
    } catch (error) {
      console.error(error);
      toast.error('处理单词失败，请重试。');
    } finally {
      setLoading(false);
    }
  };

  const handleResetWeek = () => {
    if (window.confirm("确定要重置吗？这将删除当前的进度并开始新的一周。")) {
      setWords([]);
      setAppState(AppState.INPUT);
      localStorage.removeItem(STORAGE_KEY);
    }
  };

  const handleUpdateWord = (wordId: string, updates: Partial<WordData>) => {
    setWords(prev => prev.map(w => {
      if (w.id !== wordId) return w;
      return { ...w, ...updates };
    }));
  };

  return (
    // Changed min-h-screen to ensure scrolling works when content overflows (like when keyboard is open)
    <div className="min-h-screen w-full bg-slate-50 relative">
      {/* 
        PERFORMANCE FIX: 
        Replaced heavy animated blobs (filter blur + animation loop) with a static CSS gradient mesh.
        This prevents crashes on mobile devices when the keyboard opens/closes (which triggers repaints).
      */}
      <div className="fixed inset-0 z-0 bg-gradient-to-br from-indigo-50 via-purple-50 to-pink-50 opacity-80 pointer-events-none"></div>
      <div className="fixed top-0 left-0 w-full h-1 bg-gradient-to-r from-indigo-500 via-purple-500 to-pink-500 z-50"></div>

      {/* Content Container - Allows scrolling */}
      <main className="relative z-10 w-full max-w-4xl mx-auto p-4 sm:p-6 lg:p-8 flex flex-col min-h-screen justify-center">
        {appState === AppState.INPUT && (
          <WordInput 
            onSubmit={handleWordsSubmit} 
            isLoading={loading} 
            hasExistingData={words.length > 0}
            onCancel={words.length > 0 ? () => setAppState(AppState.DASHBOARD) : undefined}
          />
        )}

        {appState === AppState.DASHBOARD && (
          <Dashboard 
            words={words} 
            onStartQuiz={() => setAppState(AppState.QUIZ)}
            onNewWeek={handleResetWeek}
          />
        )}

        {appState === AppState.QUIZ && (
          <QuizSession 
            words={words}
            onComplete={(results) => {
              setAppState(AppState.DASHBOARD);
            }}
            onUpdateWord={handleUpdateWord}
            onExit={() => setAppState(AppState.DASHBOARD)}
          />
        )}
      </main>

      <Toaster position="bottom-center" />
    </div>
  );
};

