import { SongPlayData } from '../types';

// API Base
// Using a reliable public instance of the Netease Cloud Music API
const API_BASE_URL = 'https://netease-cloud-music-api-brilliance.vercel.app';

// Helper: Normalize text
const normalize = (text: string) => {
  return text.toLowerCase()
    .replace(/['".,/#!$%^&*;:{}=\-_`~()]/g, "")
    .replace(/\s+/g, " ")
    .trim();
};

// Helper: Parse Lyrics
const parseLrc = (lrc: string): { time: number; text: string }[] => {
  if (!lrc) return [];
  const lines = lrc.split('\n');
  const result: { time: number; text: string }[] = [];
  const timeRegex = /\[(\d{2}):(\d{2})\.(\d{2,3})\]/;
  // Handle [00:00.00] format as well
  const timeRegexShort = /\[(\d{2}):(\d{2})\.(\d{2})\]/;

  for (const line of lines) {
    let match = timeRegex.exec(line);
    if (!match) match = timeRegexShort.exec(line);

    if (match) {
      const minutes = parseInt(match[1], 10);
      const seconds = parseInt(match[2], 10);
      const milliseconds = parseInt(match[3].padEnd(3, '0'), 10);
      const time = minutes * 60 + seconds + milliseconds / 1000;
      const text = line.replace(/\[.*?\]/g, '').trim();
      if (text) {
        result.push({ time, text });
      }
    }
  }
  return result;
};

// Helper: Check lyric match with fuzzy logic
const findLyricMatch = (lrcContent: string, targetLyric: string) => {
  const parsedLyrics = parseLrc(lrcContent);
  const normalizedTarget = normalize(targetLyric);
  const targetWords = normalizedTarget.split(' ');

  // If target is too short, we need an exact match
  const needsExact = targetWords.length < 4;

  const matchIndex = parsedLyrics.findIndex(line => {
    const normLine = normalize(line.text);
    if (normLine.length < 2) return false;

    if (needsExact) {
      return normLine.includes(normalizedTarget);
    } else {
      return normLine.includes(normalizedTarget) || 
             (normalizedTarget.includes(normLine) && normLine.length > 10);
    }
  });

  if (matchIndex !== -1) {
    let startTime = parsedLyrics[matchIndex].time;
    // Start playback slightly before the line
    startTime = Math.max(0, startTime - 1.5); 
    return startTime;
  }
  return null;
};

export const getSongSegment = async (searchQuery: string, targetLyric: string): Promise<SongPlayData | null> => {
  console.log(`[MusicService] Searching for: "${searchQuery}"`);

  try {
    // 1. Search for the song
    // limit=5 is enough
    const searchRes = await fetch(`${API_BASE_URL}/cloudsearch?keywords=${encodeURIComponent(searchQuery)}&limit=5&type=1`);
    if (!searchRes.ok) return null;

    const searchData = await searchRes.json();
    const songs = searchData.result?.songs || [];

    if (songs.length === 0) {
      console.log("[MusicService] No songs found.");
      return null;
    }

    // Iterate through candidates
    for (const song of songs) {
      try {
        // 2. FETCH LYRICS (Critical Step: We need to know where to start playing)
        const lyricRes = await fetch(`${API_BASE_URL}/lyric?id=${song.id}`);
        const lyricData = await lyricRes.json();
        const lrc = lyricData?.lrc?.lyric;

        if (!lrc) continue;

        // 3. MATCH LYRICS
        const startTime = findLyricMatch(lrc, targetLyric);

        if (startTime === null) {
           continue;
        }

        // 4. GET PLAYABLE URL
        // Priority A: Try the API endpoint which returns CDN links (often works better for VERCEL deployments)
        let directUrl: string | null = null;
        try {
          const urlRes = await fetch(`${API_BASE_URL}/song/url?id=${song.id}`);
          const urlData = await urlRes.json();
          const candidateUrl = urlData?.data?.[0]?.url;
          if (candidateUrl) directUrl = candidateUrl;
        } catch(e) {
          console.warn("[MusicService] API URL fetch failed, trying fallback.");
        }

        // Priority B: Fallback to the standard outer link if API didn't return one
        if (!directUrl) {
           directUrl = `https://music.163.com/song/media/outer/url?id=${song.id}.mp3`;
        }

        console.log(`[MusicService] Match found: ${song.name}`);

        return {
          url: directUrl,
          startTime,
          duration: 12,
          name: song.name,
          artist: song.ar?.[0]?.name || 'Unknown'
        };

      } catch (innerE) {
        console.warn(`[MusicService] Error processing candidate ${song.id}`, innerE);
      }
    }
  } catch (e) {
    console.error("[MusicService] Search failed", e);
  }

  return null;
};

