        <h1 className="text-2xl sm:text-3xl font-bold text-slate-800 mb-2">开启新的一周</h1>
        <p className="text-sm sm:text-base text-slate-500">
          请在下方粘贴本周的生词表。我们将使用 AI 为你生成释义和测试题。
        </p>
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">
        <div>
          <label htmlFor="words" className="block text-sm font-medium text-slate-700 mb-2">
            词汇列表 (请用逗号或换行分隔)
          </label>
          <textarea
            id="words"
            rows={8}
            className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition-all text-slate-700 placeholder-slate-400 bg-white"
            placeholder="例如: ephemeral, serendipity, resilient..."
            value={inputText}
            onChange={(e) => setInputText(e.target.value)}
            disabled={isLoading}
          />
        </div>

        <div className="flex flex-col sm:flex-row gap-3 sm:gap-4">
          {hasExistingData && onCancel && (
            <button
              type="button"
              onClick={onCancel}
              className="w-full sm:flex-1 px-6 py-3 rounded-xl border border-slate-200 text-slate-600 font-semibold hover:bg-slate-50 transition-colors order-2 sm:order-1"
              disabled={isLoading}
            >
              取消
            </button>
          )}
          <button
            type="submit"
            disabled={isLoading || !inputText.trim()}
            className={`w-full sm:flex-1 px-6 py-3 rounded-xl text-white font-semibold shadow-lg shadow-indigo-500/30 transition-all transform active:scale-95 order-1 sm:order-2
              ${isLoading || !inputText.trim() 
                ? 'bg-slate-400 cursor-not-allowed' 
                : 'bg-indigo-600 hover:bg-indigo-700 hover:-translate-y-0.5'}`}
          >
            {isLoading ? (
              <span className="flex items-center justify-center gap-2">
                <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                  <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                  <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                </svg>
                正在逐个生成资源 (较慢)...
              </span>
            ) : '开始学习'}
          </button>
        </div>
      </form>
    </div>
  );
};

import { GoogleGenAI, Type } from "@google/genai";
import { WordData } from '../types';
import { getSongSegment } from './musicService';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

export const generateWordImage = async (word: string): Promise<string | null> => {
  try {
    const prompt = `Vector illustration of "${word}". Minimalist, white background, single subject.`;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          { text: prompt },
        ],
      },
      config: {
        imageConfig: {
          aspectRatio: "1:1"
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (error) {
    throw error; // Throw up to be handled by the smart looper
  }
};

export const enrichVocabulary = async (words: string[]): Promise<WordData[]> => {
  if (words.length === 0) return [];

  const prompt = `
    I have a list of English vocabulary words: ${words.join(', ')}.

    For EACH word, return a JSON object with:
    1. "word": The word itself (lowercase).
    2. "definition": Concise Simplified Chinese definition.
    3. "partOfSpeech": e.g. noun, verb.
    4. "exampleSentence": A short English sentence with the word replaced by '_______'.
    5. "songLyric": A short, recognizable lyric line containing the word from a VERY FAMOUS song (Taylor Swift, Adele, Justin Bieber, Queen, Disney).
    6. "songInfo": "Artist - Song Name".

    Return a strict JSON array.
  `;

  try {
    // 1. Get Text Data
    // We use gemini-3-flash-preview for text as it's efficient.
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              word: { type: Type.STRING },
              definition: { type: Type.STRING },
              partOfSpeech: { type: Type.STRING },
              exampleSentence: { type: Type.STRING },
              songLyric: { type: Type.STRING },
              songInfo: { type: Type.STRING }
            },
            required: ["word", "definition", "partOfSpeech", "exampleSentence"]
          }
        }
      }
    });

    const rawData = JSON.parse(response.text || '[]');

    // 2. Map to internal structure
    const processedWords: WordData[] = rawData.map((item: any) => ({
      id: crypto.randomUUID(),
      word: item.word.toLowerCase().trim(),
      definition: item.definition,
      exampleSentence: item.exampleSentence,
      partOfSpeech: item.partOfSpeech,
      songLyric: item.songLyric,
      songInfo: item.songInfo,
      correctCount: 0,
      imageUrl: undefined,
      songData: null
    }));

    // 3. Smart Sequential Processing
    // We introduce a 'skipImages' flag. If we hit a rate limit once, we skip images for all subsequent words
    // to ensure the user at least gets the text and music data without waiting or failing.

    let skipImages = false;

    for (const word of processedWords) {

      // A. Image Generation (with circuit breaker)
      if (!skipImages) {
        try {
          const imageUrl = await generateWordImage(word.word);
          if (imageUrl) {
            word.imageUrl = imageUrl;
          }
          // Successful image gen? Wait a bit to be nice to the API
          await delay(1500); 
        } catch (imgError: any) {
          const errMsg = imgError.toString().toLowerCase();
          // Check for 429 (Too Many Requests) or Quota Exceeded
          if (errMsg.includes('429') || errMsg.includes('quota') || errMsg.includes('resource exhausted')) {
             console.warn(`[Gemini] Quota hit on image gen for "${word.word}". Skipping remaining images.`);
             skipImages = true;
          } else {
             console.warn(`[Gemini] Failed to generate image for ${word.word}:`, imgError);
          }
        }
      }

      // B. Music Matching
      if (word.songInfo) {
        try {
          // Search strictly by artist/song first to get the correct track
          const songData = await getSongSegment(word.songInfo, word.songLyric || '');
          if (songData) {
            word.songData = songData;
          }
        } catch (musicError) {
            console.warn(`[Music] Failed to find music for ${word.word}`, musicError);
        }
        // Small delay for music API
        await delay(300);
      }
    }

    return processedWords;

  } catch (error) {
    console.error("Gemini API Error:", error);
    throw new Error("生成内容失败，请检查网络或稍后重试。");
  }
};

import { SongPlayData } from '../types';

// API Base
// Using a reliable public instance of the Netease Cloud Music API
const API_BASE_URL = 'https://netease-cloud-music-api-brilliance.vercel.app';

// Helper: Normalize text
const normalize = (text: string) => {
  return text.toLowerCase()
    .replace(/['".,/#!$%^&*;:{}=\-_`~()]/g, "")
    .replace(/\s+/g, " ")
    .trim();
};

// Helper: Parse Lyrics
const parseLrc = (lrc: string): { time: number; text: string }[] => {
  if (!lrc) return [];
  const lines = lrc.split('\n');
  const result: { time: number; text: string }[] = [];
  const timeRegex = /\[(\d{2}):(\d{2})\.(\d{2,3})\]/;
  const timeRegexShort = /\[(\d{2}):(\d{2})\.(\d{2})\]/;

  for (const line of lines) {
    let match = timeRegex.exec(line);
    if (!match) match = timeRegexShort.exec(line);

    if (match) {
      const minutes = parseInt(match[1], 10);
      const seconds = parseInt(match[2], 10);
      const milliseconds = parseInt(match[3].padEnd(3, '0'), 10);
      const time = minutes * 60 + seconds + milliseconds / 1000;
      const text = line.replace(/\[.*?\]/g, '').trim();
      if (text) {
        result.push({ time, text });
      }
    }
  }
  return result;
};

// Helper: Check lyric match with fuzzy logic
const findLyricMatch = (lrcContent: string, targetLyric: string) => {
  if (!targetLyric) return null;

  const parsedLyrics = parseLrc(lrcContent);
  const normalizedTarget = normalize(targetLyric);

  // Try to find the lyric line
  const matchIndex = parsedLyrics.findIndex(line => {
    const normLine = normalize(line.text);
    return normLine.length > 5 && (normLine.includes(normalizedTarget) || normalizedTarget.includes(normLine));
  });

  if (matchIndex !== -1) {
    // Start 2 seconds before the line
    return Math.max(0, parsedLyrics[matchIndex].time - 2.0); 
  }
  return null;
};

export const getSongSegment = async (searchQuery: string, targetLyric?: string): Promise<SongPlayData | null> => {
  console.log(`[MusicService] Searching for: "${searchQuery}"`);

  try {
    // 1. Search for the song
    const searchRes = await fetch(`${API_BASE_URL}/cloudsearch?keywords=${encodeURIComponent(searchQuery)}&limit=3&type=1`);
    if (!searchRes.ok) return null;

    const searchData = await searchRes.json();
    const songs = searchData.result?.songs || [];

    if (songs.length === 0) return null;

    // Use the first result as the primary candidate since we searched by "Artist - Song"
    const song = songs[0];

    // 2. Try to get lyrics to find start time
    let startTime = 0;
    let foundLyricMatch = false;

    if (targetLyric) {
        try {
            const lyricRes = await fetch(`${API_BASE_URL}/lyric?id=${song.id}`);
            const lyricData = await lyricRes.json();
            const lrc = lyricData?.lrc?.lyric;
            if (lrc) {
                const matchTime = findLyricMatch(lrc, targetLyric);
                if (matchTime !== null) {
                    startTime = matchTime;
                    foundLyricMatch = true;
                    console.log(`[MusicService] Lyric matched at ${startTime}s`);
                }
            }
        } catch (e) {
            console.warn("[MusicService] Lyric fetch failed, defaulting to start.");
        }
    }

    // 3. Construct URL
    // The "outer" URL is generally the most reliable for 3rd party apps if Referrer is handled.
    // We prefer this over the API /song/url which sometimes returns expiring links.
    const directUrl = `https://music.163.com/song/media/outer/url?id=${song.id}.mp3`;

    return {
      url: directUrl,
      startTime: startTime,
      duration: 15, // Play for 15 seconds
      name: song.name,
      artist: song.ar?.[0]?.name || 'Unknown'
    };

  } catch (e) {
    console.error("[MusicService] General failure", e);
    return null;
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { WordData, QuizResult, SongPlayData } from '../types';
import { playSuccessSound, playErrorSound, playVictorySound, speakText } from '../services/audioService';
import toast from 'react-hot-toast';

interface QuizSessionProps {
  words: WordData[];
  onComplete: (results: QuizResult[]) => void;
  onUpdateWord: (id: string, updates: Partial<WordData>) => void;
  onExit: () => void;
}

type QuizMode = 'SPELL_FROM_DEF' | 'SPELL_FROM_AUDIO' | 'MEANING_FROM_WORD';

export const QuizSession: React.FC<QuizSessionProps> = ({ words, onComplete, onUpdateWord, onExit }) => {
  const [queue, setQueue] = useState<WordData[]>([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [input, setInput] = useState('');
  const [status, setStatus] = useState<'idle' | 'correct' | 'incorrect'>('idle');
  const [showHint, setShowHint] = useState(false);

  // New States for Mixed Mode
  const [quizMode, setQuizMode] = useState<QuizMode>('SPELL_FROM_DEF');
  const [choices, setChoices] = useState<WordData[]>([]);

  // Music State
  const [musicState, setMusicState] = useState<'idle' | 'playing' | 'error'>('idle');

  const audioRef = useRef<HTMLAudioElement | null>(null);

  const [isFinished, setIsFinished] = useState(false);

  const inputRef = useRef<HTMLInputElement>(null);
  const nextButtonRef = useRef<HTMLButtonElement>(null);
  const hasInitialized = useRef(false);

  // Cleanup
  useEffect(() => {
    return () => {
      window.speechSynthesis?.cancel();
      stopMusic();
    };
  }, []);

  useEffect(() => {
    if (isFinished) {
      playVictorySound();
    }
  }, [isFinished]);

  useEffect(() => {
    if (!hasInitialized.current && words.length > 0) {
      const shuffled = [...words].sort(() => Math.random() - 0.5);
      setQueue(shuffled);
      hasInitialized.current = true;
      setupNewRound(shuffled[0], shuffled);
    }
  }, [words]);

  const currentWord = queue[currentIndex];

  const stopMusic = () => {
    if (audioRef.current) {
      audioRef.current.pause();
      audioRef.current.removeAttribute('src'); // Fully detach
      audioRef.current.load();
      audioRef.current = null;
    }
    setMusicState('idle');
  };

  const setupNewRound = (word: WordData, allWords: WordData[]) => {
    const modes: QuizMode[] = ['SPELL_FROM_DEF', 'SPELL_FROM_AUDIO', 'MEANING_FROM_WORD'];
    const nextMode = modes[Math.floor(Math.random() * modes.length)];
    setQuizMode(nextMode);

    if (nextMode === 'MEANING_FROM_WORD') {
      const distractors = allWords
        .filter(w => w.id !== word.id)
        .sort(() => 0.5 - Math.random())
        .slice(0, 3);
      const options = [word, ...distractors].sort(() => 0.5 - Math.random());
      setChoices(options);
    } else if (nextMode === 'SPELL_FROM_AUDIO') {
       setTimeout(() => speakText(word.word), 500);
    }
  };

  // Focus Logic
  useEffect(() => {
    const timer = setTimeout(() => {
      if (isFinished) return;
      if (status === 'idle') {
        if (quizMode !== 'MEANING_FROM_WORD') {
          inputRef.current?.focus();
        }
      } else if (status === 'correct') {
        nextButtonRef.current?.focus();
      }
    }, 100);
    return () => clearTimeout(timer);
  }, [status, currentIndex, quizMode, isFinished]);

  const handleSpellingSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentWord || status !== 'idle') return;
    const cleanInput = input.trim().toLowerCase();
    const cleanTarget = currentWord.word.toLowerCase();
    if (cleanInput === cleanTarget) {
      handleCorrect();
    } else {
      handleIncorrect();
    }
  };

  const handleChoiceSelect = (selectedId: string) => {
    if (!currentWord || status !== 'idle') return;
    if (selectedId === currentWord.id) {
      handleCorrect();
    } else {
      handleIncorrect();
    }
  };

  const handleCorrect = async () => {
    setStatus('correct');
    playSuccessSound();
    speakText(currentWord.word);

    // Instant Song Playback using pre-loaded data
    if (currentWord.songData) {
        // Short delay to let the TTS start first
        setTimeout(() => playSong(currentWord.songData!), 300);
    } else if (currentWord.songInfo) {
        console.log("No pre-loaded song found.");
        fallbackTTS(currentWord);
    }

    const newCount = currentWord.correctCount + 1;
    onUpdateWord(currentWord.id, { 
      correctCount: newCount, 
      lastPracticed: new Date().toISOString() 
    });
  };

  const playSong = (songData: SongPlayData) => {
      stopMusic();
      const audio = new Audio();

      // CRITICAL: This allows playing from Netease without 403 Forbidden
      audio.referrerPolicy = "no-referrer";
      audio.src = songData.url;
      audioRef.current = audio;

      // Event: Metadata Loaded
      audio.onloadedmetadata = () => {
          if (songData.startTime > 0 && songData.startTime < audio.duration) {
            audio.currentTime = songData.startTime;
          }
      };

      // Event: Ready to play
      audio.oncanplay = async () => {
        if (audioRef.current !== audio) return;

        try {
          await audio.play();
          setMusicState('playing');

          // Stop after duration
          setTimeout(() => {
            if (audioRef.current === audio) {
              // Fade out logic
              const fadeOut = setInterval(() => {
                  if (audio.volume > 0.1) {
                      audio.volume -= 0.1;
                  } else {
                      clearInterval(fadeOut);
                      try { audio.pause(); } catch(e) { /* ignore */ }
                      setMusicState('idle');
                  }
              }, 200);
            }
          }, songData.duration * 1000);
        } catch (playError) {
          console.warn("Autoplay blocked", playError);
          setMusicState('error');
          // Don't fallback to TTS immediately if it's just a user interaction block
        }
      };

      audio.onerror = (e) => {
        console.error("Audio Load Error", e);
        setMusicState('error');
        fallbackTTS(currentWord);
      };
  };

  const fallbackTTS = (word: WordData) => {
    if (word.songLyric) {
        const speechText = `Like in the song: ${word.songLyric}`;
        setTimeout(() => speakText(speechText, 0.95), 1000);
    }
  };

  const handleIncorrect = () => {
    setStatus('incorrect');
    playErrorSound();
    setTimeout(() => {
      setStatus('idle');
      setInput('');
      setShowHint(true);
    }, 1000);
  };

  const handleNext = () => {
    stopMusic();
    if (currentIndex < queue.length - 1) {
      const nextIndex = currentIndex + 1;
      setCurrentIndex(nextIndex);
      setStatus('idle');
      setInput('');
      setShowHint(false);
      setupNewRound(queue[nextIndex], queue);
    } else {
      setIsFinished(true);
    }
  };

  if (isFinished) {
    return (
      <div className="w-full max-w-lg mx-auto flex flex-col h-full justify-center items-center p-4">
        <div className="bg-white shadow-xl rounded-2xl p-8 w-full text-center animate-fade-in-up flex flex-col items-center">
           <div className="w-24 h-24 bg-green-100 rounded-full flex items-center justify-center mb-6 text-green-500 shadow-sm animate-bounce">
             <svg xmlns="http://www.w3.org/2000/svg" width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M6 9H4.5a2.5 2.5 0 0 1 0-5H6"></path><path d="M18 9h1.5a2.5 2.5 0 0 0 0-5H18"></path><path d="M4 22h16"></path><path d="M10 14.66V17c0 .55-.47.98-.97 1.21C7.85 18.75 7 20.24 7 22"></path><path d="M14 14.66V17c0 .55.47.98.97 1.21C16.15 18.75 17 20.24 17 22"></path><path d="M18 2H6v7a6 6 0 0 0 12 0V2Z"></path></svg>
           </div>
           <h2 className="text-3xl font-bold text-slate-800 mb-2">周任务完成！</h2>
           <p className="text-slate-500 mb-8 text-lg">你已经成功掌握了所有的单词。</p>

           <button
             onClick={() => onComplete([])}
             className="w-full bg-indigo-600 text-white font-bold py-4 px-6 rounded-xl shadow-lg shadow-indigo-500/30 hover:bg-indigo-700 transition-all active:scale-95 flex items-center justify-center gap-2"
           >
             <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M3 9l9-7 9 7v11a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2z"></path><polyline points="9 22 9 12 15 12 15 22"></polyline></svg>
             回到主页
           </button>
        </div>
      </div>
    );
  }

  if (!currentWord) return <div className="p-8 text-center text-slate-500">准备中...</div>;

  const progress = ((currentIndex) / queue.length) * 100;

  const renderQuestion = () => {
    switch (quizMode) {
      case 'SPELL_FROM_DEF':
        return (
          <div className="flex flex-col items-center animate-fade-in">
             <div className="text-xs font-bold text-indigo-500 uppercase tracking-wide bg-indigo-50 inline-block px-3 py-1 rounded-full mb-4">
               根据中文拼写
            </div>
            <p className="text-slate-700 text-xl sm:text-2xl font-medium leading-relaxed px-2 mb-2">
              {currentWord.definition}
            </p>
            <p className="text-slate-400 text-sm mb-6">{currentWord.partOfSpeech}</p>
          </div>
        );
      case 'SPELL_FROM_AUDIO':
        return (
          <div className="flex flex-col items-center animate-fade-in">
            <div className="text-xs font-bold text-pink-500 uppercase tracking-wide bg-pink-50 inline-block px-3 py-1 rounded-full mb-6">
               听音拼写
            </div>
            <button 
              type="button"
              onClick={() => speakText(currentWord.word)}
              className="w-24 h-24 rounded-full bg-indigo-100 text-indigo-600 flex items-center justify-center hover:bg-indigo-200 transition-all active:scale-95 mb-6"
            >
              <svg xmlns="http://www.w3.org/2000/svg" width="40" height="40" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polygon points="11 5 6 9 2 9 2 15 6 15 11 19 11 5"></polygon><path d="M19.07 4.93a10 10 0 0 1 0 14.14M15.54 8.46a5 5 0 0 1 0 7.07"></path></svg>
            </button>
            <p className="text-slate-400 text-sm mb-2">点击图标重播读音</p>
          </div>
        );
      case 'MEANING_FROM_WORD':
        return (
          <div className="flex flex-col items-center animate-fade-in mb-4">
             <div className="text-xs font-bold text-teal-500 uppercase tracking-wide bg-teal-50 inline-block px-3 py-1 rounded-full mb-4">
               英译中
            </div>
            <h2 className="text-3xl sm:text-4xl font-bold text-slate-800 mb-2">{currentWord.word}</h2>
            <p className="text-slate-400 text-sm">{currentWord.partOfSpeech}</p>
          </div>
        );
    }
  };

  return (
    <div className="w-full max-w-lg mx-auto flex flex-col gap-4">
      {/* Progress Bar */}
      <div className="bg-white/30 backdrop-blur-sm h-1.5 rounded-full overflow-hidden shrink-0 mx-1">
        <div 
          className="bg-indigo-500 h-full transition-all duration-500 ease-out"
          style={{ width: `${progress}%` }}
        ></div>
      </div>

      <div className="bg-white shadow-xl rounded-2xl overflow-hidden relative flex flex-col min-h-[400px]">
        {/* Card Header */}
        <div className="bg-indigo-600 px-6 py-4 flex justify-between items-center text-white shrink-0">
          <span className="font-semibold text-indigo-100 tracking-wider text-xs uppercase">单词 {currentIndex + 1} / {queue.length}</span>
          <button onClick={onExit} className="text-indigo-200 hover:text-white transition-colors p-1">
            <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>
          </button>
        </div>

        {/* Card Body */}
        <div className="p-6 sm:p-10 flex flex-col items-center text-center flex-1">

          {status === 'correct' ? (
            <div className="animate-fade-in flex flex-col items-center w-full gap-6">
              <div className="flex flex-col items-center gap-1 sm:gap-2">
                <div className="text-xl sm:text-2xl font-bold text-green-500 flex items-center gap-2">
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7"></path></svg>
                  回答正确!
                </div>
                <div className="text-3xl sm:text-4xl text-slate-800 font-bold capitalize">{currentWord.word}</div>
                <div className="text-slate-500 text-sm mb-2">{currentWord.definition}</div>

                {currentWord.songData && (
                  <div className={`bg-amber-50 border border-amber-200 rounded-lg p-3 w-full max-w-sm transition-all duration-500 relative overflow-hidden ${musicState === 'playing' ? 'shadow-lg shadow-amber-100 scale-105 ring-2 ring-amber-300' : ''}`}>
                    <div className="flex items-center gap-2 text-amber-600 text-xs font-bold uppercase mb-1 relative z-10">
                      {musicState === 'playing' ? (
                        <span className="flex gap-1 items-center">
                          <span className="flex h-3 w-3 relative">
                            <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-amber-400 opacity-75"></span>
                            <span className="relative inline-flex rounded-full h-3 w-3 bg-amber-500"></span>
                          </span>
                          Playing
                        </span>
                      ) : musicState === 'error' ? (
                         <span className="flex gap-1 items-center text-red-500">
                           <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"></circle><line x1="12" y1="8" x2="12" y2="12"></line><line x1="12" y1="16" x2="12.01" y2="16"></line></svg>
                           Play Failed
                         </span>
                      ) : (
                        <span className="flex gap-1 items-center">
                           <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M9 18V5l12-2v13"></path><circle cx="6" cy="18" r="3"></circle><circle cx="18" cy="16" r="3"></circle></svg>
                           {currentWord.songData.artist} - {currentWord.songData.name}
                        </span>
                      )}
                    </div>
                    <p className="text-slate-700 italic font-medium transition-colors duration-300 relative z-10">
                      "{currentWord.songLyric}"
                    </p>
                    {musicState === 'playing' && (
                       <div className="absolute bottom-0 left-0 h-1 bg-amber-200/50 w-full animate-progress origin-left"></div>
                    )}
                  </div>
                )}
                {/* Fallback Display if SongInfo exists but No SongData found */}
                {!currentWord.songData && currentWord.songInfo && (
                   <div className="text-xs text-slate-400 italic">
                      From song: {currentWord.songInfo} (Audio unavailable)
                   </div>
                )}
              </div>

              <div className="w-full flex items-center justify-center">
                <div className="w-full max-w-[280px] aspect-square rounded-xl overflow-hidden shadow-md border border-slate-100 bg-slate-50 flex items-center justify-center relative">
                  {currentWord.imageUrl ? (
                    <img 
                      src={currentWord.imageUrl} 
                      alt={currentWord.word} 
                      className="w-full h-full object-contain animate-fade-in bg-white" 
                    />
                  ) : (
                    <div className="text-slate-400 flex flex-col items-center p-4">
                        <span className="text-xs">暂无图片 (API限流或失败)</span>
                    </div>
                  )}
                </div>
              </div>

              <button
                ref={nextButtonRef}
                onClick={handleNext}
                className="w-full bg-indigo-600 text-white font-bold py-3.5 px-6 rounded-xl shadow-lg shadow-indigo-500/30 active:scale-95 transition-all hover:bg-indigo-700 flex items-center justify-center gap-2 mb-2"
              >
                {currentIndex < queue.length - 1 ? (
                  <>
                    下一个单词
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 7l5 5m0 0l-5 5m5-5H6"></path></svg>
                  </>
                ) : (
                  <>
                    完成练习
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7"></path></svg>
                  </>
                )}
              </button>
            </div>
          ) : (
            <div className="flex flex-col w-full flex-1">
              <div className="flex-1 flex flex-col justify-center items-center mb-6 space-y-4 min-h-[120px]">
                {renderQuestion()}
              </div>

              {quizMode === 'MEANING_FROM_WORD' ? (
                <div className="w-full flex flex-col gap-3">
                  {choices.map((choice) => (
                    <button
                      key={choice.id}
                      onClick={() => handleChoiceSelect(choice.id)}
                      className={`w-full p-4 rounded-xl border-2 text-left transition-all active:scale-[0.98]
                        ${status === 'incorrect' 
                          ? 'border-slate-100 bg-slate-50 text-slate-400' 
                          : 'border-slate-200 bg-white hover:border-indigo-300 hover:bg-indigo-50 text-slate-700'
                        }`}
                    >
                       {choice.definition}
                    </button>
                  ))}
                  {status === 'incorrect' && (
                     <div className="text-center text-red-500 mt-2 font-medium animate-shake">
                       选择错误，请重试
                     </div>
                  )}
                </div>
              ) : (
                <form onSubmit={handleSpellingSubmit} className="w-full relative shrink-0 mb-4">
                  <div className={`relative transition-transform duration-300 ${status === 'incorrect' ? 'animate-shake' : ''}`}>
                    <input
                      ref={inputRef}
                      type="text"
                      value={input}
                      onChange={(e) => setInput(e.target.value)}
                      placeholder="输入单词..."
                      className={`w-full text-center text-2xl sm:text-3xl font-bold py-3 sm:py-4 bg-transparent border-b-2 sm:border-b-4 focus:outline-none transition-colors rounded-none
                        ${status === 'incorrect' ? 'border-red-500 text-red-500' : 
                        'border-slate-200 focus:border-indigo-500 text-slate-800'}`}
                      autoComplete="off"
                      autoCorrect="off"
                      autoCapitalize="off"
                      spellCheck="false"
                    />
                  </div>

                  {showHint && status === 'idle' && (
                    <div className="mt-3 text-sm text-slate-400 animate-fade-in">
                      提示: 首字母是 <span className="font-bold text-slate-600">{currentWord.word.substring(0, 1).toUpperCase()}</span>
                    </div>
                  )}
                </form>
              )}
            </div>
          )}
        </div>
      </div>
      <div className="h-4 sm:h-0"></div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { WordData, QuizResult, SongPlayData } from '../types';
import { playSuccessSound, playErrorSound, playVictorySound, speakText } from '../services/audioService';
import toast from 'react-hot-toast';

interface QuizSessionProps {
  words: WordData[];
  onComplete: (results: QuizResult[]) => void;
  onUpdateWord: (id: string, updates: Partial<WordData>) => void;
  onExit: () => void;
}

type QuizMode = 'SPELL_FROM_DEF' | 'SPELL_FROM_AUDIO' | 'MEANING_FROM_WORD';

export const QuizSession: React.FC<QuizSessionProps> = ({ words, onComplete, onUpdateWord, onExit }) => {
  const [queue, setQueue] = useState<WordData[]>([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [input, setInput] = useState('');
  const [status, setStatus] = useState<'idle' | 'correct' | 'incorrect'>('idle');
  const [showHint, setShowHint] = useState(false);

  // New States for Mixed Mode
  const [quizMode, setQuizMode] = useState<QuizMode>('SPELL_FROM_DEF');
  const [choices, setChoices] = useState<WordData[]>([]);

  // Music State
  const [musicState, setMusicState] = useState<'idle' | 'playing' | 'error'>('idle');

  const audioRef = useRef<HTMLAudioElement | null>(null);

  const [isFinished, setIsFinished] = useState(false);

  const inputRef = useRef<HTMLInputElement>(null);
  const nextButtonRef = useRef<HTMLButtonElement>(null);
  const hasInitialized = useRef(false);

  // Cleanup
  useEffect(() => {
    return () => {
      window.speechSynthesis?.cancel();
      stopMusic();
    };
  }, []);

  useEffect(() => {
    if (isFinished) {
      playVictorySound();
    }
  }, [isFinished]);

  useEffect(() => {
    if (!hasInitialized.current && words.length > 0) {
      const shuffled = [...words].sort(() => Math.random() - 0.5);
      setQueue(shuffled);
      hasInitialized.current = true;
      setupNewRound(shuffled[0], shuffled);
    }
  }, [words]);

  const currentWord = queue[currentIndex];

  const stopMusic = () => {
    if (audioRef.current) {
      audioRef.current.pause();
      audioRef.current.removeAttribute('src'); // Fully detach
      audioRef.current.load();
      audioRef.current = null;
    }
    setMusicState('idle');
  };

  const setupNewRound = (word: WordData, allWords: WordData[]) => {
    const modes: QuizMode[] = ['SPELL_FROM_DEF', 'SPELL_FROM_AUDIO', 'MEANING_FROM_WORD'];
    const nextMode = modes[Math.floor(Math.random() * modes.length)];
    setQuizMode(nextMode);

    if (nextMode === 'MEANING_FROM_WORD') {
      const distractors = allWords
        .filter(w => w.id !== word.id)
        .sort(() => 0.5 - Math.random())
        .slice(0, 3);
      const options = [word, ...distractors].sort(() => 0.5 - Math.random());
      setChoices(options);
    } else if (nextMode === 'SPELL_FROM_AUDIO') {
       setTimeout(() => speakText(word.word), 500);
    }
  };

  // Focus Logic
  useEffect(() => {
    const timer = setTimeout(() => {
      if (isFinished) return;
      if (status === 'idle') {
        if (quizMode !== 'MEANING_FROM_WORD') {
          inputRef.current?.focus();
        }
      } else if (status === 'correct') {
        nextButtonRef.current?.focus();
      }
    }, 100);
    return () => clearTimeout(timer);
  }, [status, currentIndex, quizMode, isFinished]);

  const handleSpellingSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentWord || status !== 'idle') return;
    const cleanInput = input.trim().toLowerCase();
    const cleanTarget = currentWord.word.toLowerCase();
    if (cleanInput === cleanTarget) {
      handleCorrect();
    } else {
      handleIncorrect();
    }
  };

  const handleChoiceSelect = (selectedId: string) => {
    if (!currentWord || status !== 'idle') return;
    if (selectedId === currentWord.id) {
      handleCorrect();
    } else {
      handleIncorrect();
    }
  };

  const handleCorrect = async () => {
    setStatus('correct');
    playSuccessSound();
    speakText(currentWord.word);

    // Instant Song Playback using pre-loaded data
    if (currentWord.songData) {
        // Short delay to let the TTS start first
        setTimeout(() => playSong(currentWord.songData!), 300);
    } else if (currentWord.songInfo) {
        console.log("No pre-loaded song found.");
        fallbackTTS(currentWord);
    }

    const newCount = currentWord.correctCount + 1;
    onUpdateWord(currentWord.id, { 
      correctCount: newCount, 
      lastPracticed: new Date().toISOString() 
    });
  };

  const playSong = (songData: SongPlayData) => {
      stopMusic();
      const audio = new Audio();

      // CRITICAL: This allows playing from Netease without 403 Forbidden
      (audio as any).referrerPolicy = "no-referrer";
      audio.src = songData.url;
      audioRef.current = audio;

      // Event: Metadata Loaded
      audio.onloadedmetadata = () => {
          if (songData.startTime > 0 && songData.startTime < audio.duration) {
            audio.currentTime = songData.startTime;
          }
      };

      // Event: Ready to play
      audio.oncanplay = async () => {
        if (audioRef.current !== audio) return;

        try {
          await audio.play();
          setMusicState('playing');

          // Stop after duration
          setTimeout(() => {
            if (audioRef.current === audio) {
              // Fade out logic
              const fadeOut = setInterval(() => {
                  if (audio.volume > 0.1) {
                      audio.volume -= 0.1;
                  } else {
                      clearInterval(fadeOut);
                      try { audio.pause(); } catch(e) { /* ignore */ }
                      setMusicState('idle');
                  }
              }, 200);
            }
          }, songData.duration * 1000);
        } catch (playError) {
          console.warn("Autoplay blocked", playError);
          setMusicState('error');
          // Don't fallback to TTS immediately if it's just a user interaction block
        }
      };

      audio.onerror = (e) => {
        console.error("Audio Load Error", e);
        setMusicState('error');
        fallbackTTS(currentWord);
      };
  };

  const fallbackTTS = (word: WordData) => {
    if (word.songLyric) {
        const speechText = `Like in the song: ${word.songLyric}`;
        setTimeout(() => speakText(speechText, 0.95), 1000);
    }
  };

  const handleIncorrect = () => {
    setStatus('incorrect');
    playErrorSound();
    setTimeout(() => {
      setStatus('idle');
      setInput('');
      setShowHint(true);
    }, 1000);
  };

  const handleNext = () => {
    stopMusic();
    if (currentIndex < queue.length - 1) {
      const nextIndex = currentIndex + 1;
      setCurrentIndex(nextIndex);
      setStatus('idle');
      setInput('');
      setShowHint(false);
      setupNewRound(queue[nextIndex], queue);
    } else {
      setIsFinished(true);
    }
  };

  if (isFinished) {
    return (
      <div className="w-full max-w-lg mx-auto flex flex-col h-full justify-center items-center p-4">
        <div className="bg-white shadow-xl rounded-2xl p-8 w-full text-center animate-fade-in-up flex flex-col items-center">
           <div className="w-24 h-24 bg-green-100 rounded-full flex items-center justify-center mb-6 text-green-500 shadow-sm animate-bounce">
             <svg xmlns="http://www.w3.org/2000/svg" width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M6 9H4.5a2.5 2.5 0 0 1 0-5H6"></path><path d="M18 9h1.5a2.5 2.5 0 0 0 0-5H18"></path><path d="M4 22h16"></path><path d="M10 14.66V17c0 .55-.47.98-.97 1.21C7.85 18.75 7 20.24 7 22"></path><path d="M14 14.66V17c0 .55.47.98.97 1.21C16.15 18.75 17 20.24 17 22"></path><path d="M18 2H6v7a6 6 0 0 0 12 0V2Z"></path></svg>
           </div>
           <h2 className="text-3xl font-bold text-slate-800 mb-2">周任务完成！</h2>
           <p className="text-slate-500 mb-8 text-lg">你已经成功掌握了所有的单词。</p>

           <button
             onClick={() => onComplete([])}
             className="w-full bg-indigo-600 text-white font-bold py-4 px-6 rounded-xl shadow-lg shadow-indigo-500/30 hover:bg-indigo-700 transition-all active:scale-95 flex items-center justify-center gap-2"
           >
             <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M3 9l9-7 9 7v11a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2z"></path><polyline points="9 22 9 12 15 12 15 22"></polyline></svg>
             回到主页
           </button>
        </div>
      </div>
    );
  }

  if (!currentWord) return <div className="p-8 text-center text-slate-500">准备中...</div>;

  const progress = ((currentIndex) / queue.length) * 100;

  const renderQuestion = () => {
    switch (quizMode) {
      case 'SPELL_FROM_DEF':
        return (
          <div className="flex flex-col items-center animate-fade-in">
             <div className="text-xs font-bold text-indigo-500 uppercase tracking-wide bg-indigo-50 inline-block px-3 py-1 rounded-full mb-4">
               根据中文拼写
            </div>
            <p className="text-slate-700 text-xl sm:text-2xl font-medium leading-relaxed px-2 mb-2">
              {currentWord.definition}
            </p>
            <p className="text-slate-400 text-sm mb-6">{currentWord.partOfSpeech}</p>
          </div>
        );
      case 'SPELL_FROM_AUDIO':
        return (
          <div className="flex flex-col items-center animate-fade-in">
            <div className="text-xs font-bold text-pink-500 uppercase tracking-wide bg-pink-50 inline-block px-3 py-1 rounded-full mb-6">
               听音拼写
            </div>
            <button 
              type="button"
              onClick={() => speakText(currentWord.word)}
              className="w-24 h-24 rounded-full bg-indigo-100 text-indigo-600 flex items-center justify-center hover:bg-indigo-200 transition-all active:scale-95 mb-6"
            >
              <svg xmlns="http://www.w3.org/2000/svg" width="40" height="40" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polygon points="11 5 6 9 2 9 2 15 6 15 11 19 11 5"></polygon><path d="M19.07 4.93a10 10 0 0 1 0 14.14M15.54 8.46a5 5 0 0 1 0 7.07"></path></svg>
            </button>
            <p className="text-slate-400 text-sm mb-2">点击图标重播读音</p>
          </div>
        );
      case 'MEANING_FROM_WORD':
        return (
          <div className="flex flex-col items-center animate-fade-in mb-4">
             <div className="text-xs font-bold text-teal-500 uppercase tracking-wide bg-teal-50 inline-block px-3 py-1 rounded-full mb-4">
               英译中
            </div>
            <h2 className="text-3xl sm:text-4xl font-bold text-slate-800 mb-2">{currentWord.word}</h2>
            <p className="text-slate-400 text-sm">{currentWord.partOfSpeech}</p>
          </div>
        );
    }
  };

  return (
    <div className="w-full max-w-lg mx-auto flex flex-col gap-4">
      {/* Progress Bar */}
      <div className="bg-white/30 backdrop-blur-sm h-1.5 rounded-full overflow-hidden shrink-0 mx-1">
        <div 
          className="bg-indigo-500 h-full transition-all duration-500 ease-out"
          style={{ width: `${progress}%` }}
        ></div>
      </div>

      <div className="bg-white shadow-xl rounded-2xl overflow-hidden relative flex flex-col min-h-[400px]">
        {/* Card Header */}
        <div className="bg-indigo-600 px-6 py-4 flex justify-between items-center text-white shrink-0">
          <span className="font-semibold text-indigo-100 tracking-wider text-xs uppercase">单词 {currentIndex + 1} / {queue.length}</span>
          <button onClick={onExit} className="text-indigo-200 hover:text-white transition-colors p-1">
            <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>
          </button>
        </div>

        {/* Card Body */}
        <div className="p-6 sm:p-10 flex flex-col items-center text-center flex-1">

          {status === 'correct' ? (
            <div className="animate-fade-in flex flex-col items-center w-full gap-6">
              <div className="flex flex-col items-center gap-1 sm:gap-2">
                <div className="text-xl sm:text-2xl font-bold text-green-500 flex items-center gap-2">
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7"></path></svg>
                  回答正确!
                </div>
                <div className="text-3xl sm:text-4xl text-slate-800 font-bold capitalize">{currentWord.word}</div>
                <div className="text-slate-500 text-sm mb-2">{currentWord.definition}</div>

                {currentWord.songData && (
                  <div className={`bg-amber-50 border border-amber-200 rounded-lg p-3 w-full max-w-sm transition-all duration-500 relative overflow-hidden ${musicState === 'playing' ? 'shadow-lg shadow-amber-100 scale-105 ring-2 ring-amber-300' : ''}`}>
                    <div className="flex items-center gap-2 text-amber-600 text-xs font-bold uppercase mb-1 relative z-10">
                      {musicState === 'playing' ? (
                        <span className="flex gap-1 items-center">
                          <span className="flex h-3 w-3 relative">
                            <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-amber-400 opacity-75"></span>
                            <span className="relative inline-flex rounded-full h-3 w-3 bg-amber-500"></span>
                          </span>
                          Playing
                        </span>
                      ) : musicState === 'error' ? (
                         <span className="flex gap-1 items-center text-red-500">
                           <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"></circle><line x1="12" y1="8" x2="12" y2="12"></line><line x1="12" y1="16" x2="12.01" y2="16"></line></svg>
                           Play Failed
                         </span>
                      ) : (
                        <span className="flex gap-1 items-center">
                           <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M9 18V5l12-2v13"></path><circle cx="6" cy="18" r="3"></circle><circle cx="18" cy="16" r="3"></circle></svg>
                           {currentWord.songData.artist} - {currentWord.songData.name}
                        </span>
                      )}
                    </div>
                    <p className="text-slate-700 italic font-medium transition-colors duration-300 relative z-10">
                      "{currentWord.songLyric}"
                    </p>
                    {musicState === 'playing' && (
                       <div className="absolute bottom-0 left-0 h-1 bg-amber-200/50 w-full animate-progress origin-left"></div>
                    )}
                  </div>
                )}
                {/* Fallback Display if SongInfo exists but No SongData found */}
                {!currentWord.songData && currentWord.songInfo && (
                   <div className="text-xs text-slate-400 italic">
                      From song: {currentWord.songInfo} (Audio unavailable)
                   </div>
                )}
              </div>

              <div className="w-full flex items-center justify-center">
                <div className="w-full max-w-[280px] aspect-square rounded-xl overflow-hidden shadow-md border border-slate-100 bg-slate-50 flex items-center justify-center relative">
                  {currentWord.imageUrl ? (
                    <img 
                      src={currentWord.imageUrl} 
                      alt={currentWord.word} 
                      className="w-full h-full object-contain animate-fade-in bg-white" 
                    />
                  ) : (
                    <div className="text-slate-400 flex flex-col items-center p-4">
                        <span className="text-xs">暂无图片 (API限流或失败)</span>
                    </div>
                  )}
                </div>
              </div>

              <button
                ref={nextButtonRef}
                onClick={handleNext}
                className="w-full bg-indigo-600 text-white font-bold py-3.5 px-6 rounded-xl shadow-lg shadow-indigo-500/30 active:scale-95 transition-all hover:bg-indigo-700 flex items-center justify-center gap-2 mb-2"
              >
                {currentIndex < queue.length - 1 ? (
                  <>
                    下一个单词
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 7l5 5m0 0l-5 5m5-5H6"></path></svg>
                  </>
                ) : (
                  <>
                    完成练习
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7"></path></svg>
                  </>
                )}
              </button>
            </div>
          ) : (
            <div className="flex flex-col w-full flex-1">
              <div className="flex-1 flex flex-col justify-center items-center mb-6 space-y-4 min-h-[120px]">
                {renderQuestion()}
              </div>

              {quizMode === 'MEANING_FROM_WORD' ? (
                <div className="w-full flex flex-col gap-3">
                  {choices.map((choice) => (
                    <button
                      key={choice.id}
                      onClick={() => handleChoiceSelect(choice.id)}
                      className={`w-full p-4 rounded-xl border-2 text-left transition-all active:scale-[0.98]
                        ${status === 'incorrect' 
                          ? 'border-slate-100 bg-slate-50 text-slate-400' 
                          : 'border-slate-200 bg-white hover:border-indigo-300 hover:bg-indigo-50 text-slate-700'
                        }`}
                    >
                       {choice.definition}
                    </button>
                  ))}
                  {status === 'incorrect' && (
                     <div className="text-center text-red-500 mt-2 font-medium animate-shake">
                       选择错误，请重试
                     </div>
