                      ref={inputRef}
                      type="text"
                      value={input}
                      onChange={(e) => setInput(e.target.value)}
                      placeholder="输入单词..."
                      className={`w-full text-center text-2xl sm:text-3xl font-bold py-3 sm:py-4 bg-transparent border-b-2 sm:border-b-4 focus:outline-none transition-colors rounded-none
                        ${status === 'incorrect' ? 'border-red-500 text-red-500' : 
                        'border-slate-200 focus:border-indigo-500 text-slate-800'}`}
                      autoComplete="off"
                      autoCorrect="off"
                      autoCapitalize="off"
                      spellCheck="false"
                    />
                  </div>

                  {showHint && status === 'idle' && (
                    <div className="mt-3 text-sm text-slate-400 animate-fade-in">
                      提示: 首字母是 <span className="font-bold text-slate-600">{currentWord.word.substring(0, 1).toUpperCase()}</span>
                    </div>
                  )}
                </form>
              )}
            </div>
          )}
        </div>
      </div>
      <div className="h-4 sm:h-0"></div>
    </div>
  );
};

import { GoogleGenAI, Type } from "@google/genai";
import { WordData } from '../types';
import { getSongSegment } from './musicService';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Using Lexica API for "Search" instead of "Generation".
// This is free, extremely fast, and searches a database of existing high-quality AI art.
// It avoids the Gemini Quota limits entirely for images.
export const searchWordImage = async (word: string): Promise<string | null> => {
  try {
    // Search for a specific style to keep the app looking consistent
    const query = `minimalist vector illustration ${word} flat design white background`;
    const response = await fetch(`https://lexica.art/api/v1/search?q=${encodeURIComponent(query)}`);

    if (!response.ok) return null;

    const data = await response.json();
    if (data.images && data.images.length > 0) {
      // Return the first relevant image
      return data.images[0].src;
    }
    return null;
  } catch (error) {
    console.warn(`Image Search failed for ${word}:`, error);
    // Fallback: If search fails, return null (Dashboard handles empty images gracefully)
    return null;
  }
};

export const enrichVocabulary = async (words: string[]): Promise<WordData[]> => {
  if (words.length === 0) return [];

  // Prompt purely for Text Data (Definitions, Music Info, Sentences)
  // Gemini 3 Flash is very fast and has high quotas for text.
  const prompt = `
    I have a list of English vocabulary words: ${words.join(', ')}.

    For EACH word, return a JSON object with:
    1. "word": The word itself (lowercase).
    2. "definition": Concise Simplified Chinese definition.
    3. "partOfSpeech": e.g. noun, verb.
    4. "exampleSentence": A short English sentence with the word replaced by '_______'.
    5. "songLyric": A short, recognizable lyric line containing the word from a VERY FAMOUS song (Taylor Swift, Adele, Justin Bieber, Queen, Disney).
    6. "songInfo": "Artist - Song Name".

    Return a strict JSON array.
  `;

  try {
    // 1. Get Text Data (Fast)
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              word: { type: Type.STRING },
              definition: { type: Type.STRING },
              partOfSpeech: { type: Type.STRING },
              exampleSentence: { type: Type.STRING },
              songLyric: { type: Type.STRING },
              songInfo: { type: Type.STRING }
            },
            required: ["word", "definition", "partOfSpeech", "exampleSentence"]
          }
        }
      }
    });

    const rawData = JSON.parse(response.text || '[]');

    // 2. Map to internal structure
    let processedWords: WordData[] = rawData.map((item: any) => ({
      id: crypto.randomUUID(),
      word: item.word.toLowerCase().trim(),
      definition: item.definition,
      exampleSentence: item.exampleSentence,
      partOfSpeech: item.partOfSpeech,
      songLyric: item.songLyric,
      songInfo: item.songInfo,
      correctCount: 0,
      imageUrl: undefined,
      songData: null
    }));

    // 3. Parallel Enrichment (Images + Music)
    // Since we are NOT using Gemini Image Gen anymore, we don't need to be serial.
    // We can fetch everything in parallel for maximum speed.

    const enrichedWords = await Promise.all(processedWords.map(async (word) => {
        // A. Search Image (Lexica API - Fast)
        try {
            const imageUrl = await searchWordImage(word.word);
            if (imageUrl) {
                word.imageUrl = imageUrl;
            }
        } catch (e) {
            console.warn(`Error fetching image for ${word.word}`, e);
        }

        // B. Match Music (Netease API - Fast)
        if (word.songInfo) {
            try {
                const songData = await getSongSegment(word.songInfo, word.songLyric || '');
                if (songData) {
                    word.songData = songData;
                }
            } catch (e) {
                console.warn(`Error fetching music for ${word.word}`, e);
            }
        }

        return word;
    }));

    return enrichedWords;

  } catch (error) {
    console.error("Gemini API Error:", error);
    throw new Error("生成内容失败，请检查网络或稍后重试。");
  }
};

