import { SongPlayData } from '../types';

// List of public Netease Cloud Music API instances
// We rotate through these if one fails to avoid "Failed to fetch" errors due to downtime or rate limits.
const API_MIRRORS = [
  'https://netease-cloud-music-api-brilliance.vercel.app',
  'https://music.qier222.com/api',
  'https://netease-cloud-music-api-anon.vercel.app'
];

// Helper: Normalize text
const normalize = (text: string) => {
  return text.toLowerCase()
    .replace(/['".,/#!$%^&*;:{}=\-_`~()]/g, "")
    .replace(/\s+/g, " ")
    .trim();
};

// Helper: Parse Lyrics
const parseLrc = (lrc: string): { time: number; text: string }[] => {
  if (!lrc) return [];
  const lines = lrc.split('\n');
  const result: { time: number; text: string }[] = [];
  const timeRegex = /\[(\d{2}):(\d{2})\.(\d{2,3})\]/;
  const timeRegexShort = /\[(\d{2}):(\d{2})\.(\d{2})\]/;

  for (const line of lines) {
    let match = timeRegex.exec(line);
    if (!match) match = timeRegexShort.exec(line);

    if (match) {
      const minutes = parseInt(match[1], 10);
      const seconds = parseInt(match[2], 10);
      const milliseconds = parseInt(match[3].padEnd(3, '0'), 10);
      const time = minutes * 60 + seconds + milliseconds / 1000;
      const text = line.replace(/\[.*?\]/g, '').trim();
      if (text) {
        result.push({ time, text });
      }
    }
  }
  return result;
};

// Helper: Check lyric match with fuzzy logic
const findLyricMatch = (lrcContent: string, targetLyric: string) => {
  if (!targetLyric) return null;

  const parsedLyrics = parseLrc(lrcContent);
  const normalizedTarget = normalize(targetLyric);

  // Try to find the lyric line
  const matchIndex = parsedLyrics.findIndex(line => {
    const normLine = normalize(line.text);
    return normLine.length > 5 && (normLine.includes(normalizedTarget) || normalizedTarget.includes(normLine));
  });

  if (matchIndex !== -1) {
    // Start 2 seconds before the line
    return Math.max(0, parsedLyrics[matchIndex].time - 2.0); 
  }
  return null;
};

// Robust fetcher that tries mirrors
const fetchFromApi = async (path: string): Promise<any> => {
    for (const baseUrl of API_MIRRORS) {
        try {
            const controller = new AbortController();
            // 4 second timeout per mirror to fail fast
            const timeoutId = setTimeout(() => controller.abort(), 4000); 

            const res = await fetch(`${baseUrl}${path}`, { signal: controller.signal });
            clearTimeout(timeoutId);

            if (res.ok) {
                return await res.json();
            }
        } catch (e) {
            // Silently continue to next mirror
            continue;
        }
    }
    throw new Error("All API mirrors failed");
};

export const getSongSegment = async (searchQuery: string, targetLyric?: string): Promise<SongPlayData | null> => {
  try {
    // 1. Search for the song
    const searchData = await fetchFromApi(`/cloudsearch?keywords=${encodeURIComponent(searchQuery)}&limit=3&type=1`);

    const songs = searchData.result?.songs || [];

    if (songs.length === 0) return null;

    // Use the first result as the primary candidate since we searched by "Artist - Song"
    const song = songs[0];

    // 2. Try to get lyrics to find start time
    let startTime = 0;

    if (targetLyric) {
        try {
            const lyricData = await fetchFromApi(`/lyric?id=${song.id}`);
            const lrc = lyricData?.lrc?.lyric;
            if (lrc) {
                const matchTime = findLyricMatch(lrc, targetLyric);
                if (matchTime !== null) {
                    startTime = matchTime;
                }
            }
        } catch (e) {
            console.warn("[MusicService] Lyric fetch failed, defaulting to start.");
        }
    }

    // 3. Construct URL
    // The "outer" URL is generally the most reliable for 3rd party apps if Referrer is handled.
    const directUrl = `https://music.163.com/song/media/outer/url?id=${song.id}.mp3`;

    return {
      url: directUrl,
      startTime: startTime,
      duration: 15, // Play for 15 seconds
      name: song.name,
      artist: song.ar?.[0]?.name || 'Unknown'
    };

  } catch (e) {
    // Gracefully handle failure so the app doesn't crash
    console.warn("[MusicService] Failed to retrieve music data. Music will be disabled for this word.");
    return null;
  }
};

import { GoogleGenAI, Type } from "@google/genai";
import { WordData } from '../types';
import { getSongSegment } from './musicService';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Using Lexica API for "Search" instead of "Generation".
export const searchWordImage = async (word: string): Promise<string | null> => {
  try {
    const query = `minimalist vector illustration ${word} flat design white background`;
    const response = await fetch(`https://lexica.art/api/v1/search?q=${encodeURIComponent(query)}`);

    if (!response.ok) return null;

    const data = await response.json();
    if (data.images && data.images.length > 0) {
      return data.images[0].src;
    }
    return null;
  } catch (error) {
    console.warn(`Image Search failed for ${word}:`, error);
    return null;
  }
};

// NEW: Helper to fetch media for a single word independently
export const fetchMediaForWord = async (word: WordData): Promise<WordData> => {
  const updatedWord = { ...word };
  let hasChanges = false;

  // A. Search Image (Lexica API)
  if (!updatedWord.imageUrl) {
      try {
          const imageUrl = await searchWordImage(updatedWord.word);
          if (imageUrl) {
              updatedWord.imageUrl = imageUrl;
              hasChanges = true;
          }
      } catch (e) {
          console.warn(`Error fetching image for ${updatedWord.word}`, e);
      }
  }

  // B. Match Music (Netease API)
  if (updatedWord.songInfo && !updatedWord.songData) {
      try {
          const songData = await getSongSegment(updatedWord.songInfo, updatedWord.songLyric || '');
          if (songData) {
              updatedWord.songData = songData;
              hasChanges = true;
          }
      } catch (e) {
          console.warn(`Error fetching music for ${updatedWord.word}`, e);
      }
  }

  // Return the updated object only if we found something, otherwise return original to avoid useless state updates
  return hasChanges ? updatedWord : word;
};

export const enrichVocabulary = async (words: string[]): Promise<WordData[]> => {
  if (words.length === 0) return [];

  // Prompt purely for Text Data (Definitions, Music Info, Sentences)
  // Gemini 3 Flash is very fast and has high quotas for text.
  const prompt = `
    I have a list of English vocabulary words: ${words.join(', ')}.

    For EACH word, return a JSON object with:
    1. "word": The word itself (lowercase).
    2. "definition": Concise Simplified Chinese definition.
    3. "partOfSpeech": e.g. noun, verb.
    4. "exampleSentence": A short English sentence with the word replaced by '_______'.
    5. "songLyric": A short, recognizable lyric line containing the word from a VERY FAMOUS song (Taylor Swift, Adele, Justin Bieber, Queen, Disney).
    6. "songInfo": "Artist - Song Name".

    Return a strict JSON array.
  `;

  try {
    // 1. Get Text Data (Fast)
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              word: { type: Type.STRING },
              definition: { type: Type.STRING },
              partOfSpeech: { type: Type.STRING },
              exampleSentence: { type: Type.STRING },
              songLyric: { type: Type.STRING },
              songInfo: { type: Type.STRING }
            },
            required: ["word", "definition", "partOfSpeech", "exampleSentence"]
          }
        }
      }
    });

    const rawData = JSON.parse(response.text || '[]');

    // 2. Map to internal structure and RETURN IMMEDIATELY
    // We do NOT fetch images or music here anymore. We let the UI load first.
    let processedWords: WordData[] = rawData.map((item: any) => ({
      id: crypto.randomUUID(),
      word: item.word.toLowerCase().trim(),
      definition: item.definition,
      exampleSentence: item.exampleSentence,
      partOfSpeech: item.partOfSpeech,
      songLyric: item.songLyric,
      songInfo: item.songInfo,
      correctCount: 0,
      imageUrl: undefined,
      songData: null
    }));

    return processedWords;

  } catch (error) {
    console.error("Gemini API Error:", error);
    throw new Error("生成内容失败，请检查网络或稍后重试。");
  }
};

import React, { useState, useEffect } from 'react';
import { WordInput } from './components/WordInput';
import { QuizSession } from './components/QuizSession';
import { Dashboard } from './components/Dashboard';
import { WordData, AppState } from './types';
import { enrichVocabulary, fetchMediaForWord } from './services/geminiService';
import { Toaster, toast } from 'react-hot-toast';

const STORAGE_KEY = 'lexiweek_data_v1';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.DASHBOARD);
  const [words, setWords] = useState<WordData[]>([]);
  const [loading, setLoading] = useState(false);

  // Load from local storage on mount
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setWords(parsed);
        if (parsed.length === 0) {
          setAppState(AppState.INPUT);
        }
      } catch (e) {
        console.error("Failed to parse saved data", e);
        setAppState(AppState.INPUT);
      }
    } else {
      setAppState(AppState.INPUT);
    }
  }, []);

  // Save to local storage whenever words change
  useEffect(() => {
    if (words.length === 0) {
       // Allow clearing storage if empty
       if (appState === AppState.INPUT) { // Only if we explicitly reset
          localStorage.removeItem(STORAGE_KEY);
       }
       return;
    }

    try {
      // 1. Try to save EVERYTHING including images
      localStorage.setItem(STORAGE_KEY, JSON.stringify(words));
    } catch (e) {
      // 2. If Quota Exceeded, fallback to saving ONLY text data
      if (e instanceof DOMException && (e.name === 'QuotaExceededError' || e.name === 'NS_ERROR_DOM_QUOTA_REACHED')) {
         console.warn("Storage quota exceeded. Saving without images.");
         try {
            const dataToSave = words.map(w => {
              // eslint-disable-next-line @typescript-eslint/no-unused-vars
              const { imageUrl, ...rest } = w;
              return rest;
            });
            localStorage.setItem(STORAGE_KEY, JSON.stringify(dataToSave));
         } catch (retryError) {
            console.error("Critical: Failed to save data even without images", retryError);
         }
      } else {
        console.error("Storage error:", e);
      }
    }
  }, [words, appState]);

  const handleUpdateWord = (wordId: string, updates: Partial<WordData>) => {
    setWords(prev => prev.map(w => {
      if (w.id !== wordId) return w;
      return { ...w, ...updates };
    }));
  };

  const handleWordsSubmit = async (rawWords: string[]) => {
    setLoading(true);
    try {
      // 1. Get Text Data ONLY (This is fast)
      const initialWords = await enrichVocabulary(rawWords);

      // 2. Update State & UI IMMEDIATELY
      setWords(initialWords);
      setAppState(AppState.DASHBOARD);
      toast.success('文本生成完成，正在后台加载图片和音乐...');
      setLoading(false); // Stop the spinner on the input screen

      // 3. Background Process: Fetch Media for each word
      // We trigger these asynchronously so the user can use the app while they load.
      initialWords.forEach(async (word) => {
        try {
          const enrichedWord = await fetchMediaForWord(word);
          // Only trigger a re-render if we actually got new data (image or song)
          if (enrichedWord.imageUrl || enrichedWord.songData) {
             handleUpdateWord(enrichedWord.id, enrichedWord);
          }
        } catch (e) {
          console.error(`Background fetch failed for ${word.word}`, e);
        }
      });

    } catch (error) {
      console.error(error);
      toast.error('处理单词失败，请重试。');
      setLoading(false);
    }
  };

  const handleResetWeek = () => {
    if (window.confirm("确定要重置吗？这将删除当前的进度并开始新的一周。")) {
      setWords([]);
      setAppState(AppState.INPUT);
      localStorage.removeItem(STORAGE_KEY);
    }
  };

  return (
    // Changed min-h-screen to ensure scrolling works when content overflows (like when keyboard is open)
    <div className="min-h-screen w-full bg-slate-50 relative">
      {/* 
        PERFORMANCE FIX: 
        Replaced heavy animated blobs with a static CSS gradient mesh.
      */}
      <div className="fixed inset-0 z-0 bg-gradient-to-br from-indigo-50 via-purple-50 to-pink-50 opacity-80 pointer-events-none"></div>
      <div className="fixed top-0 left-0 w-full h-1 bg-gradient-to-r from-indigo-500 via-purple-500 to-pink-500 z-50"></div>

      {/* Content Container - Allows scrolling */}
      <main className="relative z-10 w-full max-w-4xl mx-auto p-4 sm:p-6 lg:p-8 flex flex-col min-h-screen justify-center">
        {appState === AppState.INPUT && (
          <WordInput 
            onSubmit={handleWordsSubmit} 
            isLoading={loading} 
            hasExistingData={words.length > 0}
            onCancel={words.length > 0 ? () => setAppState(AppState.DASHBOARD) : undefined}
          />
        )}

        {appState === AppState.DASHBOARD && (
          <Dashboard 
            words={words} 
            onStartQuiz={() => setAppState(AppState.QUIZ)}
            onNewWeek={handleResetWeek}
          />
        )}

        {appState === AppState.QUIZ && (
          <QuizSession 
            words={words}
            onComplete={(results) => {
              setAppState(AppState.DASHBOARD);
            }}
            onUpdateWord={handleUpdateWord}
            onExit={() => setAppState(AppState.DASHBOARD)}
          />
        )}
      </main>

      <Toaster position="bottom-center" />
    </div>
  );
};

export default App;

