// Helper to fetch media for a single word independently
export const fetchMediaForWord = async (word: WordData): Promise<WordData> => {
  const updatedWord = { ...word };
  let hasChanges = false;

  // A. Search Image (Lexica API)
  if (!updatedWord.imageUrl) {
      try {
          const imageUrl = await searchWordImage(updatedWord.word);
          if (imageUrl) {
              updatedWord.imageUrl = imageUrl;
              hasChanges = true;
          }
      } catch (e) {
          console.warn(`Error fetching image for ${updatedWord.word}`, e);
      }
  }

  // B. Match Music (iTunes API)
  if (updatedWord.songInfo && !updatedWord.songData) {
      try {
          const songData = await getSongSegment(updatedWord.songInfo, updatedWord.songLyric || '');
          if (songData) {
              updatedWord.songData = songData;
              hasChanges = true;
          }
      } catch (e) {
          console.warn(`Error fetching music for ${updatedWord.word}`, e);
      }
  }

  return hasChanges ? updatedWord : word;
};

// STREAMING Implementation
// Instead of waiting for the full array, we stream NDJSON (Newline Delimited JSON) objects.
export const streamVocabularyEnrichment = async (
  words: string[],
  onWordReceived: (word: WordData) => void
): Promise<void> => {
  if (words.length === 0) return;

  const prompt = `
    I have a list of English vocabulary words: ${words.join(', ')}.

    For EACH word, generate a JSON object.

    IMPORTANT FORMATTING RULES:
    1. Output strictly **NDJSON** (Newline Delimited JSON). 
    2. Write ONE valid JSON object per line.
    3. Do NOT wrap the output in [ ] or a list.
    4. Do NOT use markdown code blocks (like \`\`\`json). Just raw text.

    Schema for each object:
    {
      "word": "string (lowercase)",
      "definition": "string (Concise Simplified Chinese definition)",
      "partOfSpeech": "string (e.g. noun, verb)",
      "exampleSentence": "string (English sentence with the word replaced by '_______')",
      "songLyric": "string (Short recognizable lyric line containing the word from a VERY FAMOUS song like Taylor Swift/Adele/Disney)",
      "songInfo": "string (Artist - Song Name)"
    }
  `;

  try {
    const response = await ai.models.generateContentStream({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      // Note: JSON mode (responseMimeType: "application/json") typically enforces a single JSON object or array.
      // For streaming independent objects (NDJSON), we often get better results with text mode + strict prompting,
      // or we can use JSON mode but we'd have to parse the incremental array construction which is harder.
      // We will stick to text mode with strict prompting for line-by-line processing.
    });

    let buffer = '';

    for await (const chunk of response) {
      const text = chunk.text;
      if (!text) continue;

      buffer += text;

      // Split by newline to find complete JSON objects
      const lines = buffer.split('\n');

      // Keep the last part in the buffer as it might be an incomplete line
      buffer = lines.pop() || '';

      for (const line of lines) {
        processLine(line, onWordReceived);
      }
    }

    // Process any remaining buffer
    if (buffer.trim()) {
      processLine(buffer, onWordReceived);
    }

  } catch (error) {
    console.error("Gemini Streaming Error:", error);
    throw new Error("生成流中断，请重试。");
  }
};

const processLine = (line: string, callback: (word: WordData) => void) => {
  const cleanLine = line.trim();
  if (!cleanLine) return;

  // Cleanup potential markdown artifacts if the model disobeys
  // e.g. removal of ```json , ``` , [ , ] , or trailing commas
  let jsonString = cleanLine
    .replace(/^```json/, '')
    .replace(/^```/, '')
    .replace(/```$/, '')
    .replace(/^\[/, '') // Remove starting array bracket if present
    .replace(/,$/, '')  // Remove trailing comma if present
    .replace(/\]$/, ''); // Remove closing array bracket if present

  try {
    const item = JSON.parse(jsonString);

    // Validate required fields roughly
    if (item.word && item.definition) {
        const wordData: WordData = {
          id: crypto.randomUUID(),
          word: item.word.toLowerCase().trim(),
          definition: item.definition,
          exampleSentence: item.exampleSentence || "No example available.",
          partOfSpeech: item.partOfSpeech || "",
          songLyric: item.songLyric,
          songInfo: item.songInfo,
          correctCount: 0,
          imageUrl: undefined,
          songData: null
        };
        callback(wordData);
    }
  } catch (e) {
    // It's common to have a line that isn't valid JSON during streaming (e.g. empty lines or partials)
    // We just ignore them.
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { WordInput } from './components/WordInput';
import { QuizSession } from './components/QuizSession';
import { Dashboard } from './components/Dashboard';
import { WordData, AppState } from './types';
import { streamVocabularyEnrichment, fetchMediaForWord } from './services/geminiService';
import { Toaster, toast } from 'react-hot-toast';

const STORAGE_KEY = 'lexiweek_data_v1';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.DASHBOARD);
  const [words, setWords] = useState<WordData[]>([]);
  const [loading, setLoading] = useState(false);

  // Ref to track if we have already switched to dashboard during streaming
  const hasSwitchedToDashboardRef = useRef(false);

  // Load from local storage on mount
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setWords(parsed);
        if (parsed.length === 0) {
          setAppState(AppState.INPUT);
        }
      } catch (e) {
        console.error("Failed to parse saved data", e);
        setAppState(AppState.INPUT);
      }
    } else {
      setAppState(AppState.INPUT);
    }
  }, []);

  // Save to local storage whenever words change
  useEffect(() => {
    if (words.length === 0) {
       // Allow clearing storage if empty
       if (appState === AppState.INPUT) { 
          localStorage.removeItem(STORAGE_KEY);
       }
       return;
    }

    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(words));
    } catch (e) {
      if (e instanceof DOMException && (e.name === 'QuotaExceededError' || e.name === 'NS_ERROR_DOM_QUOTA_REACHED')) {
         console.warn("Storage quota exceeded. Saving without images.");
         try {
            const dataToSave = words.map(w => {
              // eslint-disable-next-line @typescript-eslint/no-unused-vars
              const { imageUrl, ...rest } = w;
              return rest;
            });
            localStorage.setItem(STORAGE_KEY, JSON.stringify(dataToSave));
         } catch (retryError) { /* ignore */ }
      }
    }
  }, [words, appState]);

  const handleUpdateWord = (wordId: string, updates: Partial<WordData>) => {
    setWords(prev => prev.map(w => {
      if (w.id !== wordId) return w;
      return { ...w, ...updates };
    }));
  };

  const handleWordsSubmit = async (rawWords: string[]) => {
    setLoading(true);
    hasSwitchedToDashboardRef.current = false;

    // Clear previous words if any, to show fresh start
    setWords([]);

    try {
      // Stream text data
      await streamVocabularyEnrichment(rawWords, async (textWord) => {
        // 1. Add new word to state immediately
        setWords(prev => [...prev, textWord]);

        // 2. Switch to dashboard as soon as the FIRST word arrives
        if (!hasSwitchedToDashboardRef.current) {
          hasSwitchedToDashboardRef.current = true;
          setLoading(false);
          setAppState(AppState.DASHBOARD);
          toast.success('开始生成单词...');
        }

        // 3. Trigger background media fetch for this specific word
        try {
          const enrichedWord = await fetchMediaForWord(textWord);
          // Only update if we actually got media
          if (enrichedWord.imageUrl || enrichedWord.songData) {
            handleUpdateWord(enrichedWord.id, enrichedWord);
          }
        } catch (e) {
          console.error(`Media fetch error for ${textWord.word}`, e);
        }
      });

    } catch (error) {
      console.error(error);
      toast.error('连接超时，请检查网络。');
      setLoading(false);
    }
  };

  const handleResetWeek = () => {
    if (window.confirm("确定要重置吗？这将删除当前的进度并开始新的一周。")) {
      setWords([]);
      setAppState(AppState.INPUT);
      localStorage.removeItem(STORAGE_KEY);
    }
  };

  return (
    <div className="min-h-screen w-full bg-slate-50 relative">
      {/* Background Gradient */}
      <div className="fixed inset-0 z-0 bg-gradient-to-br from-indigo-50 via-purple-50 to-pink-50 opacity-80 pointer-events-none"></div>
      <div className="fixed top-0 left-0 w-full h-1 bg-gradient-to-r from-indigo-500 via-purple-500 to-pink-500 z-50"></div>

      <main className="relative z-10 w-full max-w-4xl mx-auto p-4 sm:p-6 lg:p-8 flex flex-col min-h-screen justify-center">
        {appState === AppState.INPUT && (
          <WordInput 
            onSubmit={handleWordsSubmit} 
            isLoading={loading} 
            hasExistingData={words.length > 0}
            onCancel={words.length > 0 ? () => setAppState(AppState.DASHBOARD) : undefined}
          />
        )}

        {appState === AppState.DASHBOARD && (
          <Dashboard 
            words={words} 
            onStartQuiz={() => setAppState(AppState.QUIZ)}
            onNewWeek={handleResetWeek}
          />
        )}

        {appState === AppState.QUIZ && (
          <QuizSession 
            words={words}
            onComplete={(results) => {
              setAppState(AppState.DASHBOARD);
            }}
            onUpdateWord={handleUpdateWord}
            onExit={() => setAppState(AppState.DASHBOARD)}
          />
        )}
      </main>

      <Toaster position="bottom-center" />
    </div>
  );
};

export default App;

