import { GoogleGenAI } from "@google/genai";
import { WordData } from '../types';
import { getSongSegment } from './musicService';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Using Lexica API for "Search" instead of "Generation".
export const searchWordImage = async (word: string): Promise<string | null> => {
  try {
    const query = `minimalist vector illustration ${word} flat design white background`;
    const response = await fetch(`https://lexica.art/api/v1/search?q=${encodeURIComponent(query)}`);

    if (!response.ok) return null;

    const data = await response.json();
    if (data.images && data.images.length > 0) {
      return data.images[0].src;
    }
    return null;
  } catch (error) {
    console.warn(`Image Search failed for ${word}:`, error);
    return null;
  }
};

// Helper to fetch media for a single word independently
// Now supports trying specific candidate index or auto-fallback
export const fetchMediaForWord = async (word: WordData, forceIndex?: number): Promise<WordData> => {
  const updatedWord = { ...word };
  let hasChanges = false;

  // A. Search Image (Lexica API)
  if (!updatedWord.imageUrl) {
      try {
          const imageUrl = await searchWordImage(updatedWord.word);
          if (imageUrl) {
              updatedWord.imageUrl = imageUrl;
              hasChanges = true;
          }
      } catch (e) {
          console.warn(`Error fetching image for ${updatedWord.word}`, e);
      }
  }

  // B. Match Music (iTunes API) with Fallback Logic
  // If forceIndex is provided, we try that specific one.
  // Otherwise, we look for the first valid song if we don't have one yet.
  if (updatedWord.songCandidates && updatedWord.songCandidates.length > 0) {

      let startIndex = forceIndex !== undefined ? forceIndex : (updatedWord.activeCandidateIndex || 0);

      // If forcing an index, just try that one.
      // If automatic (forceIndex undefined) and we already have songData, skip.
      if (forceIndex !== undefined || !updatedWord.songData) {

          // Loop through candidates starting from startIndex
          for (let i = startIndex; i < updatedWord.songCandidates.length; i++) {
              const candidate = updatedWord.songCandidates[i];
              try {
                  const songData = await getSongSegment(candidate.songInfo, candidate.songLyric);
                  if (songData) {
                      updatedWord.songData = songData;
                      updatedWord.songInfo = candidate.songInfo;
                      updatedWord.songLyric = candidate.songLyric;
                      updatedWord.activeCandidateIndex = i;
                      hasChanges = true;
                      break; // Found a working song, stop looking
                  } else {
                     // If specifically requested index failed, and we are not in a loop, we might want to continue?
                     // For now, if auto-loading, we continue. If forced, we stop after one attempt or continue?
                     // Let's continue to find the *next available* valid song.
                  }
              } catch (e) {
                  console.warn(`Error fetching music for candidate ${i} (${updatedWord.word})`, e);
              }

              // If we were forcing a specific index and it failed, we usually want to try the next one anyway
              // to ensure the user gets *some* music.
          }
      }
  }

  return hasChanges ? updatedWord : word;
};

