// Helper for JSONP to bypass CORS on iTunes API
let jsonpCounter = 0;
const fetchJsonp = (url: string): Promise<any> => {
  return new Promise((resolve, reject) => {
    const callbackName = `jsonp_callback_${Date.now()}_${jsonpCounter++}`;

    // Create script
    const script = document.createElement('script');
    // iTunes requires the callback parameter to be named 'callback'
    const separator = url.includes('?') ? '&' : '?';
    script.src = `${url}${separator}callback=${callbackName}`;
    script.async = true;

    // Define global callback
    (window as any)[callbackName] = (data: any) => {
      cleanup();
      resolve(data);
    };

    // Error handling
    script.onerror = () => {
      cleanup();
      reject(new Error(`JSONP request failed for ${url}`));
    };

    // Cleanup function
    const cleanup = () => {
      if (document.body.contains(script)) {
        document.body.removeChild(script);
      }
      delete (window as any)[callbackName];
    };

    document.body.appendChild(script);
  });
};

export const getSongSegment = async (searchQuery: string, targetLyric?: string): Promise<SongPlayData | null> => {
  try {
    // iTunes Search API
    // We search by "Artist SongName" which usually gives the best match.
    // "entity=song" ensures we get music tracks.
    // "limit=1" keeps it fast.

    // Clean up the query: replace " - " with space for better iTunes search
    const cleanQuery = searchQuery.replace(/ - /g, ' ');
    const term = encodeURIComponent(cleanQuery);

    const url = `https://itunes.apple.com/search?term=${term}&media=music&entity=song&limit=1`;

    // Use JSONP to avoid CORS issues
    const data = await fetchJsonp(url);

    if (!data || data.resultCount === 0) return null;

    const track = data.results[0];

    // iTunes previews are typically 30 seconds.
    // User requested "play that sentence then stop".
    // Without precise lyric timestamps, 10-12 seconds is the sweet spot for a Chorus phrase.
    return {
      url: track.previewUrl,
      startTime: 0, 
      duration: 10, // CHANGED: Shortened from 29.5 to 10 seconds
      name: track.trackName,
      artist: track.artistName
    };

  } catch (e) {
    console.warn("[MusicService] iTunes match failed:", e);
    return null;
  }
};

