// CORS Proxy to access Netease APIs from the browser
const CORS_PROXY = 'https://corsproxy.io/?';

interface LrcLine {
  time: number; // in seconds
  text: string;
}

// Parse standard LRC format: [mm:ss.xx] lyric text
const parseLrc = (lrcText: string): LrcLine[] => {
  const lines: LrcLine[] = [];
  const regex = /\[(\d{2}):(\d{2})\.(\d{2,3})\](.*)/;

  lrcText.split('\n').forEach(line => {
    const match = line.match(regex);
    if (match) {
      const minutes = parseInt(match[1], 10);
      const seconds = parseInt(match[2], 10);
      const ms = parseInt(match[3], 10);
      const totalSeconds = minutes * 60 + seconds + ms / (match[3].length === 3 ? 1000 : 100);
      lines.push({
        time: totalSeconds,
        text: match[4].trim()
      });
    }
  });
  return lines;
};

// Search Netease for a song ID
const searchNetease = async (query: string): Promise<any | null> => {
  try {
    const url = `http://music.163.com/api/search/pc?s=${encodeURIComponent(query)}&type=1&limit=1`;
    const response = await fetch(CORS_PROXY + encodeURIComponent(url));
    const data = await response.json();
    if (data.code === 200 && data.result && data.result.songs && data.result.songs.length > 0) {
      return data.result.songs[0];
    }
    return null;
  } catch (e) {
    console.warn("Netease search failed", e);
    return null;
  }
};

// Get Lyrics for a song ID
const getLyrics = async (id: number): Promise<string | null> => {
  try {
    const url = `http://music.163.com/api/song/lyric?id=${id}&lv=1&kv=1&tv=-1`;
    const response = await fetch(CORS_PROXY + encodeURIComponent(url));
    const data = await response.json();
    if (data.code === 200 && data.lrc && data.lrc.lyric) {
      return data.lrc.lyric;
    }
    return null;
  } catch (e) {
    console.warn("Netease lyric fetch failed", e);
    return null;
  }
};

export const getSongSegment = async (searchQuery: string, targetLyricWord?: string): Promise<SongPlayData | null> => {
  try {
    // 1. Search for the song
    const cleanQuery = searchQuery.replace(/ - /g, ' ');
    const song = await searchNetease(cleanQuery);

    if (!song) return null;

    // 2. Get the full audio URL (Using the Netease redirect interface, usually works with no-referrer)
    // We strictly use http protocol for the initial link, browser might upgrade it.
    const audioUrl = `http://music.163.com/song/media/outer/url?id=${song.id}.mp3`;

    // 3. Get and Parse Lyrics
    const lrcText = await getLyrics(song.id);
    let startTime = 0;
    let duration = 10; // Default fallback duration
    let matchedLyric = song.name;

    if (lrcText && targetLyricWord) {
      const lrcLines = parseLrc(lrcText);
      const wordLower = targetLyricWord.toLowerCase().trim();

      // Find the first line that contains the target word
      const matchIndex = lrcLines.findIndex(line => line.text.toLowerCase().includes(wordLower));

      if (matchIndex !== -1) {
        const startLine = lrcLines[matchIndex];
        // Calculate duration based on when the NEXT line starts
        // We add a small buffer (0.5s) to ensure the sentence finishes but doesn't run too long into the next
        const nextLine = lrcLines[matchIndex + 1];

        startTime = startLine.time;
        matchedLyric = startLine.text;

        if (nextLine) {
          duration = nextLine.time - startLine.time;
          // Cap duration between 3s and 12s to avoid weird cuts
          duration = Math.max(3, Math.min(duration, 12));
        } else {
          duration = 8; // Default if last line
        }

        // Slight adjustment: start 0.2s early to catch the breath/attack
        startTime = Math.max(0, startTime - 0.2);
      } else {
          // If word not found in lyric text, try to play chorus (usually around 30% - 40% into song or 60s)
          // Since we don't have chorus metadata, we fall back to beginning or a guess.
          // Let's just play from 0 if no match, or keep default.
          console.log("Word not found in lyrics, using default start.");
      }
    }

    return {
      url: audioUrl,
      startTime: startTime,
      duration: duration,
      name: song.name,
      artist: song.artists?.[0]?.name || "Unknown Artist"
    };

  } catch (e) {
    console.warn("[MusicService] Netease flow failed:", e);
    return null;
  }
};

