const tryNeteaseStrategy = async (searchQuery: string, targetLyricWord?: string): Promise<SongPlayData | null> => {
  try {
    const cleanQuery = searchQuery.replace(/ - /g, ' ');
    // 1. Search
    const searchUrl = `http://music.163.com/api/search/pc?s=${encodeURIComponent(cleanQuery)}&type=1&limit=1`;
    const searchRes = await fetch(CORS_PROXY + encodeURIComponent(searchUrl));
    const searchData = await searchRes.json();

    if (searchData.code !== 200 || !searchData.result?.songs?.[0]) return null;
    const song = searchData.result.songs[0];

    // 2. Check Playability (Try to fetch headers of the MP3 to see if it exists/404)
    // IMPORTANT: Use HTTPS for the mp3 link to avoid Mixed Content errors
    const audioUrl = `https://music.163.com/song/media/outer/url?id=${song.id}.mp3`;

    // Optional: Verify url exists via HEAD request if needed, but skipping for speed.

    // 3. Get Lyrics
    const lrcUrl = `http://music.163.com/api/song/lyric?id=${song.id}&lv=1&kv=1&tv=-1`;
    const lrcRes = await fetch(CORS_PROXY + encodeURIComponent(lrcUrl));
    const lrcData = await lrcRes.json();

    let startTime = 0;
    let duration = 10;

    if (lrcData.code === 200 && lrcData.lrc?.lyric && targetLyricWord) {
      const lrcLines = parseLrc(lrcData.lrc.lyric);
      const wordLower = targetLyricWord.toLowerCase().trim();
      const matchIndex = lrcLines.findIndex(line => line.text.toLowerCase().includes(wordLower));

      if (matchIndex !== -1) {
        const startLine = lrcLines[matchIndex];
        const nextLine = lrcLines[matchIndex + 1];
        startTime = startLine.time;
        if (nextLine) {
          duration = nextLine.time - startLine.time;
          duration = Math.max(3, Math.min(duration, 12));
        } else {
          duration = 8;
        }
        startTime = Math.max(0, startTime - 0.2);
      }
    }

    return {
      url: audioUrl,
      startTime,
      duration,
      name: song.name,
      artist: song.artists?.[0]?.name || "Unknown"
    };
  } catch (e) {
    console.warn("Netease strategy failed:", e);
    return null;
  }
};

