const CORS_PROXY = 'https://corsproxy.io/?';

// JSONP for iTunes
let jsonpCounter = 0;
const fetchJsonp = (url: string): Promise<any> => {
  return new Promise((resolve, reject) => {
    const callbackName = `jsonp_callback_${Date.now()}_${jsonpCounter++}`;
    const script = document.createElement('script');
    const separator = url.includes('?') ? '&' : '?';
    script.src = `${url}${separator}callback=${callbackName}`;
    script.async = true;
    (window as any)[callbackName] = (data: any) => {
      cleanup();
      resolve(data);
    };
    script.onerror = () => {
      cleanup();
      reject(new Error(`JSONP request failed for ${url}`));
    };
    const cleanup = () => {
      if (document.body.contains(script)) {
        document.body.removeChild(script);
      }
      delete (window as any)[callbackName];
    };
    document.body.appendChild(script);
  });
};

// ==========================================
// STRATEGY A: NETEASE (Precision w/ Lyrics)
// ==========================================

interface LrcLine {
  time: number;
  text: string;
}

const parseLrc = (lrcText: string): LrcLine[] => {
  const lines: LrcLine[] = [];
  const regex = /\[(\d{2}):(\d{2})\.(\d{2,3})\](.*)/;
  lrcText.split('\n').forEach(line => {
    const match = line.match(regex);
    if (match) {
      const minutes = parseInt(match[1], 10);
      const seconds = parseInt(match[2], 10);
      const ms = parseInt(match[3], 10);
      const totalSeconds = minutes * 60 + seconds + ms / (match[3].length === 3 ? 1000 : 100);
      lines.push({ time: totalSeconds, text: match[4].trim() });
    }
  });
  return lines;
};

const tryNeteaseStrategy = async (searchQuery: string, targetLyricWord?: string): Promise<SongPlayData | null> => {
  try {
    const cleanQuery = searchQuery.replace(/ - /g, ' ');
    // 1. Search
    const searchUrl = `http://music.163.com/api/search/pc?s=${encodeURIComponent(cleanQuery)}&type=1&limit=1`;
    const searchRes = await fetch(CORS_PROXY + encodeURIComponent(searchUrl));
    const searchData = await searchRes.json();

    if (searchData.code !== 200 || !searchData.result?.songs?.[0]) return null;
    const song = searchData.result.songs[0];

    // 2. Check Playability (Try to fetch headers of the MP3 to see if it exists/404)
    // IMPORTANT: Use HTTPS for the mp3 link to avoid Mixed Content errors
    const audioUrl = `https://music.163.com/song/media/outer/url?id=${song.id}.mp3`;

    // Optional: Verify url exists via HEAD request if needed, but skipping for speed.

    // 3. Get Lyrics
    const lrcUrl = `http://music.163.com/api/song/lyric?id=${song.id}&lv=1&kv=1&tv=-1`;
    const lrcRes = await fetch(CORS_PROXY + encodeURIComponent(lrcUrl));
    const lrcData = await lrcRes.json();

    let startTime = 0;
    let duration = 10;

    if (lrcData.code === 200 && lrcData.lrc?.lyric && targetLyricWord) {
      const lrcLines = parseLrc(lrcData.lrc.lyric);
      const wordLower = targetLyricWord.toLowerCase().trim();
      const matchIndex = lrcLines.findIndex(line => line.text.toLowerCase().includes(wordLower));

      if (matchIndex !== -1) {
        const startLine = lrcLines[matchIndex];
        const nextLine = lrcLines[matchIndex + 1];
        startTime = startLine.time;
        if (nextLine) {
          duration = nextLine.time - startLine.time;
          duration = Math.max(3, Math.min(duration, 12));
        } else {
          duration = 8;
        }
        startTime = Math.max(0, startTime - 0.2);
      }
    }

    return {
      url: audioUrl,
      startTime,
      duration,
      name: song.name,
      artist: song.artists?.[0]?.name || "Unknown"
    };
  } catch (e) {
    console.warn("Netease strategy failed:", e);
    return null;
  }
};

// ==========================================
// STRATEGY B: ITUNES (Reliability Fallback)
// ==========================================

const tryItunesStrategy = async (searchQuery: string): Promise<SongPlayData | null> => {
  try {
    const cleanQuery = searchQuery.replace(/ - /g, ' ');
    const term = encodeURIComponent(cleanQuery);
    const url = `https://itunes.apple.com/search?term=${term}&media=music&entity=song&limit=1`;

    const data = await fetchJsonp(url);
    if (!data || data.resultCount === 0) return null;

    const track = data.results[0];
    return {
      url: track.previewUrl,
      startTime: 0,
      duration: 15, // Play 15s of the preview (usually Chorus)
      name: track.trackName,
      artist: track.artistName
    };
  } catch (e) {
    console.warn("iTunes strategy failed:", e);
    return null;
  }
};

