// MAIN EXPORT
// ==========================================

export const getSongSegment = async (searchQuery: string, targetLyricWord?: string): Promise<SongPlayData | null> => {
  // 1. Try Netease first (for precision)
  // We only use Netease if we have a target word to look for in lyrics, otherwise straight to iTunes is safer
  if (targetLyricWord) {
    const neteaseResult = await tryNeteaseStrategy(searchQuery, targetLyricWord);
    if (neteaseResult) {
      console.log(`[Music] Using Netease for ${searchQuery}`);
      return neteaseResult;
    }
  }

  // 2. Fallback to iTunes (for reliability)
  console.log(`[Music] Falling back to iTunes for ${searchQuery}`);
  return await tryItunesStrategy(searchQuery);
};

