// Helper to calculate match score
const calculateMatchScore = (lyricLine: string, targetWord: string): number => {
  const lowerLine = lyricLine.toLowerCase();
  const lowerWord = targetWord.toLowerCase();
  if (lowerLine.includes(lowerWord)) return 1;
  return 0;
};

const tryNeteaseStrategy = async (searchQuery: string, targetLyricWord?: string): Promise<SongPlayData | null> => {
  try {
    const cleanQuery = searchQuery.replace(/ - /g, ' ');
    // 1. Search (Fetch more results to filter VIP)
    // type=1: Single song
    const searchUrl = `http://music.163.com/api/search/pc?s=${encodeURIComponent(cleanQuery)}&type=1&limit=6`;
    const searchRes = await fetch(CORS_PROXY + encodeURIComponent(searchUrl));
    const searchData = await searchRes.json();

    if (searchData.code !== 200 || !searchData.result?.songs) return null;

    const songs = searchData.result.songs;

    // 2. Iterate through songs to find a valid one
    // Priority: Playable (fee!=1/4) AND Has Lyrics Match -> Playable -> Just First
    for (const song of songs) {
        // Fee logic: 0=Free, 8=Free(LowQ), 1=VIP, 4=Paid
        // We skip VIP (1) and Paid (4) if possible.
        const isFree = song.fee === 0 || song.fee === 8;

        // If it's strictly VIP, we might still be able to play 30s preview via some endpoints, 
        // but standard hack link fails. Let's try to stick to free.
        // However, sometimes popular songs are all VIP.
        // We will prioritize Free songs.

        if (!isFree) continue;

        // Fetch Lyrics
        try {
            const lrcUrl = `http://music.163.com/api/song/lyric?id=${song.id}&lv=1&kv=1&tv=-1`;
            const lrcRes = await fetch(CORS_PROXY + encodeURIComponent(lrcUrl));
            const lrcData = await lrcRes.json();

            if (lrcData.code === 200 && lrcData.lrc?.lyric) {
                 const lrcLines = parseLrc(lrcData.lrc.lyric);
                 let matchIndex = -1;

                 if (targetLyricWord) {
                    const wordLower = targetLyricWord.toLowerCase().trim();
                    // Try exact match first
                    matchIndex = lrcLines.findIndex(line => {
                        const words = line.text.toLowerCase().split(/[^a-z]+/);
                        return words.includes(wordLower);
                    });

                    // If no exact match, try substring
                    if (matchIndex === -1) {
                        matchIndex = lrcLines.findIndex(line => line.text.toLowerCase().includes(wordLower));
                    }
                 }

                 // If we found the word, this is the Perfect Candidate
                 if (matchIndex !== -1) {
                    const startLine = lrcLines[matchIndex];
                    const nextLine = lrcLines[matchIndex + 1];
                    let duration = 8;
                    if (nextLine) {
                        duration = nextLine.time - startLine.time;
                        // Clamp duration
                        duration = Math.max(3, Math.min(duration, 15));
                    }

                    return {
                        url: `https://music.163.com/song/media/outer/url?id=${song.id}.mp3`,
                        startTime: Math.max(0, startLine.time - 0.5), // Start slightly earlier
                        duration: duration,
                        name: song.name,
                        artist: song.artists?.[0]?.name || "Unknown"
                    };
                 }
            }
        } catch (err) {
            console.warn(`Failed to check lyrics for song ${song.id}`, err);
        }
    }

    // If loop finishes and no perfect match, we might return null to let fallback handle it
    // Or we could pick the first free song and play from 0?
    // Let's return null to trigger iTunes fallback which is safer for "Just playing something"
    return null;

  } catch (e) {
    console.warn("Netease strategy failed:", e);
    return null;
  }
};

