      console.warn(`[Music] No results found on iTunes for: ${cleanQuery}`);
      return null;
    }

    const track = data.results[0];

    // 4. Return formatted data
    // iTunes previews are usually 30 seconds.
    // Since we don't have timestamp data, we play from the beginning of the preview.
    // The Gemini Prompt is optimized to suggest songs where the word is in the Chorus,
    // which is what previews usually contain.
    return {
      url: track.previewUrl, // .m4a file, high quality, highly cacheable
      startTime: 0,
      duration: 29, // Play almost the full preview
      name: track.trackName,
      artist: track.artistName
    };

  } catch (e) {
    console.error("[Music] iTunes strategy error:", e);
    return null;
  }
};

