// ==========================================
// CONFIG
// ==========================================

const PROXY_BASE = 'http://localhost:3001';

// ==========================================
// UTILS
// ==========================================

// JSONP for iTunes
let jsonpCounter = 0;
const fetchJsonp = (url: string): Promise<any> => {
  return new Promise((resolve, reject) => {
    const callbackName = `jsonp_callback_${Date.now()}_${jsonpCounter++}`;
    const script = document.createElement('script');
    const separator = url.includes('?') ? '&' : '?';
    script.src = `${url}${separator}callback=${callbackName}`;
    script.async = true;
    (window as any)[callbackName] = (data: any) => {
      cleanup();
      resolve(data);
    };
    script.onerror = () => {
      cleanup();
      reject(new Error(`JSONP request failed for ${url}`));
    };
    const cleanup = () => {
      if (document.body.contains(script)) {
        document.body.removeChild(script);
      }
      delete (window as any)[callbackName];
    };
    document.body.appendChild(script);
  });
};

interface LrcLine {
  time: number;
  text: string;
}

const parseLrc = (lrcText: string): LrcLine[] => {
  const lines: LrcLine[] = [];
  const regex = /\[(\d{2}):(\d{2})\.(\d{2,3})\](.*)/;
  lrcText.split('\n').forEach(line => {
    const match = line.match(regex);
    if (match) {
      const minutes = parseInt(match[1], 10);
      const seconds = parseInt(match[2], 10);
      const ms = parseInt(match[3], 10);
      const totalSeconds = minutes * 60 + seconds + ms / (match[3].length === 3 ? 1000 : 100);
      lines.push({ time: totalSeconds, text: match[4].trim() });
    }
  });
  return lines;
};

// ==========================================
// STRATEGY A: LOCAL PROXY (Netease via Node)
// ==========================================

const tryLocalProxyStrategy = async (searchQuery: string, targetWord: string): Promise<SongPlayData | null> => {
  try {
    // 1. Search
    const cleanQuery = searchQuery.replace(/ - /g, ' ');
    const searchRes = await fetch(`${PROXY_BASE}/search?q=${encodeURIComponent(cleanQuery)}`);

    // If the proxy server is not running, fetch will throw immediately
    if (!searchRes.ok) throw new Error("Proxy response not ok");

    const searchData = await searchRes.json();
    if (!searchData.result?.songs) return null;

    const songs = searchData.result.songs;

    // 2. Iterate songs to find one with matching lyrics
    for (const song of songs) {
       // We don't need to worry about VIP too much if we are streaming via proxy (sometimes works),
       // but ideally we still prefer free songs.

       try {
          const lrcRes = await fetch(`${PROXY_BASE}/lyric?id=${song.id}`);
          const lrcData = await lrcRes.json();

          if (lrcData.lrc?.lyric) {
             const lrcLines = parseLrc(lrcData.lrc.lyric);
             const wordLower = targetWord.toLowerCase().trim();

             // Find line
             const matchIndex = lrcLines.findIndex(line => 
                 line.text.toLowerCase().includes(wordLower)
             );

             if (matchIndex !== -1) {
                const startLine = lrcLines[matchIndex];
                const nextLine = lrcLines[matchIndex + 1];
                let duration = 10;

                if (nextLine) {
                   duration = nextLine.time - startLine.time;
                   duration = Math.max(3, Math.min(duration, 15)); // Clamp 3s to 15s
                }

                return {
                    // Use the proxy stream endpoint to avoid 403 Forbidden
                    url: `${PROXY_BASE}/stream?id=${song.id}`,
                    startTime: Math.max(0, startLine.time - 0.5),
                    duration: duration,
                    name: song.name,
                    artist: song.artists?.[0]?.name || "Unknown"
                };
             }
          }
       } catch (innerErr) {
           console.warn(`[Proxy] Failed checking song ${song.id}`, innerErr);
       }
    }

    return null;
  } catch (e) {
    // Usually connection refused if server not running
    return null;
  }
};

// ==========================================
// STRATEGY B: ITUNES (Fallback)
// ==========================================

const tryItunesStrategy = async (searchQuery: string): Promise<SongPlayData | null> => {
  try {
    const cleanQuery = searchQuery.replace(/ - /g, ' ').replace(/\(.*\)/, '').trim();
    const term = encodeURIComponent(cleanQuery);
    const url = `https://itunes.apple.com/search?term=${term}&media=music&entity=song&limit=1`;

    const data = await fetchJsonp(url);
    if (!data || data.resultCount === 0 || !data.results[0]) return null;

    const track = data.results[0];
    return {
      url: track.previewUrl,
      startTime: 0,
      duration: 29, 
      name: track.trackName,
      artist: track.artistName
    };
  } catch (e) {
    return null;
  }
};

// ==========================================
// MAIN EXPORT
// ==========================================

export const getSongSegment = async (searchQuery: string, targetWord?: string): Promise<SongPlayData | null> => {
  // 1. Try Local Proxy (Netease) if target word is provided (needed for lyric matching)
  if (targetWord) {
     const proxyResult = await tryLocalProxyStrategy(searchQuery, targetWord);
     if (proxyResult) {
        console.log(`[Music] 🟢 Using Local Proxy for: ${searchQuery}`);
        return proxyResult;
     }
  }

  // 2. Fallback to iTunes
  console.log(`[Music] 🟡 Falling back to iTunes for: ${searchQuery}`);
  return await tryItunesStrategy(searchQuery);
};

