import { GoogleGenAI } from "@google/genai";
import { WordData } from '../types';
import { getSongSegment } from './musicService';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// ==========================================
// CONCURRENCY CONTROL & UTILS
// ==========================================

const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

/**
 * A simple async queue to limit concurrent API calls.
 * This ensures we don't fire 20 image generation requests at once.
 */
class RequestQueue {
  private queue: (() => Promise<void>)[] = [];
  private working = 0;
  private limit: number;
  private timeBetweenRequests: number;

  constructor(concurrencyLimit: number, delayMs: number) {
    this.limit = concurrencyLimit;
    this.timeBetweenRequests = delayMs;
  }

  enqueue<T>(task: () => Promise<T>): Promise<T> {
    return new Promise((resolve, reject) => {
      this.queue.push(async () => {
        try {
          const result = await task();
          resolve(result);
        } catch (e) {
          reject(e);
        }
      });
      this.process();
    });
  }

  private async process() {
    if (this.working >= this.limit || this.queue.length === 0) return;

    this.working++;
    const task = this.queue.shift();

    if (task) {
      await task();
      // Enforce a gap between requests to respect Rate Limits (RPM)
      if (this.queue.length > 0) {
        await delay(this.timeBetweenRequests);
      }
    }

    this.working--;
    this.process();
  }
}

// Limit to 1 request at a time, with 1.5 seconds gap between them.
// This is conservative but safe for the free tier.
const imageGenerationQueue = new RequestQueue(1, 1500);

// ==========================================
// IMAGE GENERATION
// ==========================================

const callGeminiImage = async (prompt: string, attempt = 1): Promise<string | null> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [{ text: prompt }]
      }
    });

    if (response.candidates && response.candidates.length > 0) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) {
          return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
        }
      }
    }
    return null;
  } catch (error: any) {
    // Check for rate limit errors (429) or temporary server errors (503)
    const isRateLimit = error.status === 429 || (error.message && error.message.includes('429'));
    const isServerOverload = error.status === 503;

    if ((isRateLimit || isServerOverload) && attempt <= 3) {
      const waitTime = 2000 * Math.pow(2, attempt - 1); // Exponential backoff: 2s, 4s, 8s
      console.warn(`Gemini 429/503 hit. Retrying in ${waitTime}ms (Attempt ${attempt})...`);
      await delay(waitTime);
      return callGeminiImage(prompt, attempt + 1);
    }

    throw error; // Let the caller handle non-retryable errors
  }
};

export const generateWordImage = async (word: string): Promise<string | null> => {
  // Wrap the entire logic in the Queue
  return imageGenerationQueue.enqueue(async () => {
    // 1. Try Gemini
    try {
