export const fetchMediaForWord = async (word: WordData): Promise<WordData> => {
  const updatedWord = { ...word };
  let hasChanges = false;

  // Only generate Image now. No more music fetching.
  if (!updatedWord.imageUrl) {
      const imageUrl = await generateWordImage(updatedWord.word);
      if (imageUrl) {
          updatedWord.imageUrl = imageUrl;
          hasChanges = true;
      }
  }

  return hasChanges ? updatedWord : word;
};

// STREAMING Implementation
export const streamVocabularyEnrichment = async (
  words: string[],
  onWordReceived: (word: WordData) => void
): Promise<void> => {
  if (words.length === 0) return;

  const prompt = `
    I have a list of English vocabulary words: ${words.join(', ')}.

    For EACH word, generate a JSON object.

    IMPORTANT FORMATTING RULES:
    1. Output strictly **NDJSON** (Newline Delimited JSON). 
    2. Write ONE valid JSON object per line.
    3. Do NOT wrap the output in [ ] or a list.

    Schema for each object:
    {
      "word": "string (lowercase)",
      "definition": "string (Concise Simplified Chinese definition)",
      "partOfSpeech": "string (e.g. noun, verb)",
      "exampleSentence": "string (English sentence with the word replaced by '_______')",
      "quote": {
        "english": "string (A short, witty joke OR a common proverb/idiom that uses this word. Must be under 25 words.)",
        "chinese": "string (Translation of the quote in Chinese)"
      }
    }

    INSTRUCTIONS FOR 'quote':
    - It must be fun or insightful.
    - If the word is common, use a famous proverb.
    - If the word is obscure, use a short, clean joke.
    - The word itself MUST appear in the English quote.
  `;

  try {
    const response = await ai.models.generateContentStream({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });

    let buffer = '';

    for await (const chunk of response) {
      const text = chunk.text;
      if (!text) continue;

      buffer += text;

      const lines = buffer.split('\n');
      buffer = lines.pop() || '';

      for (const line of lines) {
        processLine(line, onWordReceived);
      }
    }

    if (buffer.trim()) {
      processLine(buffer, onWordReceived);
    }

  } catch (error) {
    console.error("Gemini Streaming Error:", error);
    throw new Error("生成流中断，请重试。");
  }
};

const processLine = (line: string, callback: (word: WordData) => void) => {
  const cleanLine = line.trim();
  if (!cleanLine) return;

  let jsonString = cleanLine
    .replace(/^```json/, '')
    .replace(/^```/, '')
    .replace(/```$/, '')
    .replace(/^\[/, '') 
    .replace(/,$/, '')  
    .replace(/\]$/, '');

  try {
    const item = JSON.parse(jsonString);

    if (item.word && item.definition) {
        // Handle legacy string format if necessary, though we prefer object now
        let quoteObj = undefined;
        if (item.quote) {
          if (typeof item.quote === 'string') {
             quoteObj = { english: item.quote, chinese: '' };
          } else {
             quoteObj = item.quote;
          }
        }

        const wordData: WordData = {
          id: crypto.randomUUID(),
          word: item.word.toLowerCase().trim(),
          definition: item.definition,
          exampleSentence: item.exampleSentence || "No example available.",
          partOfSpeech: item.partOfSpeech || "",
          quote: quoteObj, 

          correctCount: 0,
          imageUrl: undefined,
        };
        callback(wordData);
    }
  } catch (e) {
    // Ignore invalid lines
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { WordData, QuizResult } from '../types';
import { playSuccessSound, playErrorSound, playVictorySound, speakText, resumeAudioContext } from '../services/audioService';

interface QuizSessionProps {
  words: WordData[];
  onComplete: (results: QuizResult[]) => void;
  onUpdateWord: (id: string, updates: Partial<WordData>) => void;
  onExit: () => void;
}

type QuizMode = 'SPELL_FROM_DEF' | 'SPELL_FROM_AUDIO' | 'MEANING_FROM_WORD';

export const QuizSession: React.FC<QuizSessionProps> = ({ words, onComplete, onUpdateWord, onExit }) => {
  const [queue, setQueue] = useState<WordData[]>([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [input, setInput] = useState('');
  const [status, setStatus] = useState<'idle' | 'correct' | 'incorrect'>('idle');
  const [showHint, setShowHint] = useState(false);

  // New States for Mixed Mode
  const [quizMode, setQuizMode] = useState<QuizMode>('SPELL_FROM_DEF');
  const [choices, setChoices] = useState<WordData[]>([]);

  const [isFinished, setIsFinished] = useState(false);

  const inputRef = useRef<HTMLInputElement>(null);
  const nextButtonRef = useRef<HTMLButtonElement>(null);
  const hasInitialized = useRef(false);

  // Cleanup
  useEffect(() => {
    return () => {
      window.speechSynthesis?.cancel();
    };
  }, []);

  useEffect(() => {
    if (isFinished) {
      playVictorySound();
    }
  }, [isFinished]);

  useEffect(() => {
    if (!hasInitialized.current && words.length > 0) {
      const shuffled = [...words].sort(() => Math.random() - 0.5);
      setQueue(shuffled);
      hasInitialized.current = true;
      setupNewRound(shuffled[0], shuffled);
    }
  }, [words]);

  // SMART PRE-LOADING: Preload images for the next 3 words in the queue.
  // This ensures images are in the browser cache before the user clicks "Next".
  useEffect(() => {
    if (queue.length === 0) return;

    const PRELOAD_COUNT = 3;
    const nextWords = queue.slice(currentIndex + 1, currentIndex + 1 + PRELOAD_COUNT);

    nextWords.forEach(word => {
      if (word.imageUrl) {
        const img = new Image();
        img.src = word.imageUrl;
      }
    });
  }, [currentIndex, queue]);

  // Re-sync currentWord
  const currentWord = queue.length > 0 ? words.find(w => w.id === queue[currentIndex].id) || queue[currentIndex] : null;

  const setupNewRound = (word: WordData, allWords: WordData[]) => {
    const modes: QuizMode[] = ['SPELL_FROM_DEF', 'SPELL_FROM_AUDIO', 'MEANING_FROM_WORD'];
    const nextMode = modes[Math.floor(Math.random() * modes.length)];
    setQuizMode(nextMode);

    if (nextMode === 'MEANING_FROM_WORD') {
      const distractors = allWords
        .filter(w => w.id !== word.id)
        .sort(() => 0.5 - Math.random())
        .slice(0, 3);
      const options = [word, ...distractors].sort(() => 0.5 - Math.random());
      setChoices(options);
    } else if (nextMode === 'SPELL_FROM_AUDIO') {
       setTimeout(() => speakText(word.word), 500);
    }
  };

  // Focus Logic
  useEffect(() => {
    const timer = setTimeout(() => {
      if (isFinished) return;
      if (status === 'idle') {
        if (quizMode !== 'MEANING_FROM_WORD') {
          inputRef.current?.focus();
        }
      } else if (status === 'correct') {
        nextButtonRef.current?.focus();
      }
    }, 100);
    return () => clearTimeout(timer);
  }, [status, currentIndex, quizMode, isFinished]);

  const handleSpellingSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentWord || status !== 'idle') return;
    const cleanInput = input.trim().toLowerCase();
    const cleanTarget = currentWord.word.toLowerCase();

    // Unlock Audio for iOS
    resumeAudioContext();

    if (cleanInput === cleanTarget) {
      handleCorrect();
    } else {
      handleIncorrect();
    }
  };

  const handleChoiceSelect = (selectedId: string) => {
    if (!currentWord || status !== 'idle') return;

    // Unlock Audio for iOS
    resumeAudioContext();

    if (selectedId === currentWord.id) {
      handleCorrect();
    } else {
      handleIncorrect();
    }
  };

  const handleCorrect = async () => {
    if (!currentWord) return;
    setStatus('correct');

    // 1. Play success effect
    playSuccessSound();

    // 2. Speak the word first
    window.speechSynthesis.cancel();
    speakText(currentWord.word);

    // 3. Read the English quote after a short delay
    if (currentWord.quote) {
      setTimeout(() => {
        // Safe access for both legacy string and new object types
        const textToSpeak = typeof currentWord.quote === 'string' 
          ? currentWord.quote 
          : currentWord.quote?.english;

        if (textToSpeak) {
           speakText(textToSpeak, 0.9);
        }
      }, 1000);
    }

    const newCount = currentWord.correctCount + 1;
    onUpdateWord(currentWord.id, { 
      correctCount: newCount, 
      lastPracticed: new Date().toISOString() 
    });
  };

  const handleIncorrect = () => {
    setStatus('incorrect');
    playErrorSound();
    setTimeout(() => {
      setStatus('idle');
      setInput('');
      setShowHint(true);
    }, 1000);
  };

  const handleNext = () => {
    window.speechSynthesis.cancel();
    if (currentIndex < queue.length - 1) {
      const nextIndex = currentIndex + 1;
      setCurrentIndex(nextIndex);
      setStatus('idle');
      setInput('');
      setShowHint(false);
      setupNewRound(queue[nextIndex], queue);
