    window.speechSynthesis.cancel();
    if (currentIndex < queue.length - 1) {
      const nextIndex = currentIndex + 1;
      setCurrentIndex(nextIndex);
      setStatus('idle');
      setInput('');
      setShowHint(false);
      setupNewRound(queue[nextIndex], queue);
    } else {
      setIsFinished(true);
    }
  };

